RegisterGlobalEvent(13, "Abandoned Temple", function()
    evt.SimpleMessage("The ruins of a temple built by the lost civilization lies on the island just northwest of the main island. I have not explored it however, for dangerous reptiles have made it their lair. I do suspect that the temple leads to an underwater tunnel which surfaces near the boat docks on the northwest island.With the bridges out, that tunnel may be the only way to reach the docks and a boat to safety!")
end)

RegisterGlobalEvent(14, "Quest", function()
    if not IsQBitSet(QBit(138)) then -- Found Isthric the Tongue
        evt.SimpleMessage("My brother, Isthric the Tongue, went to check on the tobersk plants on one of the lesser islands.\nHe has not returned!\nI am afraid that he is one of those stranded by the cataclysm. He may even be hurt!\nIf you were to fix the Portals of Stone, he would surely be able to return, and we could get help to those who need it!\nFind him for me!")
        SetQBit(QBit(137)) -- Find Isthric the Tongue, brother of Rohtnax. Return to Rohtnax in the village of Blood Drop on Dagger Wound Island.
        return
    end
    evt.SimpleMessage("You found Isthric and told him how to return home?\nWe are indeed in debt to you, Merchant of Alvar!\nI will speak well of you to Clan Leader Brekish Onefang.\nPlease take these potions of Cure Wounds as a reward.")
    evt.ForPlayer(Players.All)
    AddValue(Experience, 750)
    evt.ForPlayer(Players.Member0)
    AddValue(InventoryItem(222), 222) -- Cure Wounds
    AddValue(InventoryItem(222), 222) -- Cure Wounds
    ClearQBit(QBit(137)) -- Find Isthric the Tongue, brother of Rohtnax. Return to Rohtnax in the village of Blood Drop on Dagger Wound Island.
    evt.ForPlayer(Players.All)
    SetAward(Award(54)) -- Rescued Isthric the Tongue, brother of Rohtnax, on the Dagger Wound Islands.
    evt.SetNPCTopic(29, 0, 0) -- Rohtnax topic 0 cleared
end)

RegisterGlobalEvent(15, "Portals of Stone", function()
    if not IsQBitSet(QBit(1)) then -- Activate Area 1 teleporters 3 and 4.
        evt.SimpleMessage("My Granda used to tell us of the times past, when the Portals of Stone were the main travel route between the islands.\nShe told us that the keys to the Portals disappeared during one of the first raids committed by the Regnan Pirates.\nIf the Portals of Stone were working my brother Isthric could return back to the main island!")
        return
    end
    evt.SimpleMessage("You have repaired the Portals of Stone?\nThat is tremendous news!\nQuickly, find my brother, Isthric and tell him to return home!")
end)

