RegisterGlobalEvent(22, "Promotion to Dark Elf Patriarch", function()
    evt.SimpleMessage("The Merchant Council had sent our greatest warrior, Cauri Blackthorne, to consult with the Sun Temple priests about the disasters that have struck all of Jadame.Cauri left for the Temple of the Sun in Murmurwoods shortly after rumors of the cataclysms were heard here in Alvar.\nShe was to return after consulting the priests.\nWe are very concerned that she has not returned.As for your promotion, only Cauri can accurately test your skills and assess your worthiness for promotion.\nIf you find her, provide her with any assistance she may need and return here with news of her status and location.")
    SetQBit(QBit(39)) -- Find Cauri Blackthorne then return to Dantillion in Murmurwoods with information of her location. - Dark Elf Promotion to Patriarch
    evt.SetNPCTopic(39, 0, 31) -- Relburn Jeebes topic 0: Where is Cauri?
end)

RegisterGlobalEvent(23, "Cauri Blackthorne", function()
    if IsQBitSet(QBit(1537)) then -- Promoted to Elf Patriarch.
        evt.SimpleMessage("Cauri returned and informed us of this assistance you provided her.\nShe also notified us of your promotion.\nCongratulations, may your profits bring you much joy!")
        evt.ForPlayer(Players.Member0)
        AddValue(Gold, 15000)
        evt.SetNPCTopic(39, 1, 0) -- Relburn Jeebes topic 1 cleared
        return
    elseif HasAward(Award(20)) then -- Rescued Cauri Blackthorne.
        evt.SimpleMessage("Cauri returned and informed us of this assistance you provided her.\nShe also notified us of your promotion.\nCongratulations, may your profits bring you much joy!")
        evt.ForPlayer(Players.Member0)
        AddValue(Gold, 15000)
        evt.SetNPCTopic(39, 1, 0) -- Relburn Jeebes topic 1 cleared
    else
        evt.SimpleMessage("This is the home of Cauri Blackthorne, greatest Dark Elf warrior.\nShe is currently out, working for the Merchant Council of Alvar.\nPerhaps you should consult them as to her whereabouts.")
    end
end)

RegisterGlobalEvent(24, "Thank you!", function()
    evt.SimpleMessage("Thank you for your assistance with the Basilisk Curse.\nUsually I am prepared to handle the vile lizards, but this time there were just too many of them.The Temple of the Sun asked me to check on a few pilgrims that were looking for the Druid Circle of Stone in this area.\nWhen I found the first statue, I realized what had happened to the pilgrims.\nI myself did not know of the increase in the number of Basilisks in this area.\nThey seem to be agitated by something.\nI was going to investigate the Druid Circle of Stone when the Basilisks attacked me.")
end)

RegisterGlobalEvent(25, "Patriarch", function()
    evt.SimpleMessage("::Cauri looks over the Dark Elf(s) in your party::To rescue me, you must have researched my path, and investigated the places I had been.\nThis demonstrates the intelligence needed to succeed in dealing with the world and business.To get to where I was attacked, you must have the skills needed to fight the Basilisks and other threats, demonstrating your prowess as a warrior.\nSkill in battle is needed when proper negotiations break down.To ask me for promotion demonstrates desire, and without desire success will always escape your grasp.You have all of the traits necessary to hold the title of Patriarch.\nI will notify to Council upon my return.\nIt would be my pleasure to travel with you again.\nYou can find me in the Inn in Ravenshore.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 8) then
            SetValue(ClassId, 9)
            AddValue(Experience, 35000)
            SetQBit(QBit(1537)) -- Promoted to Elf Patriarch.
        else
            AddValue(Experience, 25000)
            SetAward(Award(20)) -- Rescued Cauri Blackthorne.
        end
    end
    ClearQBit(QBit(39)) -- Find Cauri Blackthorne then return to Dantillion in Murmurwoods with information of her location. - Dark Elf Promotion to Patriarch
    SetQBit(QBit(40)) -- Found and Rescued Cauri Blackthorne
    SetQBit(QBit(430)) -- Roster Character In Party 31
    evt.SetNPCTopic(42, 1, 38) -- Cauri Blackthorne topic 1: Thanks for your help!
end)

RegisterGlobalEvent(26, "Circle of Stone", function()
    evt.SimpleMessage("I need to investigate the Circle of Stone further for the Temple of the Sun.\nHopefully not all of the pilgrims met the fate of these. Hopefully there are survivors!Something has agitated the creatures in this area, and I think the source can be found in the Circle.")
end)

RegisterGlobalEvent(27, "Cauri Blackthorne", function()
    if IsQBitSet(QBit(39)) then -- Find Cauri Blackthorne then return to Dantillion in Murmurwoods with information of her location. - Dark Elf Promotion to Patriarch
        evt.SimpleMessage("Cauri Blackthorne was here well over a week ago, maybe longer.\nShe had asked us many questions about the elemental incursions.\nWe provided her with what information we had here.\nShe said she would return to Alvar with the information.\nBefore she left, we asked her if she could do a favor for us.\nWe asked her if she could check on a group of pilgrims that were traveling to the old Druid Circle of Stone to the northeast of here.\nShe assured us that she would check in on them on her way back to Alvar.")
        evt.ForPlayer(Players.Member0)
        AddValue(InventoryItem(339), 339) -- Stone to Flesh
        evt.ForPlayer(Players.Member1)
        AddValue(InventoryItem(339), 339) -- Stone to Flesh
        evt.ForPlayer(Players.Member2)
        AddValue(InventoryItem(339), 339) -- Stone to Flesh
        evt.ForPlayer(Players.Member3)
        AddValue(InventoryItem(339), 339) -- Stone to Flesh
        evt.ForPlayer(Players.Member4)
        AddValue(InventoryItem(339), 339) -- Stone to Flesh
        evt.SetNPCTopic(41, 0, 26) -- Dantillion  topic 0: Circle of Stone
