RegisterGlobalEvent(33, "Smuggler Boats", function()
    evt.SimpleMessage("My cargoes are not the kind that want inspecting by harbor officials so my boats have to be, and are, the fastest on the coast of Jadame. They can even outrun a Regnan galley! From here they run west to Ravage Roaming and east to Shadowspire.")
end)

RegisterGlobalEvent(34, "Ancient Troll Home", function()
    evt.SimpleMessage("Ancient Troll legends tell of a time when we did not live here in this desolate region.\nThey tell of a place that was quiet and tranquil.\nWe were driven from this place by the Curse of the Stone.\nSo for many hundred years we have dwelt here upon the Sand of Iron.\nNow it seems we will be forced from this place as well.\nThe growing sea of fire has destroyed most of my village.\nMany friends and family have perished.\nThis may indeed be the end of my Clan.There is a saying amongst my people, \"a thing lives only as long as it is remembered.\"\nAs long as I remember our homeland, then it will always be there for us to return too.\nIt just needs to be found.")
end)

RegisterGlobalEvent(35, "Quest", function()
    evt.SimpleMessage("Perhaps if you could locate our previous homeland, and check to see if the Curse of the Stone still exists.\nIf it does perhaps there is a way to remove it.\nAny Troll in your party who completes this task would be promoted to War Troll of our Clan. Many honors are bestowed with this title, and you would be forever known to us as a legendary hero.One of our warriors, Dartin Dunewalker, set out to find this place.\nHe left thinking he would find clues among the stone fields of Ravage Roaming.\nPerhaps you can find him there and work together--or at the least, find clues that will lead you to our goal.")
    SetQBit(QBit(68)) -- Find the Ancient Troll Homeland and return to Volog Sandwind in the Ironsand Desert. - Given By ? In area 4
    evt.SetNPCTopic(43, 0, 40) -- Volog Sandwind topic 0: Ancient Home
end)

RegisterGlobalEvent(36, "Ancient Home Found!", function()
    evt.SimpleMessage("You have found our Ancient Home?\nIts located in the western area of the Murmurwoods?\nThis is wonderful news.\nPerhaps there is still time to move my people.\nUnfortunately the Elemental threat must be dealt with first, or no people will be safe! All Trolls among you have been promoted to War Troll, and their names will be forever remembered in our songs.\nI will teach the rest of you what skills I can, perhaps it will be enough to help you save all of Jadame.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 38) then
            SetValue(ClassId, 39)
            AddValue(Experience, 35000)
            SetQBit(QBit(1538)) -- Promoted to War Troll.
        else
            AddValue(Experience, 25000)
            SetQBit(QBit(1539)) -- Found Troll Homeland.
        end
    end
    ClearQBit(QBit(68)) -- Find the Ancient Troll Homeland and return to Volog Sandwind in the Ironsand Desert. - Given By ? In area 4
    evt.SetNPCTopic(43, 1, 612) -- Volog Sandwind topic 1: Roster Join Event
end)
RegisterCanShowTopic(36, function()
    evt._BeginCanShowTopic(36)
    local visible = true
    if IsQBitSet(QBit(69)) then -- Ancient Troll Homeland Found
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(37, "Curse of Stone", function()
    evt.SimpleMessage("You were sent to find the Ancient Troll Home?\nYour assistance is welcomed!\nI am at a loss; the clues I followed to this region have lead to a dead end.\nNo one here knows about the Curse of the Stone mentioned in our legends.\nThe Ogre Mage, Zog was less than helpful.\nI was lucky to escape his fortress with my life. Although, he may have provided assistance with out meaning too!\nWhen I mentioned the Curse of the Stone, he said if I bothered him further, he would be sure to cage me with his pet Basilisk!\nBasilisks roam the Murmurwoods!")
end)

RegisterGlobalEvent(38, "Thanks for your help!", function()
    evt.SimpleMessage("Thanks again for your assistance with the Basilisk curse!")
end)

RegisterGlobalEvent(39, "Thanks for your help!", function()
    evt.SimpleMessage("Thanks for finding our Ancient Home, once the treat to Jadame has been handled we can begin to move there!")
end)

RegisterGlobalEvent(40, "Ancient Home", function()
    evt.SimpleMessage("Have you found the Ancient Home for our Clan?\nWithout its location, my people will surely perish!")
end)
