RegisterGlobalEvent(41, "Deliver Report", function()
    evt.SimpleMessage("Disaster in Dagger Wound, too? This is indeed disturbing. If one were to believe all the rumors, one would think that all of Jadame is in upheaval and chaos.I wish I knew more. I rely on our caravan masters for news, but all who were supposed to arrive here this month have not. What I do hear, troubles me. Hurricanes, floods, and now a volcano! The worst I've heard is that a sea of fire has appeared in the Ironsand Desert--and this from many sources.I wonder if this crystal in Ravenshore has something to do with it. Its appearance at the onset of the calamity seems to be more than a coincidence.")
    ClearQBit(QBit(11)) -- Report to Bastian Loudrin, the merchant guildmaster in Alvar. - Given By Elgar Fellmoon (w503, area 2). Taken by Bastian Loudrin (area 3).
    SetQBit(QBit(12)) -- Quest 11 is done.
    evt.SetNPCTopic(5, 0, 42) -- Bastian Loudrin topic 0: Quest
    evt.ForPlayer(Players.All)
    AddValue(Experience, 15000)
    evt.ForPlayer(Players.Member0)
    AddValue(Gold, 2000)
end)
RegisterCanShowTopic(41, function()
    evt._BeginCanShowTopic(41)
    local visible = true
    if IsQBitSet(QBit(11)) then -- Report to Bastian Loudrin, the merchant guildmaster in Alvar. - Given By Elgar Fellmoon (w503, area 2). Taken by Bastian Loudrin (area 3).
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(42, "Quest", function()
    if not IsQBitSet(QBit(25)) then -- Find a witness to the lake of fire's formation. Bring him back to the merchant guild in Alvar. - Given and taken by Bastian Lourdrin (area 3).
        evt.SimpleMessage("All of this upheaval is seriously impacting our guild's business. I need more information, but I'm being buried in gossip and rumor.Many tell me of this sea of fire in the Ironsand Desert. I've heard the tale enough that I almost believe it. Confirmation or denial of the lake's existence would be of great help to me.If you would serve me, go to the Ironsand Desert and seek this lake. If it is indeed there, find me someone who saw it appear. Bring him back here so I can hear his story myself.")
        SetQBit(QBit(25)) -- Find a witness to the lake of fire's formation. Bring him back to the merchant guild in Alvar. - Given and taken by Bastian Lourdrin (area 3).
        AddValue(History(6), 0)
        evt.MoveNPC(7, 752) -- Overdune Snapfinger -> Overdune's House
        evt.MoveNPC(47, 752) -- Farhill Snapfinger -> Overdune's House
        return
    end
    if HasPlayer(4) then -- Overdune Snapfinger
        evt.SimpleMessage("Oh, what a mess you've made of things! When I asked you to find me a witness of events in the Ironsand Desert, I thought it would be obvious that you'd have to return him to me in good condition! I mean look at the poor Troll! Take him to the temple and get him fixed up.And please...try to remember you're working for the guild. We do have a reputation for conducting ourselves with at least passing competence.")
        return
    elseif IsQBitSet(QBit(60)) then -- Party visits Ironsand After QuestBit 25 set.
        evt.SimpleMessage("Well, so it is true. Imagine…a lake of fire. But where is my eyewitness? I need to speak with someone who saw its formation. This is important…for reasons I'm unwilling to discuss with you now.Find me someone who saw the birth of the lake of fire! Try searching the Troll village, Rust.")
    else
        evt.SimpleMessage("I must know more about what is going on in the Ironsand Desert. I can't use more rumors. I have enough of those already.I need you to actually go there. The desert is several days travel to the east.")
    end
end)

