RegisterGlobalEvent(44, "Well Done", function()
    evt.SimpleMessage("You have done what I feared was impossible. Though these times are fraught with uncertainties, that you have united key factions of Jadame goes a long way towards securing our continued existence.Well, I have done what I can. I leave the defense of the land to the alliance council. I hope they find the accommodations I have provided them in Ravenshore to be adequate--the guild house there is not our most luxurious. Still, I though it would be best if the council was located near the crystal.I wish them, and you, good luck!")
end)

RegisterGlobalEvent(45, "Lake of Fire", function()
    evt.SimpleMessage("Yes, I was here when the lake of fire first appeared. A strange gateway appeared on the desert plain outside the village. The fire you see spilled forth from it. The fire spread like water poured on the ground.A wave of flames rushed over the edge of the village. Most of my people were lost instantly. What remains of this village is as you see it.I was in the hills overlooking the village when this all happened. I saw it all, but I can hardly believe it.")
    evt.SetNPCTopic(7, 0, 46) -- Overdune Snapfinger topic 0: Come to Alvar
end)

RegisterGlobalEvent(46, "Come to Alvar", function()
    if IsQBitSet(QBit(62)) then -- Vilebites Ashes (item603) placed in troll tomb.
        evt.SimpleMessage("You have done my family a great service. With his ashes safe in the holy sanctuary of the village tomb, Vilebite can lie in peace. My father, too is greatly improved. We have talked and I believe that he can now take care of himself while I accompany you to Alvar.")
        SetQBit(QBit(63)) -- Quest 61 done.
        ClearQBit(QBit(61)) -- Put Vilebite's ashes in the Dust village tomb then return to Overdune. - Given and taken by Overdune, NPC 7, w177.
        evt.ForPlayer(Players.All)
        SetAutonote(495) -- Placed Vilebite's ashes in the Troll Tomb.
        evt.ForPlayer(Players.Member0)
        AddValue(Gold, 7500)
        evt.ForPlayer(Players.All)
        AddValue(Experience, 20000)
        evt.SetNPCTopic(7, 0, 604) -- Overdune Snapfinger topic 0: Roster Join Event
        evt.SetNPCGreeting(47, 18) -- Farhill Snapfinger greeting: Th-thank you for giving my son Vilebite his rest.
        evt.SetNPCTopic(47, 0, 47) -- Farhill Snapfinger topic 0: Vilebite
        return
    elseif IsQBitSet(QBit(61)) then -- Put Vilebite's ashes in the Dust village tomb then return to Overdune. - Given and taken by Overdune, NPC 7, w177.
        evt.SimpleMessage("I will go with you only after my brother's ashes are safely in the village tomb.")
    else
        evt.SimpleMessage("I would come with you, If it were not for my father. So deep is his mourning for my brother, Vilebite, that he cannot care for himself.My father believes that Vilebite's soul cannot rest until his remains are at rest in the village tomb. Unfortunately, Gogs infested the tomb when the lake of fire appeared.Here! Take my brother's ashes. I'm sure my father's grief will lessen if they are placed in the tomb. Do this for me and I will travel with you to Alvar.")
        SetQBit(QBit(61)) -- Put Vilebite's ashes in the Dust village tomb then return to Overdune. - Given and taken by Overdune, NPC 7, w177.
        AddValue(InventoryItem(603), 603) -- Urn of Ashes
        SetQBit(QBit(202)) -- Urn of Ashes - I lost it
    end
return
end)

RegisterGlobalEvent(47, "Vilebite", function()
    evt.SimpleMessage("Vilebite was a good son. I will miss him. But at least I can take comfort knowing that he is at peace. Thank you for your kind and heroic deed.")
end)

RegisterGlobalEvent(48, "Alliance", function()
    evt.SimpleMessage("\"An alliance to unite Jadame,\" you say. If it wasn't Lordrin who was proposing it, I would normally have slain you for my supper.While intriguing, I cannot consider the idea now. We are under daily attack by the accursed knights of Charles Quixote. If he were not a problem, I could do as Lordrin asks.Perhaps you could help me with Quixote?")
    evt.SetNPCTopic(17, 0, 49) -- Deftclaw Redreaver topic 0: Quest
end)
