RegisterGlobalEvent(51, "Skeletal Dragons", function()
    evt.SimpleMessage("My father believed that the Necromancers of Shadowspire were attempting to create an undead Dragon.")
end)

RegisterGlobalEvent(52, "Promotion to Champion", function()
    evt.SimpleMessage("My father Blazen, left here years ago to slay the Skeletal Dragons in the Shadowspire Region. Unfortunately, he has never returned.\nHe took with him, Ebonest, the greatest Dragon slaying spear ever forged. Charles Quixote has never forgiven my father for taking Ebonest with him.\nUnfortunately we have no idea what befell my father.\nBecause my father was Charles’ second in command and responsible for the loss of Ebonest, Charles is unwilling to promote me to Champion, regardless of the merit of my skills. Perhaps if you find Ebonest, Charles with promote your knights and myself to Champions!")
    SetQBit(QBit(70)) -- Find Blazen Stormlance and recover the spear Ebonest. Return to Leane Stormlance in Garrote Gorge and deliver Ebonest to Charles Quixote.
    evt.SetNPCTopic(49, 0, 59) -- Leane Stormlance topic 0: My Father
end)

RegisterGlobalEvent(53, "Ebonest", function()
    evt.SimpleMessage("I was captured in the center of the Mad Necromancer’s lab.\nThere I was tortured and many curses were placed upon me.\n Ebonest must have been taken from me when I fell, and perhaps is still in the central chamber.\nIf you were to recover it and return it to Quixote, at least my family name will be cleared, and my daughter can continue her life without my failure haunting her.")
end)

RegisterGlobalEvent(54, "Cure", function()
    evt.ForPlayer(Players.All)
    if not HasItem(623) then -- Gem of Restoration
        evt.SimpleMessage("Perhaps the Clerics of the Sun have a way to cure me, for they would be the only ones who would know how to counter the dark magics that afflict me. There is a friend of mine in Ravenshore named Dervish Chevron. He left the Temple of the Sun years ago to pursue his own research into the mysteries of Jadame.\nPerhaps he would know of a cure, or even have it in his possession.\nIf he cannot help, promise you will return here and kill me so I may at last be at rest!")
        SetQBit(QBit(72)) -- Inquire about a cure for Blazen Stormlance from Dervish Chevron in Ravenshore.
        return
    end
    evt.ForPlayer(Players.All)
    evt.SimpleMessage("The Cleric sent you back with the Gem of Restoration?")
    RemoveItem(623) -- Gem of Restoration
