RegisterGlobalEvent(55, "Mad Necromancer", function()
    evt.SimpleMessage("Zanthora moved here from the Shadowspire to continue experiments she began at the Necromancers' Guild.\nShe desired to create the ultimate horror, the Skeletal Dragon.\nHer fellow Necromancers feared the end result. If the created Dragons where ever to escape Zanthora’s control, there would be no stopping them.")
end)

RegisterGlobalEvent(56, "Stormlance", function()
    evt.SimpleMessage("Blazen Stormlance was my lieutenant and my friend.\nI never understood his personal quest--this need to find these rumored Skeletal Dragons.\nHe took my greatest tool with him.\nWith Ebonest in my hand, I would have the Dragon problem well in hand.\n")
end)

RegisterGlobalEvent(57, "Ebonest", function()
    evt.SimpleMessage("The Clerics of the Sun imbued this spear with their blessings, making it the strongest spear forged.\nIts power is said to be able to slay any Dragon with one blow.\nIf this were so, I could end my conflict quickly, cleanly and efficiently.")
end)

RegisterGlobalEvent(58, "Promotion to Champion", function()
    evt.ForPlayer(Players.All)
    if not HasItem(539) then -- Ebonest
        evt.SimpleMessage("You have found Blazen Stormlance? But where is Ebonest?")
        return
    end
    if not IsQBitSet(QBit(22)) then -- Allied with Dragons. Return Dragon Egg to Dragons done.
        evt.SimpleMessage("You found Blazen Stormlance?\nWhat about MY spear Ebonest?\nYou have that as well?FANTASTIC!I thank you for this and find myself in your debt!\nI will promote all knights in your party to Champion and teach what skills I can to the rest of your party. ")
        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
            evt.ForPlayer(player)
            if IsAtLeast(ClassId, 16) then
                SetValue(ClassId, 19)
                AddValue(Experience, 50000)
                SetQBit(QBit(1540)) -- Promoted to Champion.
                RemoveItem(539) -- Ebonest
            else
                AddValue(Experience, 35000)
                SetQBit(QBit(1541)) -- Returned Ebonest to Charles Quixote.
            end
        end
        ClearQBit(QBit(70)) -- Find Blazen Stormlance and recover the spear Ebonest. Return to Leane Stormlance in Garrote Gorge and deliver Ebonest to Charles Quixote.
        evt.SetNPCTopic(15, 2, 735) -- Sir Charles Quixote topic 2: Promote Knights
        evt.SetNPCTopic(52, 2, 735) -- Sir Charles Quixote topic 2: Promote Knights
        return
    end
    evt.SimpleMessage("What is this?\nYou ally with my mortal enemies and then seek to do me a favor?I wonder what the Dragons think of this. But so be it.\nI am in your debt for returning Ebonest to me.\nI will promote any Knights in your party to Champion, however they will never be accepted in my service.\nThe rest I will teach what I can. I do not wish to see you again!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 16) then
            SetValue(ClassId, 19)
            AddValue(Experience, 50000)
            SetQBit(QBit(1540)) -- Promoted to Champion.
            RemoveItem(539) -- Ebonest
        else
            AddValue(Experience, 35000)
            SetQBit(QBit(1541)) -- Returned Ebonest to Charles Quixote.
        end
    end
    ClearQBit(QBit(70)) -- Find Blazen Stormlance and recover the spear Ebonest. Return to Leane Stormlance in Garrote Gorge and deliver Ebonest to Charles Quixote.
    evt.SetNPCTopic(15, 2, 735) -- Sir Charles Quixote topic 2: Promote Knights
    evt.SetNPCTopic(52, 2, 735) -- Sir Charles Quixote topic 2: Promote Knights
end)
