RegisterGlobalEvent(76, "Prophecies of the Sun", function()
    evt.ForPlayer(Players.All)
    evt.SimpleMessage("Of the many Prophecies of Jadame, the only ones that I have not be studied are the Prophecies of the Sun.\nThis temple was established by Tesius Dawnglow, who traveled here from Erathia many years ago to find these Prophecies.\nUnfortunately, they were not found.\nIt is our hope that these Prophecies hold the solution to the events that are destroying Jadame.")
end)
