RegisterGlobalEvent(82, "Korbu", function()
    evt.SimpleMessage("Korbu was the most powerful of the Vampire race.\nOver one hundred years ago, he sought something that our kind cannot accept.\nAbsolution.\nSomehow, Korbu began to experience guilt over the need to feed.\nOr perhaps over the act of feeding itself.\nHe could no longer bear the thought of killing in order to survive.\nMany of our elders argued with him.\nHe decided to find a place where he could ponder his existence.\nThus the Crypt of Korbu was constructed with slave labor in the Ravage Roaming region.\n Korbu has not been heard from since he left.\n")
end)

RegisterGlobalEvent(83, "Quest", function()
    evt.SimpleMessage("In this time of chaos, we need the minds of all our elders.\nReturn to us with Korbu, or his remains, if he has perished.\nIf he has indeed perished, you must return his Sarcophagus with him.\nWe will attempt to reanimate him so that we may consult his wisdom.")
    SetQBit(QBit(80)) -- Find the Sarcophagus of Korbu and Korbu's Remains and return them to Lathean in Shadowspire.
    evt.SetNPCTopic(62, 1, 90) -- Lathean topic 1: Return of Korbu
end)

RegisterGlobalEvent(84, "Korbu", function()
    evt.SimpleMessage("Korbu?\nHe was the greatest of our kind, and yet he always seemed troubled.\nThere are some of us that remember the times before he left. He always seemed disturbed to me.")
end)

RegisterGlobalEvent(85, "Korbu", function()
    evt.SimpleMessage("Korbu left us after making the \"Arrangement\" with the necromancers here in Shadowspire.\nWe aid them in any research they are working on, and assist with the defense of their guild.\nIn return we are allowed to feed on the local population without hindrance.")
end)

RegisterGlobalEvent(86, "Lich", function()
    evt.SimpleMessage("Ah, you seek to achieve the ultimate in the darker arts.\nThe necromancer’s among you seek to turn themselves into Liches, the most potent of necromancers.\nVery well, I can perform this transformation for you, but you must do something for me...and get something for yourselves.\nI require the Lost Book of Khel.\nIt contains secrets of necromancy that had been hidden since Khel’s tower sank beneath the waves.\nThe Lizardmen of Dagger Wound celebrated when the sea took Khel and his knowledge from us.\nWith the volcanic upheaval in that region, I believe the Tower of Khel can be found.\nRetrieve the book from the library and bring it to me!\nNow, for yourselves, you will need a Lich Jar for every necromancer that wishes to become a Lich.\nZanthora, the Mad Necromancer keeps a large supply of these jars, perhaps she will sell you one!\nIf not you must take them from her!")
    SetQBit(QBit(82)) -- Find the Lost Book of Khel and return it to Vertrinus in Shadowspire.
    evt.SetNPCTopic(61, 0, 89) -- Vetrinus Taleshire topic 0: Promotion to Lich
end)

RegisterGlobalEvent(87, "Lich Jars", function()
    evt.ForPlayer(Players.All)
    evt.SimpleMessage("The Guild of Necromancers is very stingy when it comes to parting with Lich Jars.\nYou may be better off seeking out Zanthora, and obtaining one from her.")
end)
