RegisterGlobalEvent(88, "The Lost Book of Khel", function()
    evt.ForPlayer(Players.All)
    evt.SimpleMessage("the Lost Book of Khel is rumored to hold the secrets to the ultimate powers of the dark art of necromancy.")
end)
