RegisterGlobalEvent(89, "Promotion to Lich", function()
    evt.ForPlayer(Players.All)
    if not HasItem(611) then -- Lost Book of Kehl
        evt.SimpleMessage("You do not have the Lost Book of Khel!\nI cannot help you, if you do not help me!\nReturn here with the Book and a Lich Jar for each necromancer in your party that wishes to become a Lich!")
        return
    end
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
        evt.ForPlayer(player)
        if not IsAtLeast(ClassId, 44) then
            if not HasItem(628) then -- Lich Jar
                evt.SimpleMessage("You have the Lost Book of Khel, however you lack the Lich Jars needed to complete the transformation!\nReturn here when you have one for each necromancer in your party!")
                return
            end
        end
    end
    evt.SimpleMessage("You have brought everything needed to perform the transformation!\nSo be it!\nAll necromancer’s in your party will be transformed into Liches!\nMay the dark energies flow through them for all eternity!\nThe rest of you will gain what knowledge I can teach them as reward for their assistance!\nLets begin!After we have completed, good friend Lathean can handle any future promotions for your party.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 44) then
            SetValue(ClassId, 45)
            AddValue(Experience, 35000)
            SetQBit(QBit(1548)) -- Promoted to Lich.
            RemoveItem(628) -- Lich Jar
        else
            AddValue(Experience, 25000)
            SetAward(Award(35)) -- Found the Lost Book of Khel.
        end
    end
    evt.ForPlayer(Players.All)
    RemoveItem(611) -- Lost Book of Kehl
    ClearQBit(QBit(82)) -- Find the Lost Book of Khel and return it to Vertrinus in Shadowspire.
    evt.SetNPCTopic(61, 0, 742) -- Vetrinus Taleshire topic 0: Travel with you!
end)

RegisterGlobalEvent(90, "Return of Korbu", function()
    evt.ForPlayer(Players.All)
    if HasItem(627) then -- Remains of Korbu
        if not HasItem(612) then -- Sarcophagus of Korbu
            evt.SimpleMessage("You return to us with the remains of Korbu, but where is his Sarcophagus? We cannot complete the act of reanimation without it!\nReturn to us when you have both the remains and the Sarcophagus!")
            return
        end
        evt.SimpleMessage("You have brought us the Sarcophagus of Korbu and his sacred remains.\nWe will attempt to reanimate Korbu and seek his wisdom in these troubled times!\nThe vampires among you will be transformed into Nosferatu, and the others will be taught what skills we can teach them as reward for your service.")
        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3, Players.Member4}) do
            evt.ForPlayer(player)
            if IsAtLeast(ClassId, 40) then
                SetValue(ClassId, 41)
                AddValue(Experience, 35000)
                SetQBit(QBit(1547)) -- Promoted to Nosferatu.
                RemoveItem(627) -- Remains of Korbu
                RemoveItem(612) -- Sarcophagus of Korbu
            else
                AddValue(Experience, 25000)
                SetAward(Award(33)) -- Found the Sarcophagus and Remains of Korbu.
            end
        end
        ClearQBit(QBit(80)) -- Find the Sarcophagus of Korbu and Korbu's Remains and return them to Lathean in Shadowspire.
        evt.ForPlayer(Players.All)
        RemoveItem(627) -- Remains of Korbu
        RemoveItem(612) -- Sarcophagus of Korbu
        evt.SetNPCTopic(62, 1, 739) -- Lathean topic 1: Promote Vampires
        return
    elseif HasItem(612) then -- Sarcophagus of Korbu
        evt.SimpleMessage("You return to us with the Sarcophagus of Korbu, but where are his remains? We cannot complete the act of reanimation without them!\nReturn to us when you have both the Sarcophagus and his remains!")
    else
        evt.SimpleMessage("We need to consult Korbu!")
    end
end)
