RegisterGlobalEvent(94, "Alliance", function()
    evt.SimpleMessage("Bastian Loudrin has been a great friend to the guild. Sadly, I must refuse his request at this time. Even as we speak, my guild is embroiled in a battle for its very survival. For you see, the Temple of the Sun has declared a holy war on us. Most of our members are away in the fields either leading armies or raising zombies to serve in them.I wish I could say otherwise, but the accursed temple holds the upper hand. If only the balance would tilt in our favor.")
    evt.SetNPCTopic(9, 0, 95) -- Sandro topic 0: Quest
end)
RegisterCanShowTopic(94, function()
    evt._BeginCanShowTopic(94)
    local visible = true
    if IsQBitSet(QBit(14)) then -- Form an alliance with the Necromancers' Guild in Shadowspire. - Given by Bastian Lourdrin (area 3). Activates Merchanthouse in Alvar. Taken by Sandro (area 6) or when quest 15 is done.
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(95, "Quest", function()
    if not IsQBitSet(QBit(28)) then -- Bring the Nightshade Brazier to the Necromancers' Guild leader, Sandro. The Brazier is in the Temple of the Sun. - Given and taken by Sandro (area 6). Taken when Qbit 27 set.
        evt.SimpleMessage("If we had the Nightshade Brazier back in our possession, Shadowspire's defense would not be an issue. We could bring this war to the doors of the Sun Temple. We would annihilate them!Knowing its importance, the clerics keep the brazier in a secure chamber deep within their temple. Dyson Leland believes he can gain access to that chamber. Bring him to the temple, recover the brazier and return it to me. You want me in your alliance? Well, do this for me, and I will be in your debt.If you have any questions about the Nightshade Brazier ask Thant. It was he who created the thing.")
        SetQBit(QBit(28)) -- Bring the Nightshade Brazier to the Necromancers' Guild leader, Sandro. The Brazier is in the Temple of the Sun. - Given and taken by Sandro (area 6). Taken when Qbit 27 set.
        if IsQBitSet(QBit(89)) or IsQBitSet(QBit(90)) then -- Dyson Leland talks to you about the Necromancers. For global event 97-100.
            evt.SetNPCTopic(11, 3, 634) -- Dyson Leland topic 3: Roster Join Event
        end
        return
    end
    evt.SimpleMessage("I will not join you until the security of the guild is secure. Bring me the Nightshade Brazier from the Temple of the Sun in Murmurwoods. We will talk again of alliance after that is done.")
end)

RegisterGlobalEvent(96, "Dyson Leland", function()
    evt.SimpleMessage("Early on our conflict, the Sun Temple attempted to infiltrate our ranks with a spy. Such foolishness--thinking they could so easily deceive a host of dark magicians!It was child's play to unmask their agent--one \"Dyson Leland.\" Since then we have turned him against his former masters, or so it would seem. Frankly, I don't entirely trust in his loyalty. Still, he has proven useful. As long as he does, we will continue to let him live.")
end)
RegisterCanShowTopic(96, function()
    evt._BeginCanShowTopic(96)
    local visible = true
    if HasPlayer(34) then -- Dyson Leyland
        visible = false
        return visible
    else
        visible = true
        return visible
    end
end)

RegisterGlobalEvent(97, "Necromancers", function()
    evt.SimpleMessage("How can anyone's quest for power bring him to participate in the horrors of the Dark Path? And yet, here is a whole house of them! Oh, they will call themselves \"seekers of knowledge,\" but these magicians of death are abomination! Loathsome corruption incarnate!Only through my own fear can the foul Necromancers' Guild call itself \"my master.\"")
    SetQBit(QBit(89)) -- Dyson Leland talks to you about the Necromancers. For global event 97-100.
    if not IsQBitSet(QBit(90)) then return end -- Dyson Leland talks to you about the Temple of the Sun. For Global event 97-100.
    if IsQBitSet(QBit(28)) then -- Bring the Nightshade Brazier to the Necromancers' Guild leader, Sandro. The Brazier is in the Temple of the Sun. - Given and taken by Sandro (area 6). Taken when Qbit 27 set.
        evt.SetNPCTopic(11, 3, 634) -- Dyson Leland topic 3: Roster Join Event
        return
    elseif IsQBitSet(QBit(26)) then -- Find the skeleton transformer in the Shadowspire Necromancers' Guild. Destroy it and return to Oskar Tyre. - Given and taken by Oskar Tyre (area 7). Taken when Qbit 29 set.
        evt.SetNPCTopic(11, 3, 634) -- Dyson Leland topic 3: Roster Join Event
    else
        evt.SetNPCTopic(11, 3, 100) -- Dyson Leland topic 3: Join
    end
end)

RegisterGlobalEvent(98, "Sun Temple", function()
    evt.SimpleMessage("When I was young, all I wanted to do was to join the Order of Light--to be a selfless servant of the good. As soon as I was of age, I entered the Temple of the Sun with a heart filled with the fire of purity.What a fool I was. If there is goodness in the world, I have not seen it. There is certainly none in the halls of the Sun Temple! Hiding behind the righteousness of sanctity, Order members perform the worst crimes of greed and self-indulgence. If it were not so horrid, it would pass for something like irony.")
    SetQBit(QBit(90)) -- Dyson Leland talks to you about the Temple of the Sun. For Global event 97-100.
    if not IsQBitSet(QBit(89)) then return end -- Dyson Leland talks to you about the Necromancers. For global event 97-100.
    if IsQBitSet(QBit(28)) then -- Bring the Nightshade Brazier to the Necromancers' Guild leader, Sandro. The Brazier is in the Temple of the Sun. - Given and taken by Sandro (area 6). Taken when Qbit 27 set.
        evt.SetNPCTopic(11, 3, 634) -- Dyson Leland topic 3: Roster Join Event
        return
    elseif IsQBitSet(QBit(26)) then -- Find the skeleton transformer in the Shadowspire Necromancers' Guild. Destroy it and return to Oskar Tyre. - Given and taken by Oskar Tyre (area 7). Taken when Qbit 29 set.
        evt.SetNPCTopic(11, 3, 634) -- Dyson Leland topic 3: Roster Join Event
    else
        evt.SetNPCTopic(11, 3, 100) -- Dyson Leland topic 3: Join
    end
end)

RegisterGlobalEvent(99, "Yourself", function()
    evt.SimpleMessage("A few months ago, I was called to a private audience with the Sun Temple head priest, Oskar Tyre. He sent me out on a mission of infiltration against the Necromancers' Guild. \"Become as they are,\" he said. \"Gain their trust. While you bide your time waiting to deliver a killing blow, feed us their secrets.\"A too simple plan from too simple a leader! Oh, I did as he said, bathing myself in evil so I might seem evil. But it was as if the guild could see into my heart. I was unmasked as a spy. Under threat of death, I now follow their orders. ")
end)

RegisterGlobalEvent(100, "Join", function()
    evt.SimpleMessage("Join with you? An interesting idea. But what can you offer me? After all I have been through I find myself consumed with a thirst for revenge. I would go with you, but am unwilling to spend my efforts lightly. Give me an opportunity to hurt one of my enemies--the cursed Temple of the Sun or the abominable Necromancers' Guild--and I will travel with you gladly.")
end)

RegisterGlobalEvent(101, "Thant", function()
    evt.SimpleMessage("Now that the Nightshade Brazier covers Shadowspire in its fortifying darkness. Thant goes to lead his minions.")
end)

RegisterGlobalEvent(102, "Alliance", function()
    evt.SimpleMessage("Certainly the elemental unrest concerns us greatly. Why one need travel only a short distance north from our temple to see a great maelstrom of unnatural duration and fury. But sadly we have other matters pressing.The sick horror that is the Necromancers' Guild must be blighted from this land! We wage holy war on the evil in Shadowspire. Our entire spirit and power goes into the campaign we wage against Sandro and his minions. Until that is done we cannot entertain participation in your alliance.")
    evt.SetNPCTopic(33, 0, 103) -- Oskar Tyre topic 0: Quest
end)
RegisterCanShowTopic(102, function()
