RegisterGlobalEvent(513, "Legacy event 513", function()
    if not IsAtLeast(Gold, 1000) then
        evt.SimpleMessage("I can see your heart is in the right place, but your purse obviously isn't.\nIf you don't have the money, just say so.\nIn any event, good luck dealing with the zombies.\nTa-ta!")
        evt.SetNPCTopic(461, 0, 0) -- Lunius Shador topic 0 cleared
        evt.SetNPCTopic(461, 1, 0) -- Lunius Shador topic 1 cleared
        return
    end
    evt.SimpleMessage("This 1000 gold will go a long way to keeping zombies off the roads.")
    SubtractValue(Gold, 1000)
    SetQBit(QBit(761)) -- Don't get ambushed
    evt.SetNPCTopic(461, 0, 0) -- Lunius Shador topic 0 cleared
    evt.SetNPCTopic(461, 1, 0) -- Lunius Shador topic 1 cleared
end)

RegisterGlobalEvent(514, "Legacy event 514", function()
    evt.SimpleMessage("That's a shame.\nWhat a coincidence, I think I see some zombies on the roads.\nPerhaps next time you'll be more inclined to contribute.")
    evt.SetNPCTopic(461, 0, 0) -- Lunius Shador topic 0 cleared
    evt.SetNPCTopic(461, 1, 0) -- Lunius Shador topic 1 cleared
end)

RegisterGlobalEvent(515, "Legacy event 515", function()
    evt.SimpleMessage("Excellent!")
    ClearQBit(QBit(764)) -- Bought Item 3
    if IsAtLeast(Gold, 200) then
        SubtractValue(Gold, 200)
        AddValue(InventoryItem(1494), 1494) -- Crate of Arrowheads
        SetQBit(QBit(762)) -- Bought Item 1
        SetQBit(QBit(768)) -- Can't keep buying 1
        return
    end
    evt.SimpleMessage("You don't have enough gold!")
end)
RegisterCanShowTopic(515, function()
    evt._BeginCanShowTopic(515)
    local visible = true
    if IsQBitSet(QBit(764)) then -- Bought Item 3
        visible = true
        return visible
    else
        if IsQBitSet(QBit(768)) then -- Can't keep buying 1
            visible = false
            return visible
        else
            visible = true
            return visible
        end
    end
end)

