RegisterGlobalEvent(786, "Legacy event 786", function()
    evt.SimpleMessage("Hmm… I recall a few strangers poking around the entrance to the Dragon's Cave recently.\nI didn't notice if they went inside, but I haven't seen them around since.\nThey must have realized how dangerous that place is and headed back to town.")
end)

RegisterGlobalEvent(787, "Legacy event 787", function()
    evt.SimpleMessage("The cave right behind my house is not the Abandoned Temple.\nIt belongs to Morcarack the Pitiless, the Dragon of Emerald Island.\nHe doesn't appreciate visitors, so I wouldn't advise going there.\nThe Abandoned Temple is buried in the hill south of my house.\nYou can get to it by entering the caves at the top of the hill.")
end)

RegisterGlobalEvent(788, "Legacy event 788", function()
    evt.SimpleMessage("Wild Dragonflies have infested the northwestern side of Emerald Island recently, making it dangerous to store things in our shed out there.\nDragonflies aren't terribly powerful, but they are fast and can even occasionally shoot fire at you.\nDon't take them too lightly!")
end)

RegisterGlobalEvent(789, "Legacy event 789", function()
    evt.SimpleMessage("The Dragon of Emerald Island lives in a cave in the northeast.\nI wouldn't go there, though, he doesn't like visitors.\nHe spares our town so that we may pay him tribute, and in return he keeps pirates and undesirables out.")
end)

RegisterGlobalEvent(790, "Legacy event 790", function()
    evt.SimpleMessage("You're contestants in the Scavenger Hunt?\nIf so, I wouldn't wander off to the Dragon Cave, then.\nMorcarack doesn't tolerate strangers very well.\nI bet the missing people went there thinking his cave was the Abandoned Temple--they're probably long dead.")
end)

RegisterGlobalEvent(791, "Legacy event 791", function()
    evt.SimpleMessage("I'd watch those other contestants-- some of them seem ruthless.\nOne particularly nasty group headed to the north side of the island, and I haven't seen them since.\nI'm surprised at the attention this contest has received, apparently people are hoping to get on the good side of the contestants for future favors if they win.")
end)

RegisterGlobalEvent(792, "Legacy event 792", function()
    evt.SimpleMessage("You have decided that you no longer desire my information about the places on Emerald Island.\nIf you later decide that you'd like to hear what I have to say, find me in the Two Palms tavern and then select Tour On.")
    SetQBit(QBit(529)) -- No more docent babble
    evt.SetNPCTopic(342, 2, 793) -- Margaret the Docent topic 2: Tour On
    evt.MoveNPC(342, 239) -- Margaret the Docent -> Two Palms Tavern
end)

RegisterGlobalEvent(793, "Legacy event 793", function()
