RegisterGlobalEvent(794, "Legacy event 794", function()
    evt.SimpleMessage("Though the law may decide who is guilty and who is not, I decide who is called Thief, and who is just a criminal.\nBring me that lovely vase I saw on the mantle in Lord Markham’s manor, and I shall call you Rogue.")
    SetQBit(QBit(530)) -- Go to Lord Markham's estate in Tatalia, steal the vase there, and return it to William Lasker in the Erathian Sewers.
    evt.SetNPCTopic(354, 0, 795) -- William Lasker topic 0: Rogue
end)

RegisterGlobalEvent(795, "Legacy event 795", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1426) then -- Vase
        evt.SimpleMessage("Common criminals steal whatever catches their eye; Rogues steal what I tell them to steal.\nI shall not grant titles to failures.\nReturn with Lord Markham’s Vase and I will promote all Thieves to Rogues, and all non-thieves to Honorary Rogues.")
        return
    end
    evt.SimpleMessage("Well done.\nStealing that vase took guts and skill.\nI grant you the title of Rogue, and a small payment for your services. ")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 34) then
            SetValue(ClassId, 35)
            SetQBit(QBit(1560)) -- Promoted to Rogue
            AddValue(Experience, 30000)
        else
            SetQBit(QBit(1561)) -- Promoted to Honorary Rogue
            AddValue(Experience, 15000)
        end
    end
    evt.ForPlayer(Players.All)
    RemoveItem(1426) -- Vase
    evt.ForPlayer(Players.Current)
    ClearQBit(QBit(724)) -- Vase - I lost it
    AddValue(Gold, 5000)
    ClearQBit(QBit(530)) -- Go to Lord Markham's estate in Tatalia, steal the vase there, and return it to William Lasker in the Erathian Sewers.
    evt.SetNPCTopic(354, 0, 796) -- William Lasker topic 0: Spy
end)

RegisterGlobalEvent(796, "Legacy event 796", function()
    evt.ForPlayer(Players.All)
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("Your next task is somewhat more difficult…more suited for Spies than Rogues.\nI have been asked to ensure that Watchtower 6, the only tower to survive the recent wars against the Necromancers, be unable to defend itself the next time it is attacked.\nKilling the guards inside won’t help—the Necromancers will just fill it again with more troops.\nThe tower is on the southern edge of the Necromancers’ land.\nI want you to slip inside and move the counterweight in the gatehouse at the top of the tower to the gatehouse at the bottom of the tower.\nIt is a heavy weight that can be found in a slot against the wall with a rope tied to it.\nWhen the time comes for an attack, the misplaced weights will be noticed too late, and the gate will not close.\nIf you can do this, you will have proven your status as a Spy.")
        SetQBit(QBit(531)) -- Go to Watchtower 6 in the Deyja Moors, and move the weight from the top of the tower to the bottom of the tower. Then return to William Lasker in the Erathian Sewers.
        evt.SetNPCTopic(354, 0, 797) -- William Lasker topic 0: Spy
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("You have chosen the path of Darkness, and I will promote you no further.\nPerhaps an Assassin would have something to teach you.\nI hear there is one in Deyja.")
    else
        evt.SimpleMessage("You are not quite ready to take the next step.\nThe time is fast approaching when you must decide whether to follow the path of light, or the path of darkness.\nIf you choose the Light, return to me to complete your training.")
    end
end)

RegisterGlobalEvent(797, "Legacy event 797", function()
    evt.ForPlayer(Players.All)
    if IsQBitSet(QBit(532)) then -- Watchtower 6. Weight in the appropriate box. Important for Global event 47 (Spy promotion)
        evt.SimpleMessage("Good work!\nSome day, your sabotage of that watchtower will save hundreds of lives.\nFor your services, I hereby promote the Rogues among you to the status of Spy, and the Honorary Rogues to Honorary Spies! Oh, and here’s some gold as payment. ")
        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
            evt.ForPlayer(player)
            if IsAtLeast(ClassId, 35) then
                SetValue(ClassId, 37)
                SetQBit(QBit(1562)) -- Promoted to Spy
                AddValue(Experience, 80000)
            else
                SetQBit(QBit(1563)) -- Promoted to Honorary Spy
                AddValue(Experience, 40000)
            end
        end
        AddValue(Gold, 15000)
        ClearQBit(QBit(531)) -- Go to Watchtower 6 in the Deyja Moors, and move the weight from the top of the tower to the bottom of the tower. Then return to William Lasker in the Erathian Sewers.
        evt.ForPlayer(Players.All)
        evt.SetNPCTopic(354, 0, 0) -- William Lasker topic 0 cleared
        evt.SetNPCGreeting(354, 154) -- William Lasker greeting: Greetings Rogues, how may I be of service?
    elseif HasItem(0) then -- 0
        evt.SimpleMessage("Um…The weight needs to go in the box in the lower gatehouse—not here.")
        return
    elseif IsQBitSet(QBit(568)) then -- Watchtower 6. Taken the weight from the upper gatehouse. Spy promo quest
        evt.SimpleMessage("Hmm.\nRemoving the weight from the upper gatehouse was a start, but where is it now?!?\nThe plan won’t work unless you put the weight in the lower gatehouse!\nGo back to Watchtower 6 and put the weight in the right box!")
    else
        evt.SimpleMessage("You haven’t done the job yet!\nRemember, you must go to Watchtower 6 and move the weight from the box in the upper gatehouse to the lower gatehouse.\nI will not promote you until that is done. ")
    end
end)

