        SetQBit(QBit(533)) -- Go to the Celestial Court in Celeste and kill Lady Eleanor Carmine. Return with proof to Seknit Undershadow in the Deyja Moors.
        evt.SetNPCTopic(355, 1, 800) -- Seknit Undershadow topic 1: Assassin
    elseif IsQBitSet(QBit(1561)) then -- Promoted to Honorary Rogue
        if not IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("I can turn a simple Rogue into a fearsome killer, but only if he has the right kind of temperament for the job.\nThe time is coming when you must choose to walk in the light, or in the dark.\nIf you prefer the shadow, come to me and I will complete your training.")
            return
        end
        evt.SimpleMessage("So…you wish to become an Assassin.\nVery well.\nI can provide the Rogues among you the training necessary, but you must prove both your skill and your loyalty before I will invest time in you.\nMy superiors inform me that a certain Lady Eleanor Carmine’s life must end.\nShe used to work for us, but has taken up residence in the Celestial Court with our enemies, and is providing them with information damaging to our cause.\nSilence her, and return with a trinket of hers to prove the job is done.")
        SetQBit(QBit(533)) -- Go to the Celestial Court in Celeste and kill Lady Eleanor Carmine. Return with proof to Seknit Undershadow in the Deyja Moors.
        evt.SetNPCTopic(355, 1, 800) -- Seknit Undershadow topic 1: Assassin
    else
        evt.SimpleMessage("If you were looking for someone to train you in advanced stealth techniques, I\nwould be your man.\nBut you still need someone to teach you basic techniques.\nReturn to me when you achieve Rogue or Honorary Rogue status.\nThen, perhaps, I can further your education.\nSeek the Master Thief in the sewers of Erathia.")
        return
    end
end)

RegisterGlobalEvent(800, "Legacy event 800", function()
