end)

RegisterGlobalEvent(801, "Legacy event 801", function()
    evt.SimpleMessage("Ha! So, thee wishes to take the test to be a crusader?\nI cannot blame thee—the sense of pride one feels when one has accomplished a heroic deed is sublime!\nThe test is simple.\nA dragon must be slain.\nI know just the one—Wromthrax the Heartless!\nHe lives in a cave in Tatalia, and terrorizes the peasants who live near him when he’s home.\nHe should be in the cave this time of year.\nBecause this is probably thine first dragon, I will travel with thee to give thee pointers.\nSo, let us go forthwith, and spill this monster’s black blood!")
    evt.SetNPCTopic(356, 0, 802) -- Sir Charles Quixote topic 0: Crusader
    evt.MoveNPC(356, 0) -- Sir Charles Quixote -> removed
    SetQBit(QBit(534)) -- Kill Wromthrax the Heartless in his cave in Tatalia, then talk to Sir Charles Quixote.
    evt.SetNPCGreeting(356, 159) -- Sir Charles Quixote greeting 159
    SetQBit(QBit(1684)) -- Replacement for NPCs ą17 ver. 7
end)

