RegisterGlobalEvent(803, "Legacy event 803", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("I am pleased to see thee chose the path of Light, Crusaders!\nA wrong has been committed, friends, and who else but us can put it right?\nA wicked villain has kidnapped a fair maiden by the name of Alice Hargreaves.\nHis name is William Setag, and he has imprisoned her in his tower.\nYou must ride forthwith to put this villain to the sword and rescue sweet Alice!\nIf you succeed, you will truly be Heroes of the Land!")
        evt.SetNPCTopic(356, 0, 804) -- Sir Charles Quixote topic 0: Hero
        SetQBit(QBit(536)) -- Rescue Alice Hargreaves from William's Tower in the Deyja Moors then talk to Sir Charles Quixote.
