        evt.MoveNPC(393, 1158) -- Alice Hargreaves -> Alice Hargreaves
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("I will not have truck with thee further, scoundrel!\nI see now thee hath chosen the path of Darkness.\nMayhaps thee should seek a villain like thyself for training.")
