RegisterGlobalEvent(806, "Legacy event 806", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("I'd certainly love nothing more than to corrupt your obviously pious soul, but I'm afraid you wouldn't have the stomach to follow through with my teachings.\nYou have chosen the Path of Light, you will garner no assistance from me.")
        return
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("Let's get down to business, shall we?\nI know you are well aware of my standing as the blackest Villain in Erathia.\nIt requires effort and drive to prove to be this evil-- I hope you have the mettle for it.\nI would love nothing more than to keep you in my training for years and teach you the finest parts of being a Villain.\nUnfortunately, I am under pressure to speed up your tutelage.\nTo this end, I have a direct way to learn the arts of Villainhood.\nThere is a woman, Alice Hargreaves, who is of noble blood and pure character.\nCapture this woman from her residence in Castle Gryphonheart. Return here and imprison her in my tower.\nComplete this, and I shall promote all Crusaders in your group to Villains, and the rest of your group to Honorary Villains.")
        if IsQBitSet(QBit(1590)) then -- Promoted to Crusader
            SetQBit(QBit(538)) -- Capture Alice Hargreaves from her residence in Castle Gryphonheart and return her to William's Tower in the Deyja Moors.
            evt.SetNPCTopic(357, 0, 807) -- William Setag topic 0: Villain
            evt.MoveNPC(393, 1158) -- Alice Hargreaves -> Alice Hargreaves
        elseif IsQBitSet(QBit(1591)) then -- Promoted to Honorary Crusader
            SetQBit(QBit(538)) -- Capture Alice Hargreaves from her residence in Castle Gryphonheart and return her to William's Tower in the Deyja Moors.
            evt.SetNPCTopic(357, 0, 807) -- William Setag topic 0: Villain
            evt.MoveNPC(393, 1158) -- Alice Hargreaves -> Alice Hargreaves
        else
            evt.SimpleMessage("I cannot improve upon training you do not already have.")
            return
        end
    else
        evt.SimpleMessage("Before you make this decision, you have a more pressing, immediate decision you will be forced to make.\nIf you choose the darker road, you may return to me and complete your training in the Paladins' arts.")
        return
    end
end)

