        evt.SetNPCGreeting(378, 170) -- Stephan Sand greeting: Now that you've achieved the exhalted status of Ninja, I have nothing further to give you. I hope my teachings take you far.
    elseif IsQBitSet(QBit(569)) then -- Solved the code puzzle. Ninja promo quest
        evt.SimpleMessage("So you have the key, but you haven't followed the directions in the message.\nRemember, the tomb is in Southern Erathia.\nComplete your task, and return to me to report success.\nIf you can't complete your mission, don't bother returning to me.\nFailure is pathetic.")
    else
        evt.SimpleMessage("[Sand sighs] Once again, the cipher key is the third word of the first paragraph of the Scroll of Waves.\nYou can find it somewhere in the School of Wizardry.\nI don't care how you get in there--kill anyone who gets in your way, or sneak in.\nWhatever you want.\nThe only thing that matters is success.\nEverything else is an excuse for personal weakness.")
    end
end)

RegisterGlobalEvent(815, "Legacy event 815", function()
    if IsQBitSet(QBit(1584)) then -- Promoted to Warrior Mage
        if IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("A few generations ago, an enchanted bow was created by alchemists in the Tularean Forest to seal another peace treaty between the elves and the humans.\nWhile en route to Erathia, the bow was taken from the couriers by the Titans in Avlee.\nThey have no use for the thing, so it's probably in their stronghold still.\nStrike a blow for our profession, and get that bow back.\nIt is absolutely the finest thing of its kind ever made.\nOh, and while you're there, feel free to cut some of those bullies down to size--They stole it out of cruelty, not need!\nIf you are successful, I will promote all Warrior Mages to Master Archers, or honorary Master Archers, as the case may be.")
            SetQBit(QBit(542)) -- Retrieve the Perfect Bow from the Titans' Stronghold in Avlee and return it to Lawrence Mark in Harmondale.
            evt.SetNPCTopic(379, 0, 816) -- Lawrence Mark topic 0: Master Archer
        elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("You have chosen the path of Darkness.\nI will never help you improve, for fear you will use your skills to advance your selfish goals!")
        else
            evt.SimpleMessage("So, you've achieved the rank of Warrior Mage, and wish to advance to Master Archer!\nA worthy goal, but I only promote those who's heart and courage match their skill.\nCome back to me when you have firmly committed to the Light.\nThen I will help you.")
        end
        return
    elseif IsQBitSet(QBit(1585)) then -- Promoted to Honorary Warrior Mage
        if IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("A few generations ago, an enchanted bow was created by alchemists in the Tularean Forest to seal another peace treaty between the elves and the humans.\nWhile en route to Erathia, the bow was taken from the couriers by the Titans in Avlee.\nThey have no use for the thing, so it's probably in their stronghold still.\nStrike a blow for our profession, and get that bow back.\nIt is absolutely the finest thing of its kind ever made.\nOh, and while you're there, feel free to cut some of those bullies down to size--They stole it out of cruelty, not need!\nIf you are successful, I will promote all Warrior Mages to Master Archers, or honorary Master Archers, as the case may be.")
            SetQBit(QBit(542)) -- Retrieve the Perfect Bow from the Titans' Stronghold in Avlee and return it to Lawrence Mark in Harmondale.
            evt.SetNPCTopic(379, 0, 816) -- Lawrence Mark topic 0: Master Archer
        elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("You have chosen the path of Darkness.\nI will never help you improve, for fear you will use your skills to advance your selfish goals!")
        else
            evt.SimpleMessage("So, you've achieved the rank of Warrior Mage, and wish to advance to Master Archer!\nA worthy goal, but I only promote those who's heart and courage match their skill.\nCome back to me when you have firmly committed to the Light.\nThen I will help you.")
        end
    else
        evt.SimpleMessage("I am the person to see if you want to become Master Archers, but you have come too soon!\nYou must have the proper background to become a Master, and that means first becoming a warrior mage.\nReturn when you are ready.")
    end
end)

RegisterGlobalEvent(816, "Legacy event 816", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1344) then -- The Perfect Bow
        evt.SimpleMessage("No luck getting the bow?\nWell, take your time, and plan your assault against the Titans carefully.\nAgainst such powerful opponents, there is no shame in striking and retreating.\nDo what you must to defeat these monsters.")
        return
    end
    evt.SimpleMessage("You found the bow!\nLet me take some measurements and adjust it to your specific style of archery. Once I have finished you should keep it, and use it in defense the of the land and the people.\nI am happy to promote all Warrior Mages to Master Archers, and all Honorary Warrior Mages to Honorary Master Archers.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 1) then
            SetValue(ClassId, 2)
            SetQBit(QBit(1586)) -- Promoted to Master Archer
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1587)) -- Promoted to Honorary Master Archer
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(542)) -- Retrieve the Perfect Bow from the Titans' Stronghold in Avlee and return it to Lawrence Mark in Harmondale.
    AddValue(InventoryItem(1345), 1345) -- The Perfect Bow
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    if HasItem(1344) then -- The Perfect Bow
        RemoveItem(1344) -- The Perfect Bow
    end
    evt.SetNPCTopic(379, 0, 0) -- Lawrence Mark topic 0 cleared
    evt.SetNPCGreeting(379, 172) -- Lawrence Mark greeting: Welcome my friends! That's a fine weapon you have there, but don't think for a moment you'll best me in this year's Tourney--I'm still the Master!
end)

RegisterGlobalEvent(817, "Legacy event 817", function()
    evt.SimpleMessage("[Wheeze] So you think you can become Warrior Mages, do you?\nIt isn't easy.\nYou must be equally proficient in magical skills and physical skills.\nThere is a test of this.\nVisit the Red Dwarf Mines.\nInside you will find two kinds of beasts--one that can be harmed only with magic, and one that can be harmed only with steel.\nIn the back of the lower section of the mines you will find a machine created by the Dwarves that powers the lift-- the only access between the upper and lower sections of the mines.\nTo keep the creatures trapped in the lower section, you will have to replace the belt in the machine with this one, a worn belt that will only last about an hour before breaking.\nThis should give you enough time to get to the lift and get out before you are trapped down there.\nSeal away these creatures and return to me-- only then will I call you Warrior Mages.")
    AddValue(InventoryItem(1451), 1451) -- Worn Belt
    SetQBit(QBit(543)) -- Sabotage the lift in the Red Dwarf Mines in the Bracada Desert then return to Steagal Snick in Avlee.
    SetQBit(QBit(728)) -- Worn Belt - I lost it
    evt.SetNPCTopic(380, 0, 818) -- Steagal Snick topic 0: Warrior Mage
end)

RegisterGlobalEvent(818, "Legacy event 818", function()
    if not IsQBitSet(QBit(570)) then -- Destroyed critter generator in dungeon. Warrior Mage promo quest.
        evt.SimpleMessage("You haven't sabotaged the machine yet.")
        return
    end
    evt.SimpleMessage("Very Good.\nYou have passed the test.\nNow the creatures are sealed away and won't be able to prey on the dwarves any longer, and you have proven your ability in both sorcery and steel.\nI am proud to declare all Archers amongst you Warrior Mages, and everyone else Honorary Warrior Mages.\nCongratulations!\nNow get out.\nI already weary of your company.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 0) then
            SetValue(ClassId, 1)
            SetQBit(QBit(1584)) -- Promoted to Warrior Mage
            AddValue(Experience, 30000)
        else
            SetQBit(QBit(1585)) -- Promoted to Honorary Warrior Mage
            AddValue(Experience, 15000)
        end
    end
    ClearQBit(QBit(543)) -- Sabotage the lift in the Red Dwarf Mines in the Bracada Desert then return to Steagal Snick in Avlee.
    AddValue(Gold, 7500)
    SubtractValue(ReputationInCurrentLocation, 5)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(380, 0, 819) -- Steagal Snick topic 0: Sniper
end)

RegisterGlobalEvent(819, "Legacy event 819", function()
    if IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("Getting ambitious, are we?\nThink you can earn the title of sniper?\nPerhaps you can.\nHere is what you must do:\nIn the stronghold of the Titans is a very special bow that was meant as a peace offering from the elves to the humans to quell a conflict long since forgotten.\n[Master Snick shakes his head] Gads! This peace stuff makes me nauseous!\nIn any case, fetch the bow for the good of our profession, and I'll promote you to Sniper.\n[Heh] you better act like snipers if you expect to defeat the Titans.\nA toe to toe...or should I say head to knee fight won't go well for you.")
        SetQBit(QBit(544)) -- Retrieve the Perfect Bow from the Titans' Stronghold in Avlee and return it to Steagal Snick in Avlee.
        evt.SetNPCTopic(380, 0, 820) -- Steagal Snick topic 0: Sniper
    elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("Following the Path of Light, are we?\nHow can you be a Sniper if you cry everytime you shoot someone in the back?\nMaybe you should ask that lily-livered Lawrence Mark to help you.\nI know that I will not.")
    else
        evt.SimpleMessage("Want to be a Sniper, eh? Maybe.\nBut I doubt you have the heart for it.\nIt needs to shrivel like a raisin and get hard as a stone to be able to do what you must.\nProve to me you are following the Path of Darkness, and then I will teach you further.")
    end
end)

RegisterGlobalEvent(820, "Legacy event 820", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1344) then -- The Perfect Bow
        evt.SimpleMessage("More failure? [Master Snick yawns]\nHow surprising.\nI'll make it simple--no bow, no title.")
        return
    end
    evt.SimpleMessage("You have the bow?!\nExcellent!\nIt's been centuries since someone was brave enough to take on the Titans and try to get that bow back!\nLet me take some measurements and adjust it to your specific style of archery.\nI am proud to be the one to first call all Warrior Mages amongst you Snipers, and to say that all Honorary Warrior Mages are Honorary Snipers!\nI must admit I didn't think you had it in you to succeed.\nI am happy that I was wrong.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 1) then
            SetValue(ClassId, 3)
            SetQBit(QBit(1588)) -- Promoted to Sniper
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1589)) -- Promoted to Honorary Sniper
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(544)) -- Retrieve the Perfect Bow from the Titans' Stronghold in Avlee and return it to Steagal Snick in Avlee.
    AddValue(InventoryItem(1345), 1345) -- The Perfect Bow
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    if HasItem(1344) then -- The Perfect Bow
        RemoveItem(1344) -- The Perfect Bow
    end
    evt.SetNPCTopic(380, 0, 0) -- Steagal Snick topic 0 cleared
    evt.SetNPCGreeting(380, 174) -- Steagal Snick greeting: Students…[Mr. Snick rasps the word, then smiles] no longer. I am proud to have helped you on your way. Use your new weapon…[wheeze] wisely.
end)

RegisterGlobalEvent(821, "Legacy event 821", function()
    if IsQBitSet(QBit(1566)) then -- Promoted to Cavalier
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("Call you Champions?\nNever!\nThe only reason I'm not hacking you evil doers to bits is that you came here peacefully.\nLeave now, before I change my mind and rid the world of another problem.")
            return
        elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("So you want to be champions, do you?\nHa!\nHow can you be a champion if you don't win any tournaments?\nYou know, I can't really promote you to Champion status--you have to do it yourself, just like everything else.\nGo and win five championship tournaments in the Arena at Knight level, and come back to me.\nI'll call you Champions then, if you want.")
            SetQBit(QBit(545)) -- Win five arena challenges then return to Leda Rowan in the Bracada Desert.
            evt.SetNPCTopic(381, 0, 822) -- Leda Rowan topic 0: Champion
        else
            evt.SimpleMessage("I can see you very much want to be called Champions, but I'm not so sure I should help you.\nProve to me that you follow the Path of Light, and then we'll talk about promotion.")
            return
        end
    elseif IsQBitSet(QBit(1567)) then -- Promoted to Honorary Cavalier
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("Call you Champions?\nNever!\nThe only reason I'm not hacking you evil doers to bits is that you came here peacefully.\nLeave now, before I change my mind and rid the world of another problem.")
            return
        elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("So you want to be champions, do you?\nHa!\nHow can you be a champion if you don't win any tournaments?\nYou know, I can't really promote you to Champion status--you have to do it yourself, just like everything else.\nGo and win five championship tournaments in the Arena at Knight level, and come back to me.\nI'll call you Champions then, if you want.")
            SetQBit(QBit(545)) -- Win five arena challenges then return to Leda Rowan in the Bracada Desert.
            evt.SetNPCTopic(381, 0, 822) -- Leda Rowan topic 0: Champion
        else
            evt.SimpleMessage("I can see you very much want to be called Champions, but I'm not so sure I should help you.\nProve to me that you follow the Path of Light, and then we'll talk about promotion.")
            return
        end
    else
        evt.SimpleMessage("I am the person to talk to if you want to be called Champions.\nFirst, though, you must practice.\nReturn to me when you've become Cavaliers.\nThen, if you have the right outlook, I will tell you what you must do to become Champions.")
        return
    end
end)

RegisterGlobalEvent(822, "Legacy event 822", function()
    if not IsAtLeast(ArenaWinsKnight, 5) then
        evt.SimpleMessage("You have not yet won 5 championship tournaments in the Arena.\nReturn to me when you have won five, and I will promote you.\nRemember, these battles MUST be at the Knight difficulty level.")
        return
    end
    evt.SimpleMessage("Congratulations for you recent tourney victories, my friends!\nI gladly name the Cavaliers among you Champions, and the Honorary Cavaliers I name Honorary Champions!\nAlways fight for the Light, Champions!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 17) then
            SetValue(ClassId, 19)
            SetQBit(QBit(1568)) -- Promoted to Champion
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1569)) -- Promoted to Honorary Champion
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(545)) -- Win five arena challenges then return to Leda Rowan in the Bracada Desert.
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(381, 0, 0) -- Leda Rowan topic 0 cleared
    evt.SetNPCGreeting(381, 176) -- Leda Rowan greeting: Hail, champions! Your courage and skill has all the tongues in the Kingdom wagging! I am very proud of you!
end)

RegisterGlobalEvent(823, "Legacy event 823", function()
    evt.SimpleMessage("The hallmark of the Cavalier is courage.\nI can promote you to Cavalier status, but before I'll do that, you'll have to prove to me your bravery in battle.\nSince most people are yellow bellied cowards at heart, I doubt you'll succeed.\nBut if you want to try, here is what you must do: Destroy all the undead in the haunted mansion in the Barrow Downs.")
    SetQBit(QBit(546)) -- Destroy all the undead in the Haunted House in the Barrow Downs and return to Frederick Org in Erathia.
    evt.SetNPCTopic(382, 0, 824) -- Frederick Org topic 0: Cavalier
end)

RegisterGlobalEvent(824, "Legacy event 824", function()
    evt.ForPlayer(Players.All)
    if not IsQBitSet(QBit(652)) then -- Cleaned out the haunted mansion (Cavalier promo)
        evt.SimpleMessage("Did one little haunted house send you packing in fear?\nI've seen chocolate eclairs with more backbone than you!\nGet you gone, and don't come back 'til you've stiffened your spine!")
        return
    end
    evt.SimpleMessage("So you're back!\nAnd from the look on your faces I see you have finished the job.\nWell done!\nI hereby officially promote all Knights amongst you to Cavaliers, and everyone else to honorary Cavaliers.\nCarry your title with pride!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 16) then
            SetValue(ClassId, 17)
            SetQBit(QBit(1566)) -- Promoted to Cavalier
            AddValue(Experience, 30000)
        else
            SetQBit(QBit(1567)) -- Promoted to Honorary Cavalier
            AddValue(Experience, 15000)
        end
    end
    ClearQBit(QBit(546)) -- Destroy all the undead in the Haunted House in the Barrow Downs and return to Frederick Org in Erathia.
    SubtractValue(ReputationInCurrentLocation, 5)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(382, 0, 825) -- Frederick Org topic 0: Black Knight
end)

RegisterGlobalEvent(825, "Legacy event 825", function()
    if IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("So you think you can become Black Knights, do you?\nVery well.\nYou know, I've heard many people say that criminals are cowards.\nThat just isn't true.\nIt takes a lot of courage to risk your life in a robbery, or in battle.\nYou've already proven you are courageous, and now it's time to put that courage and your skills to use.\nI want you to rob the Elvish Treasury.\nIt's one of the biggest hoards of treasure in the land, and it is very well guarded.\nDo the deed and abscond with the wealth.\nReturn to me when you've finished.\nThen I will promote you to Black Knights.")
        SetQBit(QBit(547)) -- Raid the Elven Treasury at Castle Navan in the Tularean Forest and return to Frederick Org in Erathia.
        evt.SetNPCTopic(382, 0, 826) -- Frederick Org topic 0: Black Knight
    elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("Bah!")
    else
        evt.SimpleMessage("It's true that I am the one you go to when you're looking to be promoted to Black Knight status.")
    end
end)

RegisterGlobalEvent(826, "Legacy event 826", function()
    if not IsQBitSet(QBit(572)) then -- Robbed Elven treasury. Black Knight promo quest.
        evt.SimpleMessage("Robbery not complete?")
        return
    end
    evt.SimpleMessage("All RIGHT!\nThat robbery was brilliant!\nI am very proud of you.\nKeep the loot--it's your reward for a job well done.\nI can safely say the Cavaliers among you have become Black Knights today, and I'll throw in an Honorary Black Knight title for the rest of you.\nYou've done well, my students!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 17) then
            SetValue(ClassId, 18)
            SetQBit(QBit(1570)) -- Promoted to Black Knight
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1571)) -- Promoted to Honorary Black Knight
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(547)) -- Raid the Elven Treasury at Castle Navan in the Tularean Forest and return to Frederick Org in Erathia.
    AddValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(382, 0, 0) -- Frederick Org topic 0 cleared
    evt.SetNPCGreeting(382, 178) -- Frederick Org greeting: [Frederick rises hastily to his feet] None shall pass! [he blinks and rubs his eyes] Oh. It's you. Sorry, I thought you were someone else. How goes the villainy?
end)

RegisterGlobalEvent(827, "Legacy event 827", function()
    if IsQBitSet(QBit(1578)) then -- Promoted to Hunter
        if IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Well, it looks like you might be able to do the job I have in mind.\nThe fundamental task a Ranger Lord faces is caring for the land.\nRecently, poachers removed a magical gemstone called the \"heart of the forest\" from the Tularean Forest.\nThe forest has become restless, and attacks travelers who come too close.\nThe forest blames all 'Walkers' for the theft, and won't calm down until the stone is returned.\nFind the stone and return it to the oldest tree in the Forest.\nCome back to me when you've done this.")
            SetQBit(QBit(548)) -- Calm the trees in the Tularean Forest by speaking to the Oldest Tree then return to Lysander Sweet in the Bracada Desert.
            evt.SetNPCTopic(383, 0, 828) -- Lysander Sweet topic 0: Ranger Lord
        elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("[Lysander frowns] You've chosen the path of darkness.")
        else
            evt.SimpleMessage("I would like to be your teacher--I really would, but I'm not sure you're cut out to be a Ranger Lord.\nSoon you must make a decision of the heart.\nIf you choose the Path of Light, return to me.\nI would be honored to be your teacher.")
        end
        return
    elseif IsQBitSet(QBit(1579)) then -- Promoted to Honorary Hunter
        if IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Well, it looks like you might be able to do the job I have in mind.\nThe fundamental task a Ranger Lord faces is caring for the land.\nRecently, poachers removed a magical gemstone called the \"heart of the forest\" from the Tularean Forest.\nThe forest has become restless, and attacks travelers who come too close.\nThe forest blames all 'Walkers' for the theft, and won't calm down until the stone is returned.\nFind the stone and return it to the oldest tree in the Forest.\nCome back to me when you've done this.")
            SetQBit(QBit(548)) -- Calm the trees in the Tularean Forest by speaking to the Oldest Tree then return to Lysander Sweet in the Bracada Desert.
            evt.SetNPCTopic(383, 0, 828) -- Lysander Sweet topic 0: Ranger Lord
        elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("[Lysander frowns] You've chosen the path of darkness.")
        else
            evt.SimpleMessage("I would like to be your teacher--I really would, but I'm not sure you're cut out to be a Ranger Lord.\nSoon you must make a decision of the heart.\nIf you choose the Path of Light, return to me.\nI would be honored to be your teacher.")
        end
    else
        evt.SimpleMessage("[Lysander shakes his head, smiling gently] Too soon, eager ones.\nI train only the most advanced students.\nSeek me out again when you reach Hunter status.")
    end
end)

RegisterGlobalEvent(828, "Legacy event 828", function()
    if IsQBitSet(QBit(553)) then -- Solved Tree quest
        evt.SimpleMessage("You've done a good thing, returning the Heart.\nThe forest is quieter now, and no longer attacks travelers.\nYou've probably saved many lives.\nFor service to the Land and the Light, I hereby promote all Hunters among you to Ranger Lords, and all honorary Hunters to honorary Ranger Lords!")
        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
            evt.ForPlayer(player)
            if IsAtLeast(ClassId, 31) then
                SetValue(ClassId, 33)
                SetQBit(QBit(1580)) -- Promoted to Ranger Lord
                AddValue(Experience, 80000)
            else
                SetQBit(QBit(1581)) -- Promoted to Honorary Ranger Lord
                AddValue(Experience, 40000)
            end
        end
        ClearQBit(QBit(548)) -- Calm the trees in the Tularean Forest by speaking to the Oldest Tree then return to Lysander Sweet in the Bracada Desert.
        SubtractValue(ReputationInCurrentLocation, 10)
        evt.ForPlayer(Players.All)
        evt.SetNPCTopic(383, 0, 0) -- Lysander Sweet topic 0 cleared
        evt.SetNPCGreeting(383, 180) -- Lysander Sweet greeting: Your good works have served the forest well. And, I can see, the experience has served you well in turn. May you continue to reap the rewards of your good deeds, my friends!
    elseif IsQBitSet(QBit(552)) then -- Talked to the Oldest Tree
        evt.SimpleMessage("Well, you've spoken with the tree, and now know as much as I do about the theft.\nIf you manage to find the stone, take it directly to the tree and then come see me.")
    else
        evt.SimpleMessage("If you can't figure out where to start, you should try finding the oldest tree in the forest.\nIt should be somewhere outside of Pierpont in Avlee.\nThe oldest tree has the power of speech, and may know something helpful.\nIt will be happy to tell you whatever you want to hear, plus a whole lot more.\nYou'll see.")
    end
end)

RegisterGlobalEvent(829, "Legacy event 829", function()
    evt.SimpleMessage("Think you can improve?\nI have a test for you.\nA hunter needs to understand the woods, and a hunter needs to be as skilled with magic as with a blade.\nThe best teachers for that are the faeries.\nThere's a faerie mound in Northern Avlee.\nFigure out how to get in, and the Faeries will grant magic to the genuine rangers among you, meaning that they will be promoted to Hunter status.\nThe rest of you will be honorary hunters. ")
    SetQBit(QBit(549)) -- Solve the secret to the entrance of the Faerie Mound in Avlee and speak to the Faerie King.
    evt.SetNPCTopic(384, 0, 830) -- Ebednezer Sower topic 0: Hunter
end)

RegisterGlobalEvent(830, "Legacy event 830", function()
    evt.SimpleMessage("Foxed by the Faeries? [Ebednezer snickers, then begins to laugh uproariously at his own wit] Foxed?\nFaeries?\nHahahah!\nGet it?\nFoxed… you know…ah ahahah.\nMaybe not.\nWell, I've already told you how to become Hunters.\nGet inside the Faerie Mound in Avlee.\nNow, stop bothering me!\n")
end)

RegisterGlobalEvent(831, "Legacy event 831", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("Gahhh!\nI can smell the stink of self righteousness on you!\nGet away from me!\nG'won, get!")
        return
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("Better a bounty hunter than a plain old hunter, huh?\nWell, this test is even simpler than the Faerie Mound idea, and you won't have to think so hard.\nEver notice how the town halls are always looking for someone to kill a monster for them?\nAll you have to do is collect 10,000 in bounties from town halls.\nWhen you've done that, come back to me, and I'll promote you to Bounty Hunters.\n")
        SetQBit(QBit(550)) -- Collect 10,000 gold worth of bounties from the Bounty Hunts in the town halls, then return to Ebednezer Sower in the Tularean Forest.
        evt.SetNPCTopic(384, 0, 832) -- Ebednezer Sower topic 0: Bounty Hunter
    else
        evt.SimpleMessage("I'll be blunt.\nI don't think I like you.\nYou'll have to prove to me you're worth something.\nSoon, you will have to choose if you'll follow the Path of Dark or the Path of Light.\nIf you choose Light, don't even bother speaking to me again.\nGot it?")
        return
    end
end)

RegisterGlobalEvent(832, "Legacy event 832", function()
    if not IsAtLeast(NumBounties, 10000) then
        evt.SimpleMessage("Not yet, not good enough!\nYou need to collect more bounties, and more importantly, kill more creatures.\nThere's some good clean fun in that.\nKilling, don't you know.")
