RegisterGlobalEvent(836, "Legacy event 836", function()
    if IsQBitSet(QBit(1607)) then -- Promoted to Priest
        if IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Priests.\nYou have come to me seeking that I be your guide on the Path of Light.\nBut be warned, to learn its ways, you must learn the ways of your own soul.\nI would suggest that we meditate on this for awhile, but you look like you're in a hurry.\nSouth of Bracada is an island called Evenmorn, and upon that island are the old temples of the Sun and the Moon.\nBoth are inhabited by the remnants of the two religions, their once proud churches reduced to two old temples fighting for a small island.The Church of the Sun was the founding religion for our current faith, the Path of Light.\nI propose we help them out and tip the balance in favor of the Church of the Sun.\nUsing the map that Daedalus Falk sent you to find in order to become priests, convince a sea captain to bring you to the island.\nThere, bring aid and comfort to the Church of the Sun by purifying the altar in the Church of the Moon.\nThis will so weaken the Moon cult that the Church of the Sun will be able to overcome them in battle.\nReturn to me when you have done this.\n ")
            SetQBit(QBit(554)) -- Purify the Altar of Evil in the Temple of the Moon on Evenmorn Isle then return to Rebecca Devine in Celeste.
            evt.SetNPCTopic(385, 0, 837) -- Rebecca Devine topic 0: Priest of Light
        elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("You've come to the wrong person if you want to be promoted beyond priest.\nI am well aware of your choice to follow the Path of the Dark, and I will have nothing to do with you.")
        else
            evt.SimpleMessage("If you wish to follow the Path of Light, first you must formally choose it.\nSoon you will be asked to make the choice, and the way will be clear.\nUntil then, I cannot be your guide.")
        end
        return
    elseif IsQBitSet(QBit(1608)) then -- Promoted to Honorary Priest
        if IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Priests.\nYou have come to me seeking that I be your guide on the Path of Light.\nBut be warned, to learn its ways, you must learn the ways of your own soul.\nI would suggest that we meditate on this for awhile, but you look like you're in a hurry.\nSouth of Bracada is an island called Evenmorn, and upon that island are the old temples of the Sun and the Moon.\nBoth are inhabited by the remnants of the two religions, their once proud churches reduced to two old temples fighting for a small island.The Church of the Sun was the founding religion for our current faith, the Path of Light.\nI propose we help them out and tip the balance in favor of the Church of the Sun.\nUsing the map that Daedalus Falk sent you to find in order to become priests, convince a sea captain to bring you to the island.\nThere, bring aid and comfort to the Church of the Sun by purifying the altar in the Church of the Moon.\nThis will so weaken the Moon cult that the Church of the Sun will be able to overcome them in battle.\nReturn to me when you have done this.\n ")
            SetQBit(QBit(554)) -- Purify the Altar of Evil in the Temple of the Moon on Evenmorn Isle then return to Rebecca Devine in Celeste.
            evt.SetNPCTopic(385, 0, 837) -- Rebecca Devine topic 0: Priest of Light
        elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("You've come to the wrong person if you want to be promoted beyond priest.\nI am well aware of your choice to follow the Path of the Dark, and I will have nothing to do with you.")
        else
            evt.SimpleMessage("If you wish to follow the Path of Light, first you must formally choose it.\nSoon you will be asked to make the choice, and the way will be clear.\nUntil then, I cannot be your guide.")
        end
    else
        evt.SimpleMessage("If you wish to become Priests of the Light, you must first become Priests.\nI don't have time to train priests, but my bitter rival, Daedalus Falk, does.\nDo not worry, he will promote you fairly, even if you do not wish to follow the terrible path of darkness that he represents.")
    end
end)

RegisterGlobalEvent(837, "Legacy event 837", function()
    if not IsQBitSet(QBit(574)) then -- Purified the Altar of Evil. Priest of Light promo quest.
        evt.SimpleMessage("You must visit Evenmorn island and purify the Altar of Darkness in the Church of the Moon.")
        return
    end
    evt.SimpleMessage("Your bravery has advanced our faith tremendously, Priests.\nIt's with a glad heart that I can hereby promote all Priests to Priests of the Light, and all honorary Priests to Honorary Priests of the Light.\nThank you so much for your help!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 5) then
            SetValue(ClassId, 6)
            SetQBit(QBit(1609)) -- Promoted to Priest of the Light
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1610)) -- Promoted to Honorary Priest of the Light
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(554)) -- Purify the Altar of Evil in the Temple of the Moon on Evenmorn Isle then return to Rebecca Devine in Celeste.
    AddValue(Gold, 10000)
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(385, 0, 0) -- Rebecca Devine topic 0 cleared
    evt.SetNPCGreeting(385, 188) -- Rebecca Devine greeting: Sunlight Reveal, my fellow Priests. I am so proud to have you as members of our faith!
end)

RegisterGlobalEvent(838, "Legacy event 838", function()
    evt.SimpleMessage("[Falk gives you a grandfatherly smile] You have, perhaps, an ambition to be priests?\nI can help you, if you'll help me.\nThere is an island south of Bracada where stands an old temple that I need to find again.\nI think the pirates west of Erathia must know where the island is.\nThe Erathian navy is rather feeble, and hasn't been able to root them out of their hiding places amongst the Tidewater Caverns.\nPerhaps the pirates have a map.\nIf you can bring me that map, I would promote you to Priest status immediately.")
    SetQBit(QBit(555)) -- Find the lost pirate map in the Tidewater Caverns in Tatalia and return to Daedalus Falk in the Deyja Moors.
    evt.SetNPCTopic(386, 0, 839) -- Daedalus Falk topic 0: Priest
end)

RegisterGlobalEvent(839, "Legacy event 839", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1485) then -- Map to Evenmorn Island
        evt.SimpleMessage("If there is a map that says where that island is, the map would be in the Tidewater Caverns of western Erathia.\nWhen you bring me that map, then I will be happy to promote you all to Priests.")
        return
    end
    evt.SimpleMessage("The Map!\nYou found it!\n[Falk looks at the map, and points at the island] There it is.\nThe island has been shrouded in mist since the Churches of the Sun and Moon began fighting over a century ago.\nKeep the map--I have the coordinates now, and will have no trouble finding the place when I need to.\nI am proud to declare the Clerics amongst you to be Priests, and the rest to be honorary Priests.\nThank you so much for your good work!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 4) then
            SetValue(ClassId, 5)
            SetQBit(QBit(1607)) -- Promoted to Priest
            AddValue(Experience, 30000)
        else
            SetQBit(QBit(1608)) -- Promoted to Honorary Priest
            AddValue(Experience, 15000)
        end
    end
    ClearQBit(QBit(555)) -- Find the lost pirate map in the Tidewater Caverns in Tatalia and return to Daedalus Falk in the Deyja Moors.
    AddValue(Gold, 5000)
    SubtractValue(ReputationInCurrentLocation, 5)
    evt.ForPlayer(Players.All)
    RemoveItem(1485) -- Map to Evenmorn Island
    ClearQBit(QBit(730)) -- Map to Evenmorn - I lost it
    evt.SetNPCTopic(386, 0, 840) -- Daedalus Falk topic 0: Priest of Dark
    SetQBit(QBit(576)) -- Activate boat to area 9. Priest promo quest
end)

RegisterGlobalEvent(840, "Legacy event 840", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("How dare you insult me with your presence?\nYou have chosen the Path of the Light, and have forever renounced me as your teacher.\nGo now, and wallow in your weakness somewhere else.")
        return
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("Priests.\n[Falk gazes coldly at you] Well it is that you have come to see the wisdom of the Path of the Dark.\nNever regret your decision, and never look back.\nSouth of Bracada is an island called Evenmorn, and upon that island are the old temples of the Sun and the Moon.\nBoth are inhabited by the remnants of the two religions, their once proud churches reduced to two old temples fighting for a small island.The Church of the Moon was the founding religion for our current faith, the Path of Darkness.\nI propose we help them out and tip the balance in favor of the Church of the Moon.\nUsing the map that I sent you to find, convince a sea captain to bring you to the island.\nThere, bring aid and comfort to the Church of the Moon by defiling the altar in the Church of the Sun.\nThis will so weaken the Sun cult that the Church of the Moon will be able to overcome them in battle.\nReturn to me when you have done this.\n ")
        SetQBit(QBit(556)) -- Deface the Altar of Good in the Temple of the Sun on Evenmorn Isle then return to Daedalus Falk in the Deyja Moors.
        evt.SetNPCTopic(386, 0, 841) -- Daedalus Falk topic 0: Priest of Dark
    else
        evt.SimpleMessage("If you wish to follow the Path of Darkness, first you must formally choose it.\nSoon you will be asked to make the choice, and the way will be clear.\nUntil then, I cannot be your guide.")
        return
    end
end)

