RegisterGlobalEvent(842, "Legacy event 842", function()
    evt.SimpleMessage("I am indeed the one to speak to if you wish to become Wizards.\nEvery student of mine must complete a project before I name them Wizards.\nThis year's project is to build a golem.\nThere are spare parts scattered about the lands from here to Avlee.\nYou'll need all four limbs plus the torso and the head.\nPay special attention to where you get the head--one of my students made a mistake while making a head last summer and gave the defective head away as a joke.\nWhen you have all the parts, come talk to me.\nI'll promote you to Wizards then, and I'll animate your Golem.\nWell, on your way, and have fun!")
    SetQBit(QBit(557)) -- Collect the six golem pieces and construct a complete golem, then return to Thomas Grey in the School of Sorcery.
    SetQBit(QBit(1686)) -- Replacement for NPCs ą56 ver. 7
    evt.SetNPCTopic(387, 0, 843) -- Thomas Grey topic 0: Wizard
end)

