RegisterGlobalEvent(844, "Legacy event 844", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("Welcome back, students.\nThe golem lesson was just an exercise, but to advance to Archmage, you really have to do something for the profession.\nCopies of the fabled Divine Intervention spell are very rare, and unfortunately the School doesn't have one.\nThere's been a history of bad luck regarding the spell.It has been around for time immemorial, but the spell has never found its way into our hands.\nAlways just out of reach, we often send guild members to find it, but every one has failed.\nSometimes they have it in their hands, but lose it on the way back, other times, the book seems to vanish, only to resurface 20 years later in some old dungeon, or on a deserted island.\nRight now, we think it's in the Breeding Zone in the Pit.\nFind the spell, and return with it.\nBreak the curse!")
        SetQBit(QBit(559)) -- Find the Book of Divine Intervention in the Breeding Zone in the Pit and return it to Thomas Grey in the School of Sorcery.
        evt.SetNPCTopic(387, 0, 845) -- Thomas Grey topic 0: Archmage
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("You've chosen Darkness, my students.\nI will teach you no more.")
    else
        evt.SimpleMessage("Archmage training is reserved only for people dedicated to the Path of Light.\nProve to me you have chosen the right way, and I will be proud to be your teacher.")
    end
end)

RegisterGlobalEvent(845, "Legacy event 845", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1289) then -- Divine Intervention
        evt.SimpleMessage("I expect trouble finding the book, which is why I'm sending you to find it.\nI know you can succeed in this mission.\nKeep trying!")
        return
    end
    evt.SimpleMessage("The book!\nThe book!\n[Master Grey clutches his ears and spins around in joy] You did it!\nOh, what a wonderful day!\nI am so proud of you!\nYou're all Archmages!\nOf course, if you weren't Wizards to begin with, it's only an honorary title, but who cares?\nYou found the book!\n[The Master sets the book down on a table next to a blank book.\nBoth open simultaneously, and quill arises from the desk to begin copying the text in the new book] You may keep the copy, and you should start seeing more copies in the Light guilds of Bracada and Celeste.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 43) then
            SetValue(ClassId, 46)
            SetQBit(QBit(1621)) -- Promoted to Archmage
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1622)) -- Promoted to Honorary Archmage
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(559)) -- Find the Book of Divine Intervention in the Breeding Zone in the Pit and return it to Thomas Grey in the School of Sorcery.
    ClearQBit(QBit(738)) -- Book of Divine Intervention - I lost it
    AddValue(Gold, 10000)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(387, 0, 0) -- Thomas Grey topic 0 cleared
    evt.SetNPCGreeting(387, 192) -- Thomas Grey greeting 192
end)

RegisterGlobalEvent(846, "Legacy event 846", function()
    if IsQBitSet(QBit(1619)) then -- Promoted to Wizard
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("Fear not death?\nI can perform the Ritual on any Wizard.\nYou need a Soul Jar.\nYears ago the Wizards stole a shipment of Jars en route from Nighon to Deyja.\nThe jars are very hard to destroy, so they hid them, thinking we would never be able to find them.Fortunately for us, dead men do indeed tell tales.\nBetter, in fact, than living ones--dead men never forget, never refuse to talk, and never lie.\nSo, we found the one who buried the Jars, and made him die.\nHe was very cooperative after his death, and said he hid them somewhere in the Walls of Mist for the Wizards in Celeste. Retrieve these jars and I will perform the Ritual on all Wizards amongst you.\nThe rest may become Honorary Liches, for what that's worth, in thanks for finding the extra Jars for us.")
            SetQBit(QBit(560)) -- Retrieve the lich jars from the Proving Grounds in Celeste and bring them back to Halfgild Wynac in the Pit.
            evt.SetNPCTopic(388, 0, 847) -- Halfgild Wynac topic 0: Lich
        elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Having chosen the path of Light, you are not suited to become Liches.\nThe Ritual would reject you, and you would die a real death.\nIf that is what you want, you certainly don't need my help…")
        else
            evt.SimpleMessage("Only followers of the Dark Path can become Liches.")
        end
        return
    elseif IsQBitSet(QBit(1620)) then -- Promoted to Honorary Wizard
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("Fear not death?\nI can perform the Ritual on any Wizard.\nYou need a Soul Jar.\nYears ago the Wizards stole a shipment of Jars en route from Nighon to Deyja.\nThe jars are very hard to destroy, so they hid them, thinking we would never be able to find them.Fortunately for us, dead men do indeed tell tales.\nBetter, in fact, than living ones--dead men never forget, never refuse to talk, and never lie.\nSo, we found the one who buried the Jars, and made him die.\nHe was very cooperative after his death, and said he hid them somewhere in the Walls of Mist for the Wizards in Celeste. Retrieve these jars and I will perform the Ritual on all Wizards amongst you.\nThe rest may become Honorary Liches, for what that's worth, in thanks for finding the extra Jars for us.")
            SetQBit(QBit(560)) -- Retrieve the lich jars from the Proving Grounds in Celeste and bring them back to Halfgild Wynac in the Pit.
            evt.SetNPCTopic(388, 0, 847) -- Halfgild Wynac topic 0: Lich
        elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Having chosen the path of Light, you are not suited to become Liches.\nThe Ritual would reject you, and you would die a real death.\nIf that is what you want, you certainly don't need my help…")
        else
            evt.SimpleMessage("Only followers of the Dark Path can become Liches.")
        end
    else
        evt.SimpleMessage("If you haven't even become Wizards yet, you aren't ready to become Liches.\nTrouble me not 'til you're qualified.")
    end
end)

