RegisterGlobalEvent(848, "Legacy event 848", function()
    evt.SimpleMessage("Advancement as a Druid is simple.\nYou must visit the three ancient temples to nature we erected centuries ago and pray at their centers.\nThey are in Tatalia, Evenmorn Isle, and Avlee, and look like circles of stone with an altar of water in their centers.\nWhere exactly I will not say, but exploring the land about them is part of the process.\nWhen you have visited all three Circles, return to me to detail your experience.")
    SetQBit(QBit(561)) -- Visit the three stonehenge monoliths in Tatalia, the Evenmorn Islands, and Avlee, then return to Anthony Green in the Tularean Forest.
    evt.SetNPCTopic(389, 0, 849) -- Anthony Green topic 0: Great Druid
end)

RegisterGlobalEvent(849, "Legacy event 849", function()
    if IsQBitSet(QBit(562)) then -- Visited all stonehenges
        evt.SimpleMessage("I have only to look into your eyes to see where you've been.\nYou have seen the circles, and they have left their imprint upon you.\nTelling you that all Druids amongst you are now Great Druids is but a formality.\nTelling the rest of you that you're now honorary Druids is showing you respect for the respect you have shown me and my faith.\n")
        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
            evt.ForPlayer(player)
            if IsAtLeast(ClassId, 12) then
                SetValue(ClassId, 13)
                SetQBit(QBit(1613)) -- Promoted to Great Druid
                AddValue(Experience, 30000)
            else
                SetQBit(QBit(1614)) -- Promoted to Honorary Great Druid
                AddValue(Experience, 15000)
            end
        end
        ClearQBit(QBit(561)) -- Visit the three stonehenge monoliths in Tatalia, the Evenmorn Islands, and Avlee, then return to Anthony Green in the Tularean Forest.
        SubtractValue(ReputationInCurrentLocation, 5)
        evt.ForPlayer(Players.All)
        evt.SetNPCTopic(389, 0, 850) -- Anthony Green topic 0: Arch Druid
    elseif IsQBitSet(QBit(563)) then -- Visited stonehenge 1 (area 9)
        evt.SimpleMessage("You've found a circle!\nVery good, but you must find all three before you will be ready for promotion.\nRemember, circles three, then return to me.")
        return
    elseif IsQBitSet(QBit(564)) then -- Visited stonehenge 2 (area 13)
        evt.SimpleMessage("You've found a circle!\nVery good, but you must find all three before you will be ready for promotion.\nRemember, circles three, then return to me.")
        return
    elseif IsQBitSet(QBit(565)) then -- Visited stonehenge 3 (area 14)
        evt.SimpleMessage("You've found a circle!\nVery good, but you must find all three before you will be ready for promotion.\nRemember, circles three, then return to me.")
    else
        evt.SimpleMessage("Visit the Circles, then return to me.\nThat is the process.\n")
    end
end)

RegisterGlobalEvent(850, "Legacy event 850", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("To be named an Arch Druid, you must serve the land.\nI know of a service you could perform.\nIn the land above Stone City, where the Dwarves bury their dead, is the barrow of King Zokarr IV.\nHe died fighting in defense of Stone City during the invasion of Erathia by Nighon.\nHis remains were never recovered and still lie in those tunnels.\n\nRetrieve his bones and place them in his coffin in his barrow.\nWhen you have done this, the King will rest, and so will the land.\nReturn to me when you've performed this service, and I will perform the Ceremony of Ascension and name you Arch Druids.")
        SetQBit(QBit(566)) -- Retrieve the bones of the Dwarf King from the tunnels between Stone City and Nighon and place them in their proper resting place in the Barrow Downs, then return to Anthony Green in the Tularean Forest.
        evt.SetNPCTopic(389, 0, 851) -- Anthony Green topic 0: Arch Druid
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("Servants of Darkness, I am sorry I promoted you earlier.\nI am ashamed I didn't notice the darkness in your souls until it was too late.\nLeave me.")
    else
        evt.SimpleMessage("I am dedicated to the service of the Light.")
    end
end)

RegisterGlobalEvent(851, "Legacy event 851", function()
    if not IsQBitSet(QBit(577)) then -- Barrow downs. Returned the bones of the Dwarf King. Arch Druid promo quest.
        evt.SimpleMessage("The Service is not easy, but it needs to be done.\nRemember, you must bring the bones of King Zokarr IV from where they lie in the tunnels between Stone City and Nighon to Zokarr's coffin in a secret dwarven barrow.\nOnly then can I perform the Ceremony of Ascension and promote you.")
        return
    end
    evt.SimpleMessage("[Master Green seems beside himself with joy at your accomplishment] I felt the King's soul return to the land of the dead when you returned his bones.\nThe land breathed a sigh of relief--did you feel it?\nThe Ceremony of Ascension is complete.\nI'm happy to promote all Great Druids amongst you to Arch Druids, and all honorary Great Druids to Honorary Arch Druids.\nThis is a very happy day!\nYour service will be remembered!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 13) then
            SetValue(ClassId, 15)
            SetQBit(QBit(1615)) -- Promoted to Arch Druid
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1616)) -- Promoted to Honorary Arch Druid
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(566)) -- Retrieve the bones of the Dwarf King from the tunnels between Stone City and Nighon and place them in their proper resting place in the Barrow Downs, then return to Anthony Green in the Tularean Forest.
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    evt.SetNPCTopic(389, 0, 0) -- Anthony Green topic 0 cleared
    evt.SetNPCGreeting(389, 196) -- Anthony Green greeting 196
end)

RegisterGlobalEvent(852, "Legacy event 852", function()
    if IsQBitSet(QBit(1613)) then -- Promoted to Great Druid
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("Becoming a Warlock for some is a simple process, and for others it is nearly impossible.\nYou need to find a familiar suited to your personality.\nThe familiar will help to focus your magical abilities and sharpen your concentration.\nSometimes a single familiar can be shared, other times not.\nThe magical effects will not be noticed by anyone but a Great Druid--someone who is already attuned to nature.\nNow, let me see what kind of familiar you will need...[Tor picks up an elaborately carved gem and peers at you through it.\nHe frowns.]\nHmm.\nWell, the good news is that you all need the same familiar, and when you find it, you will be very powerful.\nThe bad news is that you need to find a dragon familiar.\nYou must find a dragon egg.\nBring them back here and I will hatch it, and cast the familiar spell.\nThe baby dragon will imprint to you all, and you to it.\nYou may be able to find an egg in a dragon cave in the Land of the Giants.\n'Ware the mother, though.")
            SetQBit(QBit(567)) -- Retrieve the dragon egg from the Dragon Cave in the Land of the Giants and return it to Tor Anwyn in Mount Nighon.
            evt.SetNPCTopic(390, 0, 853) -- Tor Anwyn topic 0: Warlock
        elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Hmmmm.\n[Tor looks at you carefully]\nNope.\nCan't teach you.\nYou chose the Path of Light.\nI can smell it on you.\nI can sympathize with your choice, but I know that none of our spells or rituals can promote you once you have started down that path.\nSorry.")
        else
            evt.SimpleMessage("Though I like to think of the Warlocks as being followers of the Path of Twilight, or Dawn, we are technically followers of the Path of Darkness.\nYou must be dedicated followers of Darkness before I can help you.\n")
        end
        return
    elseif IsQBitSet(QBit(1614)) then -- Promoted to Honorary Great Druid
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            evt.SimpleMessage("Becoming a Warlock for some is a simple process, and for others it is nearly impossible.\nYou need to find a familiar suited to your personality.\nThe familiar will help to focus your magical abilities and sharpen your concentration.\nSometimes a single familiar can be shared, other times not.\nThe magical effects will not be noticed by anyone but a Great Druid--someone who is already attuned to nature.\nNow, let me see what kind of familiar you will need...[Tor picks up an elaborately carved gem and peers at you through it.\nHe frowns.]\nHmm.\nWell, the good news is that you all need the same familiar, and when you find it, you will be very powerful.\nThe bad news is that you need to find a dragon familiar.\nYou must find a dragon egg.\nBring them back here and I will hatch it, and cast the familiar spell.\nThe baby dragon will imprint to you all, and you to it.\nYou may be able to find an egg in a dragon cave in the Land of the Giants.\n'Ware the mother, though.")
            SetQBit(QBit(567)) -- Retrieve the dragon egg from the Dragon Cave in the Land of the Giants and return it to Tor Anwyn in Mount Nighon.
            evt.SetNPCTopic(390, 0, 853) -- Tor Anwyn topic 0: Warlock
        elseif IsQBitSet(QBit(611)) then -- Chose the path of Light
            evt.SimpleMessage("Hmmmm.\n[Tor looks at you carefully]\nNope.\nCan't teach you.\nYou chose the Path of Light.\nI can smell it on you.\nI can sympathize with your choice, but I know that none of our spells or rituals can promote you once you have started down that path.\nSorry.")
        else
            evt.SimpleMessage("Though I like to think of the Warlocks as being followers of the Path of Twilight, or Dawn, we are technically followers of the Path of Darkness.\nYou must be dedicated followers of Darkness before I can help you.\n")
        end
    else
        evt.SimpleMessage("I would love to get you started on the way to becoming Warlocks, but nothing I can do for you will be of any use until you become Great Druids.\nReturn when you have achieved that level of understanding.")
    end
end)

RegisterGlobalEvent(853, "Legacy event 853", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1449) then -- Dragon Egg
        evt.SimpleMessage("You need to bring me a dragon's egg so you I can hatch your familiar.")
        return
    end
    evt.SimpleMessage("[Tor looks at you in astonishment] You really found a dragon egg!\nIt's been more than a century since any Warlock has both needed and found a dragon familiar!\nThis will go down in the history books, that's for sure!\nMy spell book!\nI need my book!\nAh, here it is.\n[Tor chants a spell from the book, then taps the egg three times.\nThe egg hatches, and a baby dragon crawls out of the shell]\nThere you are!\nAwww, isn't he cute?\nCongratulations!\nNo longer are you simple Great Druids, but Warlocks!\nOf course, that's just an honorary title if you weren't a natural Great Druid to begin with, but nonetheless, something to be proud of.\n")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 13) then
            SetValue(ClassId, 14)
            SetQBit(QBit(1617)) -- Promoted to Warlock
            AddValue(Experience, 80000)
        else
            SetQBit(QBit(1618)) -- Promoted to Honorary Warlock
            AddValue(Experience, 40000)
        end
    end
    ClearQBit(QBit(567)) -- Retrieve the dragon egg from the Dragon Cave in the Land of the Giants and return it to Tor Anwyn in Mount Nighon.
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    RemoveItem(1449) -- Dragon Egg
    ClearQBit(QBit(739)) -- Dragon Egg - I lost it
    evt.SetNPCTopic(390, 0, 0) -- Tor Anwyn topic 0 cleared
    evt.SetNPCGreeting(389, 198) -- Anthony Green greeting 198
    SetQBit(QBit(1687)) -- Replacement for NPCs ą57 ver. 7
end)

