RegisterGlobalEvent(856, "Legacy event 856", function()
    if not IsQBitSet(QBit(647)) then -- Player castle goblins are all dead
        evt.SimpleMessage("I fear that talking will fail with these goblins, my lords.\nMay I suggest violence?")
        return
    end
    evt.SimpleMessage("Thank heavens you've cleaned them out!\nNow we need to find a way to clean up the castle and rebuild the damaged sections.\nThe only people I can think of who would have the inclination and the ability to do this are the Dwarves in Stone City, located in the Barrow Downs to the south.\nThe entrance to Stone City lies in the center of the Barrow Downs on one of the largest hills.\n")
    evt.ForPlayer(Players.All)
