RegisterGlobalEvent(866, "Legacy event 866", function()
    if not IsQBitSet(QBit(600)) then -- Talked to Catherine
        evt.SimpleMessage("Your Queen wishes to speak with you as soon as possible.\nSince the War, she has taken up residence at Gryphonheart Castle in Steadwick.\nThis is strictly business--whenever new lords assume their office she meets with them to make sure there are no misunderstandings.\nQueen Catherine is particularly interested in you, and has told me she wishes to employ your services.")
        return
    end
    if not IsQBitSet(QBit(593)) then -- Gave Loren to Catherine
        evt.SimpleMessage("I've received word that you met with the Queen.")
