RegisterGlobalEvent(874, "Legacy event 874", function()
    evt.SimpleMessage("[Queen Catherine inclines her head regally] You are the lot that won Lord Markham's silly contest, I see.\nI must admit I had little faith until the Dwarf King recognized you as the rightful rulers of Harmondale.\nYou must have done something to win his respect, or he would have nothing to do with you.\nI'm still not sure what he saw in you, but perhaps there really is something of substance here.\nWe shall see.Maybe you can do something for me that would make me think I should let you keep your new titles.\nRecently, a valuable...agent of mine was arrested in the Tularean Forest for merely doing his job.\nThey're keeping him in a cave somewhere outside of Pierpont.\nHis name is Loren Steel, and they are threatening to execute him if certain unacceptable conditions are not met in 28 days.\nReturn with him before then and you will win respect, gold, and gratitude.")
    evt.SetNPCTopic(408, 0, 875) -- Queen Catherine topic 0: Prisoner of War
    SetQBit(QBit(590)) -- Rescue Loren Steel from the Tularean Caves in the Tularean Forest and return him to Queen Catherine.
    SetQBit(QBit(600)) -- Talked to Catherine
    SetValue(Counter(1), 0)
end)

