    evt.SimpleMessage("Bring the Oscillation Overthruster back to Resurectra immediately!")
end)

RegisterGlobalEvent(895, "Legacy event 895", function()
    evt.SimpleMessage("The Test involves entering the 'front door' of the Walls of Mist, and exiting through the 'back door'.\nI use the word 'door' loosely--you'll see when you get there.\nYou will not need your weapons.\nYou will fail the test if you kill any creature in the Walls of Mist.\nIf you can complete this task, you will be given membership in the Guild of Light. Good luck.")
    SetQBit(QBit(613)) -- Complete the Walls of Mist without killing a single opponent and return to Gavin Magnus in Castle Lambent in Celeste.
    ClearQBit(QBit(664)) -- Enter Celeste from the grand teleporter in the Bracada Desert, then talk to Gavin Magnus in Castle Lambent in Celeste.
    evt.SetNPCTopic(418, 0, 896) -- Gavin Magnus topic 0: Proving Grounds
end)

RegisterGlobalEvent(896, "Legacy event 896", function()
    if not IsQBitSet(QBit(614)) then -- Completed Proving Grounds without killing a single creature
        evt.SimpleMessage("Remember, you must enter through the front door of the Walls of Mist, and exit through the back door.\nYou must not kill any creatures in the Walls of Mist.\nWhen you have done this, return to me.")
        return
    end
    evt.SimpleMessage("You passed the Test!\nThat's quite an achievement--few succeed as quickly as you did.\nMy advisors are now eager to speak to\nyou; they can be found in the four houses on the eastern side of Celeste.\nOnce again, congratulations!")
    ClearQBit(QBit(613)) -- Complete the Walls of Mist without killing a single opponent and return to Gavin Magnus in Castle Lambent in Celeste.
    evt.SetNPCTopic(418, 0, 0) -- Gavin Magnus topic 0 cleared
    AddValue(History(12), 0)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 50000)
    SetQBit(QBit(626)) -- Finished Wizard Proving Grounds
    SetAward(Award(6)) -- Completed Wizard Proving Grounds
    evt.SetNPCGreeting(418, 223) -- Gavin Magnus greeting: Welcome back, my friends. My advisors are anxious to speak with you.
    evt.MoveNPC(419, 1062) -- Resurectra -> Hostel
    evt.MoveNPC(420, 1063) -- Crag Hack -> Hostel
    evt.MoveNPC(421, 1064) -- Sir Caneghem -> Hostel
    evt.MoveNPC(422, 1065) -- Robert the Wise -> Hostel
    evt.SetNPCGreeting(419, 226) -- Resurectra greeting: I am glad you passed the King's test. It shows you are dedicated to the Path of Light. Now we should get down to business. My fellow advisors and I have some work for you if you're willing. You will, of course, be rewarded. And always remember, that whatever we ask of you, we are always moving toward a noble goal, one you will be proud to have been a part of.
    evt.SetNPCGreeting(420, 229) -- Crag Hack greeting: Now that you have completed the Test, I too, have a request of you. Unlike my friends, mine has little to do with advancing toward the Goal, but it is important nonetheless.
    evt.SetNPCGreeting(421, 232) -- Sir Caneghem greeting: I'm pleased to hear you passed the test. We must attack our enemies before they get too strong. I have a plan I think will do lasting damage to their noxious brotherhood. It's dangerous but bold, and cowards such as they will never expect it.
    evt.SetNPCGreeting(422, 235) -- Robert the Wise greeting: Like my friends, I have a task for you as well, but now is not the time. Finish their work first, then I will tell you about my mission.
    SetQBit(QBit(1605)) -- Joined the Light Guild
end)

RegisterGlobalEvent(897, "Legacy event 897", function()
    evt.SimpleMessage("We need your help retrieving half of a key to a very important place from our enemies, the Necromancers.\nLike us, they have enshrined their half of the key in their highest temple--The Temple of the Dark.\nI'm under no illusions this will be easy.\nTake your time and act when you're prepared.\nAlso, bring our half of the key to us, as well.\nIt is enshrined in the Temple of the Light.\nSince you're our ally, no one should trouble you when you go there to fetch the key.\nBy the same token, please don't harm any of them, either.")
    SetQBit(QBit(615)) -- Retrieve the altar piece from the Temple of Light in Celeste and the Temple of Dark in the Pit and return them to Resurectra in Castle Lambent in Celeste.
    evt.SetNPCTopic(419, 0, 898) -- Resurectra topic 0: Temple of the Dark
end)
RegisterCanShowTopic(897, function()
    evt._BeginCanShowTopic(897)
    local visible = true
    if IsQBitSet(QBit(626)) then -- Finished Wizard Proving Grounds
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(898, "Legacy event 898", function()
    evt.ForPlayer(Players.All)
    if HasItem(1478) then -- Altar Piece
        if not HasItem(1479) then -- Altar Piece
            evt.SimpleMessage("Well, I'm glad you found our half of the key, but you still need their half.\nHold onto it until you get the other half.\nWhen you have both halves, return to me.\nI will make them whole.")
            return
        end
        evt.SimpleMessage("I knew you could do it!\nNever doubted you for a second!\n[You hand her the key halves, and she joins them by running a finger along the crack between them.\nIt mends before your eyes, good as new] Finally!\nOne piece of the plan is in place.\nYour assistance has been invaluable.\nWe are already in your debt, and I expect we'll be even deeper in debt before our plan comes to fruition.\nSo have faith in us awhile longer--the future we're planning will astound you!")
        RemoveItem(1478) -- Altar Piece
        RemoveItem(1479) -- Altar Piece
        ClearQBit(QBit(744)) -- Altar Piece (Good) - I lost it
        ClearQBit(QBit(745)) -- Altar Piece (Evil) - I lost it
        AddValue(History(14), 0)
        AddValue(Experience, 50000)
        evt.SetNPCTopic(419, 0, 0) -- Resurectra topic 0 cleared
        ClearQBit(QBit(615)) -- Retrieve the altar piece from the Temple of Light in Celeste and the Temple of Dark in the Pit and return them to Resurectra in Castle Lambent in Celeste.
        SetQBit(QBit(627)) -- Finished Wizard Task 2 - Temple of Dark
        SetAward(Award(19)) -- Retrieved Both Temple Pieces
        evt.SetNPCGreeting(419, 227) -- Resurectra greeting: Once again, thanks for completing the key for us. We are in your debt for that act alone. I'm sure we will be even more in your debt in the near future.
        evt.ForPlayer(Players.Current)
        SubtractValue(ReputationInCurrentLocation, 5)
    elseif HasItem(1479) then -- Altar Piece
        evt.SimpleMessage("Good work on retrieving their half of the key, but you still need ours.\nIt is located in the Temple of the Light here in Celeste.")
    else
        evt.SimpleMessage("No key halves yet, I see.\nWell, take your time.\nIt must be done eventually, and sooner is better than later, but later is better than being chained to an altar and sacrificed by the High Priest of the Dark in one of their bloody rituals.\nJust bring back both halves of the key from the temples of Dark and Light, and try not to get yourselves killed doing it.")
    end
end)

RegisterGlobalEvent(899, "Legacy event 899", function()
    evt.SimpleMessage("Our plans rapidly approach their conclusion, but there is a hitch.\nThe Kreegan--also known as the Devils, or the Demons, must be destroyed before we finish our plans.\nThey represent a terrible threat, and though they do little but lick their wounds today, will one day regain their strength and devastate the world.\nIf anything we do is to have lasting effect, we must first destroy these monsters for once and for all.You are strong, but not strong enough to defeat the devils on your own.\nThey are vulnerable to the brand of magic most commonly wielded by the Necromancers, and less so by our own Wizards.\nIt is imperative that you infiltrate the Devil's base and kill their leader Xenofex.\nThat should end their threat to this world for some time.\nThe Warlocks have dug a tunnel from their volcano to the Land of the Giants-- the land the Devils claim as their own.\nPerhaps you can use that.")
    SetQBit(QBit(616)) -- Go to Colony Zod in the Land of the Giants and slay Xenofex then return to Resurectra in Castle Lambent in Celeste.
    evt.SetNPCTopic(419, 1, 900) -- Resurectra topic 1: Strike the Devils
end)
RegisterCanShowTopic(899, function()
    evt._BeginCanShowTopic(899)
    local visible = true
    if IsQBitSet(QBit(631)) then -- Killed Evil MM3 Person
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(900, "Legacy event 900", function()
    if not IsQBitSet(QBit(617)) then -- Slayed Xenofex
        evt.SimpleMessage("I guess there's no hurry getting this job done, but we don't want the Necromancers to grow bored waiting for us to do our part and destroy the blocker.\nSo, please, as soon as you feel ready you must attack the Devils.\nRemember that the Warlocks have dug a tunnel from their volcano to the land of the Devils.\nYou should be able to use that to get yourselves there.")
        return
    end
    evt.ShowMovie("\"mm3 people good\"", true)
    evt.SimpleMessage("YOU ARE HEROES!!!\nYour work against the devils was masterful!\nAnd the rescue of King Roland was as delightful as it was unexpected.\nHistory will never forget your names for doing what you just did!\nI, for one, am very proud to know you.\n")
    AddValue(Gold, 50000)
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 500000)
    ClearQBit(QBit(616)) -- Go to Colony Zod in the Land of the Giants and slay Xenofex then return to Resurectra in Castle Lambent in Celeste.
    SetQBit(QBit(632)) -- Got Hive part
    evt.SetNPCTopic(419, 1, 919) -- Resurectra topic 1: Final Task
    SetAward(Award(21)) -- Slayed Xenofex
end)

