RegisterGlobalEvent(905, "Legacy event 905", function()
    evt.SimpleMessage("Our counterparts, the former advisors to Archibald, each carry a token called a command cube on their person that we absolutely must acquire to complete the Goal.\nThere is no way any of them will part with their cube willingly, which means that we must get it some other way.\nYou will have to take it from one of them, and we think the easiest would be Tolberti.\nUnlike the rest of them, he disdains proper security and has taken up residence in one of the apartments in the Pit.\nI need you to infiltrate the pit again and get the cube from him.\nBe careful--he is well armed and much tougher than he appears.\nWhen you have the Cube, return to me.\nWe have but a short distance to the Goal, and all will be revealed very soon.")
    SetQBit(QBit(621)) -- Assassinate Tolberti in his house in the Pit and return his control cube to Robert the Wise in Celeste.
    evt.SetNPCTopic(422, 0, 906) -- Robert the Wise topic 0: Tolberti
end)
