    if HasItem(1478) then -- Altar Piece
        if not HasItem(1479) then -- Altar Piece
            evt.SimpleMessage("Well, I'm glad you found our half of the key, but you still need their half.\nHold onto it until you get the other half.\nWhen you have both halves, get back over here and I'll fix them.")
            return
        end
        evt.SimpleMessage("Excellent!\n[Kastore takes the two halves of the key and bangs them together.\nWith a bright white flash, they join together seamlessly]\nThe first part of the Plan is complete.\nI knew we, uh, Archibald made the right decision in trusting you!\n")
        RemoveItem(1478) -- Altar Piece
        RemoveItem(1479) -- Altar Piece
        ClearQBit(QBit(744)) -- Altar Piece (Good) - I lost it
        ClearQBit(QBit(745)) -- Altar Piece (Evil) - I lost it
        AddValue(History(22), 0)
        AddValue(Experience, 50000)
        evt.SetNPCTopic(423, 0, 0) -- Kastore topic 0 cleared
        ClearQBit(QBit(634)) -- Retrieve the altar piece from the Temple of Light in Celeste and the Temple of Dark in the Pit and return them to Kastore in the Pit.
        SetQBit(QBit(623)) -- Finished Necro Task 2 - Temple of Light
        SetAward(Award(19)) -- Retrieved Both Temple Pieces
        evt.SetNPCGreeting(423, 227) -- Kastore greeting: Once again, thanks for completing the key for us. We are in your debt for that act alone. I'm sure we will be even more in your debt in the near future.
    elseif HasItem(1479) then -- Altar Piece
        evt.SimpleMessage("Finally!\nI was beginning to wonder if you might have got yourselves killed already.\nWell, no matter.\nYou forgot to get the key from the Temple of the Dark, so be on your way.\nWhen you have it, return to me so I can make the two halves whole again.")
    else
        evt.SimpleMessage("No key halves yet?\nBah!\nI hope you're more competent than you seem right now!\nHow hard can this be?\nAll you have to do is burst in the front door and start shooting.\nWhen there's no one left, you can clean their place out at your leisure.\nJust hurry up and bring us both key halves.")
    end
end)

