        return
    end
    evt.ShowMovie("\"mm3 people evil\"", true)
    evt.SimpleMessage("THAT WAS AWESOME!\nYou did it!\nAnd now the single greatest threat to our plans is gone!\nWe will be Kings of the World!\n[Kastore throws his head back and laughs wildly] AHAHAHAHAHA!!!!! Ah ha ha. Yes.\nWell, good job.\nI'll even forgive you for letting that King Roland character go free--we could have used him as a bargaining chip, you know.\n[he shrugs] you probably didn't have a choice, I suppose.\nIn any event, this is a happy day!\n")
    AddValue(Gold, 50000)
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 500000)
    ClearQBit(QBit(635)) -- Go to Colony Zod in the Land of the Giants and slay Xenofex then return to Kastore in the Pit.
    SetQBit(QBit(632)) -- Got Hive part
    evt.SetNPCTopic(423, 1, 921) -- Kastore topic 1: Final Task
    SetAward(Award(21)) -- Slayed Xenofex
end)

RegisterGlobalEvent(911, "Legacy event 911", function()
    evt.SimpleMessage("Archibald has asked us to find a source of soul jars for his necromancers.\nThese are the jars that are needed to complete the Ritual that gives them eternal life, and we're almost out.\nThere are far more candidates for Lichdom than we have jars, so some of our necromancers are facing the grim possibility of real death.\nThe makers of the jars are the Warlocks.\nGo to them and convince them to give us the jars.\nIf they won't hand them over, take the jars by force-- I'm done negotiating prices with them.")
    SetQBit(QBit(636)) -- Retrieve the Case of Soul Jars from the Warlocks in Thunderfist Mountain and bring them to Maximus in the Pit.
    evt.SetNPCTopic(424, 0, 912) -- Maximus topic 0: Soul Jars
end)
RegisterCanShowTopic(911, function()
    evt._BeginCanShowTopic(911)
    local visible = true
    if IsQBitSet(QBit(622)) then -- Finished Necro Proving Grounds
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(912, "Legacy event 912", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1404) then -- Case of Soul Jars
        evt.SimpleMessage("You don't have to be nice about getting the jars from them--just get the jars any way you can.\nWe can renegotiate peace with them if we must, just like we renegotiate the price for each purchase of soul jars.")
        return
    end
    evt.SimpleMessage("[Maximus takes the case of jars with obvious delight] Nice work.")
    RemoveItem(1404) -- Case of Soul Jars
    ClearQBit(QBit(743)) -- Lich Jar Case - I lost it
    AddValue(History(20), 0)
    AddValue(Experience, 50000)
    ClearQBit(QBit(636)) -- Retrieve the Case of Soul Jars from the Warlocks in Thunderfist Mountain and bring them to Maximus in the Pit.
    SetQBit(QBit(624)) -- Finished Necro Task 3 - Soul Jars
    SetAward(Award(24)) -- Retrieved Soul Jars
    evt.SetNPCTopic(424, 0, 0) -- Maximus topic 0 cleared
    evt.SetNPCGreeting(424, 242) -- Maximus greeting: I really can't thank you enough for bringing those jars back to us. The Necromancers have been clamoring for their delivery for months! This will improve morale around here 100%! Once again, thanks!
    evt.ForPlayer(Players.Current)
    SubtractValue(ReputationInCurrentLocation, 5)
end)

RegisterGlobalEvent(913, "Legacy event 913", function()
    evt.SimpleMessage("Lord Archibald has another request--the creatures that have inhabited Clanker's laboratory must be evicted--and the teleport shield brought down.\nThe laboratory is on an island east of Pierpont in the Tularean Forest.\nBe careful--the monsters in that lab were created by Clanker himself, and some of them are much more powerful than their more common fellows elsewhere in the world.\nTake whatever you like from the place.\nLord Archibald is only interested in the real estate and the laboratory equipment.\nOnce the shield is down, Lord Archibald will be able to begin moving necromancers and equipment inside via Lloyd's Beacon. ")
    SetQBit(QBit(637)) -- Destroy the magical defenses inside Clanker's Laboratory and return to Dark Shade in the Pit.
    evt.SetNPCTopic(425, 0, 914) -- Dark Shade topic 0: Clanker's Laboratory
end)
RegisterCanShowTopic(913, function()
    evt._BeginCanShowTopic(913)
    local visible = true
    if IsQBitSet(QBit(622)) then -- Finished Necro Proving Grounds
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(914, "Legacy event 914", function()
    if not IsQBitSet(QBit(638)) then -- Destroyed the magical defenses in Clanker's Lab
        evt.SimpleMessage("This is a simple task--get a move on!\nOnce again, the laboratory on an island east of Pierpont in the Tularean Forest.\nGet the shield lowered, and your part of the job is done.")
        return
    end
    evt.SimpleMessage("It's good to see we can count on you.")
    AddValue(History(23), 0)
    SubtractValue(ReputationInCurrentLocation, 5)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 50000)
    ClearQBit(QBit(637)) -- Destroy the magical defenses inside Clanker's Laboratory and return to Dark Shade in the Pit.
    SetQBit(QBit(625)) -- Finished Necro Task 4 - Clanker's Lab
    evt.SetNPCTopic(425, 0, 0) -- Dark Shade topic 0 cleared
    evt.SetNPCGreeting(425, 245) -- Dark Shade greeting: Excellent work at Clanker's Laboratory! I know I already congratulated you on a job well done, but I just can't get over how well executed that entire plan was! The boys in the lab tell me they've already got most of old Clanker's body back together again, and they've animated the reassembled corpse. They've got him on Soul Jar research, but he's not quite as clever as he used to be, I'm told. Oh well, at least we don't need to fear him turning on us, eh?
    SetAward(Award(26)) -- Cleaned out Clanker's Laboratory
end)

RegisterGlobalEvent(915, "Legacy event 915", function()
    evt.SimpleMessage("Just as Archibald has us, King Magnus of Bracada has his advisors.\nAnd, just like us, each of them wears a small token called a command cube.\nWe need one of their cubes, and they're not going to just hand one over to us.\nWe must take one of their cubes, and we have decided it should be Robert the Wise who suffers.\nOne of our spies in their castle has damaged the lock to his room.\nThey have been lax about replacing it, so you should have no trouble going through the door.\nI don't care if you kill him or not--just get the cube and return to me at once.")
    SetQBit(QBit(639)) -- Assassinate Robert the Wise in his house in Celeste and return to Tolberti in the Pit.
    evt.SetNPCTopic(426, 0, 916) -- Tolberti topic 0: Robert the Wise
end)
RegisterCanShowTopic(915, function()
    evt._BeginCanShowTopic(915)
    local visible = true
    if IsQBitSet(QBit(622)) then -- Finished Necro Proving Grounds
        if IsQBitSet(QBit(623)) then -- Finished Necro Task 2 - Temple of Light
            if IsQBitSet(QBit(624)) then -- Finished Necro Task 3 - Soul Jars
                if IsQBitSet(QBit(625)) then -- Finished Necro Task 4 - Clanker's Lab
                    visible = true
                    return visible
                else
                    visible = false
                    return visible
                end
            else
                visible = false
                return visible
            end
        else
            visible = false
            return visible
        end
    else
        visible = false
        return visible
    end
end)

