    evt.ForPlayer(Players.All)
    if not HasItem(1477) then -- Control Cube
        evt.SimpleMessage("What's wrong?\nDon't tell me you're losing your nerve?\nHe's tough, but not immortal.\nYou can take him!\nI wouldn't have sent you on this mission if I didn't think you could handle it.")
        return
    end
    evt.SimpleMessage("[Tolberti takes the cube] This brings us very close to completing our Plan.\nI know Kastore hasn't told you exactly what the Plan is, but you'll like it, I'm sure!\nI am not allowed to say much, but I can tell you your position will be much higher than simply Lords of Harmondale, you can count on that!\nYou will find Kastore in his place on the throne of Castle Gloaming.")
    RemoveItem(1477) -- Control Cube
    AddValue(History(25), 0)
    AddValue(Experience, 250000)
