end)

RegisterGlobalEvent(917, "Legacy event 917", function()
    evt.SimpleMessage("Yes, the test.\nIt's simple.\nNear the center of the city is a place we call the Breeding Zone.\nThere's a lot of foul monsters in the pit, and they regenerate constantly.\nIt makes for a good source of slaves, spare parts, and target practice.\nAll of our necromancers are tested there when they want to rise above the level of initiate.\nI'm sure you'll pass the test.\nJust jump in the pit and find a way out.\nKill anything you want down there.\nShow no mercy.\nWhen you escape, crawl out of the pit and come see me again.\nIf you complete this, I will give you membership in the Guild of Dark. *If* you complete this...")
    SetQBit(QBit(640)) -- Complete the Breeding Zone and return to Archibald in the Pit.
    ClearQBit(QBit(663)) -- Enter the Pit from the Hall of the Pit in the Deyja Moors, then talk to Archibald in Castle Gloaming in the Pit.
    evt.SetNPCTopic(427, 0, 918) -- Archibald Ironfist topic 0: Breeding Pit
end)
RegisterCanShowTopic(917, function()
    evt._BeginCanShowTopic(917)
    local visible = true
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        visible = false
        return visible
    else
        visible = true
        return visible
    end
end)

RegisterGlobalEvent(918, "Legacy event 918", function()
    if not IsQBitSet(QBit(641)) then -- Completed Breeding Pit.
        evt.SimpleMessage("I am beginning to suspect my allies were right about you.\nCan't you pass this simple test?\nAre you too afraid, or too feeble to succeed?\nPerhaps we need new allies?")
        return
    end
    evt.SimpleMessage("You show promise, my friends.\nA fine performance.\nI think it will be sufficient proof of your skill for my advisors.\nThey are quite eager to assign tasks to you now; they can be found in the four houses in the western side of the Pit.\nAnd don't worry.\nRewards will follow, of course.")
    AddValue(History(19), 0)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 50000)
    SetAward(Award(28)) -- Completed Necromancer Breeding Pit
    ClearQBit(QBit(640)) -- Complete the Breeding Zone and return to Archibald in the Pit.
    SetQBit(QBit(622)) -- Finished Necro Proving Grounds
    evt.SetNPCTopic(427, 0, 0) -- Archibald Ironfist topic 0 cleared
    evt.SetNPCGreeting(427, 252) -- Archibald Ironfist greeting: Welcome back, allies. My advisors are eager to speak with you.
    evt.MoveNPC(423, 1079) -- Kastore -> Hostel
    evt.MoveNPC(424, 1071) -- Maximus -> Hostel
    evt.MoveNPC(425, 1078) -- Dark Shade -> Hostel
    evt.MoveNPC(426, 1070) -- Tolberti -> Hostel
    evt.SetNPCGreeting(423, 238) -- Kastore greeting: So you passed the test! Good! Now we can get down to business. You'll find that working for us…[Kastore shakes his head, and starts over] No. You'll find that working with us will advance our mutual goals and interests very quickly. We have big plans--plans big enough to include aggressive people like yourselves. As time passes, we will reveal our biggest plans to you.
    evt.SetNPCGreeting(424, 241) -- Maximus greeting: Hello! I am Maximus. Good to have you on our side. I'm glad you survived the Test. I'm against wasting good talent on that test, but my associates insist. [sigh] What can you do?
    evt.SetNPCGreeting(425, 244) -- Dark Shade greeting: I knew you would pass that Test! It really isn't that hard, if you are properly determined. You just have to harden your heart and do what must be done. The mission I have in mind for you will require that same resolve. After you passed that test, I'm sure you're up to it!
    evt.SetNPCGreeting(426, 247) -- Tolberti greeting: I, too, have a task for you in mind, but it will have to wait until you are done with my associates' missions. Return to me once you have finished their tasks.
    SetQBit(QBit(1606)) -- Joined the Dark Guild
end)

RegisterGlobalEvent(919, "Legacy event 919", function()
    evt.SimpleMessage("The time has come to achieve our Goal.\nThe reason we have sent you on all these missions is simple:\nwe have been busy gathering the parts needed to open a gate to the Ancients--the ones who colonized this world ages ago.\nUnfortunately, our former compatriots also seek those parts for their own dark dreams.\nThey wish to rebuild the Heavenly Forge from the times before the Silence, and use it to duplicate the weapons we brought with us to your world.\nWe have been competing with them for these parts, but at last we have what we need.\nExcept for one thing.\nWe have been unable to find the Oscillation Overthruster on your world.\nAll would be lost, but there is one such device aboard the Lincoln--the vehicle that brought us to your world.\nIt is in the sea west of Avlee and secured against entry, even from ourselves.\nNow you must wear our environment suits, enter the ship, and return with the Overthruster; you will find these suits in the chest outside this throne room.\nFor the suit to function properly you must not be wearing any equipment.\nAs for us, we must stand watch at the gate, and battle our former comrades.\n")
    SetQBit(QBit(642)) -- Go to the Lincoln in the sea west of Avlee and retrieve the Oscillation Overthruster and return it to Resurectra in Celeste.
    evt.SetNPCTopic(419, 1, 920) -- Resurectra topic 1: Final Task
end)

