RegisterGlobalEvent(921, "Legacy event 921", function()
    evt.SimpleMessage("Our finest hour is upon us.\nWhile you have been taking care of all those important tasks, my compatriots and I have been struggling with our former friends for the parts we need to rebuild the Heavenly Forge of legend.\nBy former friends, I mean the four chief advisors to King Magnus of the Wizards.\nThey have a plan to build a gate to the Ancients.\nThey could have stood with us, but threw it all away on some vague hope of a 'better future'.\nBut you!\nYou have stood with us all this time.Only one task remains--we need the Oscillation Overthruster from our old vehicle, the Lincoln.\nWe have been unable to find one on your world.\nThe ship is in the sea west of Avlee and secured against entry, even from ourselves.\nNow you must wear our environment suits, enter the ship, and return with the Overthruster.\nOur old environments suits have been prepared for you in the chest outside this throne room.\nFor the suit to function properly you must not be wearing any equipment.We will stand watch over the Forge, and defend it against our enemies.\nBring us the Overthruster, my friends, and together, we shall rule the world!")
    AddValue(History(29), 0)
    SetQBit(QBit(643)) -- Go to the Lincoln in the sea west of Avlee and retrieve the Oscillation Overthruster and return it to Kastore in the Pit.
    evt.SetNPCTopic(423, 1, 922) -- Kastore topic 1: Final Task
end)

