RegisterGlobalEvent(928, "Legacy event 928", function()
    evt.SimpleMessage("You want to bury the bones of Zokarr IV in our old barrows?\nNo dwarf here will brave the dangers, but Zokarr deserves to be laid to rest in the right place.\nLook for the secret barrow, the one with only one entrance.\nIn there is a coffin waiting for Zokarr's bones.")
