RegisterGlobalEvent(929, "Legacy event 929", function()
    evt.SimpleMessage("We have no one to turn to but you, the new Lords of Harmondale. The Lantern of Light is a treasured holy relic, used by the temples of Erathia.\nIts value is more symbolic than of power-- without it the temples servants lose faith.\nThis Lantern disappeared while being brought to this temple from the temple in Stone City.\nWe believe it was lost somewhere in the maze-like Barrows.\nPlease find it and return it to us.")
    evt.SetNPCTopic(432, 0, 930) -- Tarin Withern topic 0: Quest
    SetQBit(QBit(667)) -- Retrieve the Lantern of Light from the Barrow Downs and return it to Tarin Withern in Harmondale. - Barrow Lantern Quest
end)

RegisterGlobalEvent(930, "Legacy event 930", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1450) then -- Lantern of Light
        evt.SimpleMessage("Have you found the Lantern of Light?")
        return
    end
    evt.SimpleMessage("Thank you, Lords of Harmondale.\nThe Lantern's return will bolster our faith and allows us to continue our services.\nPlease take this small reward as a token of our gratitude.")
    RemoveItem(1450) -- Lantern of Light
    SetAward(Award(30)) -- Returned Withern's Lantern
    AddValue(Experience, 5000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 1000)
    ClearQBit(QBit(667)) -- Retrieve the Lantern of Light from the Barrow Downs and return it to Tarin Withern in Harmondale. - Barrow Lantern Quest
    evt.SetNPCTopic(432, 0, 0) -- Tarin Withern topic 0 cleared
    evt.SetNPCGreeting(432, 267) -- Tarin Withern greeting 267
    SubtractValue(ReputationInCurrentLocation, 5)
end)

RegisterGlobalEvent(931, "Legacy event 931", function()
    evt.SimpleMessage("My, brother, Haldar passed away last month.\nThe family was sending his remains to me to be put to final rest.\nSomething happened to those delivering these remains to me; they disappeared in Nighon and not been heard from since. I fear my brothers soul will never rest unless they are found!\nPlease return Haldar to me if you find him? I will reward you well for this!")
    evt.SetNPCTopic(433, 0, 932) -- Mazim Dusk topic 0: Quest
    SetQBit(QBit(668)) -- Retrieve Haldar's Remains from the Maze in Nighon and return them to Mazim Dusk in Nighon. - Haldar's Remains Quest
end)

RegisterGlobalEvent(932, "Legacy event 932", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1430) then -- Haldar's Remains
        evt.SimpleMessage("Did you find Haldar's Remains?")
        return
    end
    evt.SimpleMessage("Thank you for returning my \"brother's\" remains!\nHe was a promising Warlock and his life was ended to soon.\nNow that I have his remains, I will attempt to bring him back as a Lich, and together we will seek greater power and glory!")
    RemoveItem(1430) -- Haldar's Remains
    SetAward(Award(32)) -- Returned Haldar's Remains
    AddValue(Experience, 50000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 35000)
    ClearQBit(QBit(668)) -- Retrieve Haldar's Remains from the Maze in Nighon and return them to Mazim Dusk in Nighon. - Haldar's Remains Quest
    evt.SetNPCTopic(433, 0, 0) -- Mazim Dusk topic 0 cleared
    evt.SetNPCGreeting(433, 269) -- Mazim Dusk greeting: My thanks for returning Haldar's remains!
    SubtractValue(ReputationInCurrentLocation, 5)
end)

RegisterGlobalEvent(933, "Legacy event 933", function()
    evt.SimpleMessage("My lords, I was beset by foul bandits when I returned from Avlee and they took everything I had brought with me from the Elves.\nThey even took my signet ring!\nWithout it I cannot continue my business because I cannot seal contracts between myself and other merchants.\nI've heard the bandits base themselves out of a camp in Erathia, but I'm no warrior-- I'd not last a minute against them.\nPlease go to Erathia and see this justice done!")
    evt.SetNPCTopic(434, 0, 934) -- Davrik Peladium topic 0: Quest
    SetQBit(QBit(669)) -- Retrieve Davrik's Signet ring from the Bandit Caves in the northeast of Erathia and return it to Davrik Peladium in Harmondale. - Davrik's Ring Quest
end)

RegisterGlobalEvent(934, "Legacy event 934", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1408) then -- Signet Ring
        evt.SimpleMessage("You don't have my ring yet?\nThe bandits are south of Castle Gryphonheart in Erathia.\nPlease help me, I don't have anyone else to turn to.")
        return
    end
    evt.SimpleMessage("My ring!\nThank you lords.\nI can now continue my business and recover my losses, and you have made the trading routes safer for all the merchants!")
    RemoveItem(1408) -- Signet Ring
    SetAward(Award(34)) -- Returned Lord Davrik's signet Ring
    AddValue(Experience, 5000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 5000)
    ClearQBit(QBit(669)) -- Retrieve Davrik's Signet ring from the Bandit Caves in the northeast of Erathia and return it to Davrik Peladium in Harmondale. - Davrik's Ring Quest
    evt.SetNPCTopic(434, 0, 0) -- Davrik Peladium topic 0 cleared
    evt.MoveNPC(434, 0) -- Davrik Peladium -> removed
    SubtractValue(ReputationInCurrentLocation, 5)
end)

RegisterGlobalEvent(935, "Legacy event 935", function()
    evt.SimpleMessage("So you are the Lords of Harmondale, eh?\nYou don’t look like much; we shall see how history judges you!\nI myself am a historian and collector of rare historical items.\nLord Markham also collects such items of interest and there is one item in particular that would complete my collection, Parson's Quill-- the Quill used to sign the Treaty of Pierpont ending the first Timber War.\nI know you have dealt with Lord Markham before, it's how you became Lords of this land after all, and if you would take this letter to Lord Markham in Tatalia, I'm sure he would respond favorably.\nI would be even more in your debt if Lord Markham sends this item back with you!\nI would be sure to favorably record your heroic acts and deeds!")
    evt.SetNPCTopic(435, 0, 936) -- Norbert Thrush topic 0: Thrush's Letter
    SetQBit(QBit(670)) -- Take Sealed Letter to Lord Markham in Lord Markham's Manor in Tatalia for collector Norbert Thrush.
    AddValue(InventoryItem(1416), 1416) -- Letter from Norbert Thrush to Lord Markham
end)

RegisterGlobalEvent(936, "Legacy event 936", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1405) then -- Parson's Quill
        evt.SimpleMessage("Did Lord Markham refuse to give you the Quill, or have you not even visited him yet?\nHis Manor is in Tatalia, please don't forget to help me.")
        return
    end
    evt.SimpleMessage("The actual Peacock feather that was used to sign the Treaty of Pierpont.")
    RemoveItem(1405) -- Parson's Quill
    SetAward(Award(38)) -- Returned Parson's Quill to Norbert Thrush
    AddValue(Experience, 5000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 2000)
    ClearQBit(QBit(671)) -- Return Parson's Quill to Norbert Thrush in Erathia.
    evt.SetNPCTopic(435, 0, 0) -- Norbert Thrush topic 0 cleared
    evt.SetNPCGreeting(435, 273) -- Norbert Thrush greeting 273
    SubtractValue(ReputationInCurrentLocation, 5)
end)

RegisterGlobalEvent(937, "Legacy event 937", function()
    evt.ForPlayer(Players.All)
    evt.SimpleMessage("A letter from Norbert Thrush the Historian? Let me see it.\n[Lord Markham scans the letter briefly] Hmmmmm…he wants the Peacock feather that was used to sign the Treaty of Pierpont, does he.\nWell, seeing as though he has a supposed original of the Treaty, I guess the feather should go to him.\nHe has promised me anything else in his collection.\nTake this to him and tell him that I will come collect from him shortly!")
    RemoveItem(1416) -- Letter from Norbert Thrush to Lord Markham
    evt.ForPlayer(Players.Current)
    AddValue(InventoryItem(1405), 1405) -- Parson's Quill
    ClearQBit(QBit(670)) -- Take Sealed Letter to Lord Markham in Lord Markham's Manor in Tatalia for collector Norbert Thrush.
    SetQBit(QBit(671)) -- Return Parson's Quill to Norbert Thrush in Erathia.
