RegisterGlobalEvent(938, "Legacy event 938", function()
    evt.SimpleMessage("I hear you folk are the new Lords of Harmondale, eh?\nPerhaps you could do me a large favor, and help yourselves in the process.\nTo the north, in Avlee, lies the Hall under the Hill, the domain of the Faerie King.\nHe owes me a debt from a previous service of mine, and I would like to collect it.\nUnfortunately, the faeries in the Hall and the tricks they play frighten me to death.\nIf you would deliver this letter to the Faerie King, and return what he gives you to me, I'd be very grateful.\nYou would also have the chance to meet the Faerie King for yourselves.")
    SetQBit(QBit(691)) -- Take the sealed letter to the Faerie King in the Hall under the Hill in Avlee.
    AddValue(InventoryItem(1409), 1409) -- Letter from Johann Kerrid to the Faerie King
    evt.SetNPCTopic(436, 0, 940) -- Johann Kerrid topic 0: Quest
end)

RegisterGlobalEvent(939, "Legacy event 939", function()
    evt.ForPlayer(Players.All)
    evt.SimpleMessage("So, Johann be wanting the Faerie Pipes, eh?\nI can't say I'm surprised--he wouldn't come here himself, the coward.\nThe Pipes will cost you, though… all your food.\nOf course, I've got some delightful food down below, should thee be wanting to restock your packs.")
