RegisterGlobalEvent(941, "Legacy event 941", function()
    evt.SimpleMessage("We request your services for only one small task.\nIn Castle Lambent rests a valuable tapestry taken from an attack on Watchtower 3 years ago.\nI would like you to get the tapestry for me, as you must have *some* access to the Castle-- my normal associates can't even come near the place.\nI hear a large band of goblins and renegade swordsmen are about... it would be a shame if they happened to find a way to Harmondale.\nYou have one month to get the tapestry.\nDon't be late.")
    SetQBit(QBit(694)) -- Steal the Tapestry from your associate's Castle and return it to Niles Stantley in the Mercenary Guild in Tatalia. - Do the Merc Guild Quest
    SetValue(Counter(5), 0)
