RegisterGlobalEvent(942, "Legacy event 942", function()
    evt.SimpleMessage("We request your services for one task.\nA rare and valuable tapestry rests in Castle Gloaming, an antique from near the Silence stolen from the wizards some time ago.\nI would like you to get the tapestry for me, as my normal associates don't have access to Castle Gloaming.\nIn return, I'll make sure that the large band of renegade swordsmen and goblins near Harmondale don't accidentally stumble upon your quiet, little village.\nYou have one month; don't be late.")
