RegisterGlobalEvent(943, "Legacy event 943", function()
    evt.ForPlayer(Players.All)
    if IsAtLeast(Counter(5), 672) then
        evt.SimpleMessage("I see.\nWell, it would appear that the band of renegades has indeed discovered your little town, and has begun looting.\nYou may find your bank account a little, well, pinched.\nConsider this a lesson in punctuality.\nGo now and have a pleasant, pleasant day.")
        SetQBit(QBit(695)) -- Failed either goto or do guild quest
        return
    elseif HasItem(1422) then -- Big Tapestry
        evt.SimpleMessage("Excellent!\nI see that you can be trusted to perform well when called upon.\nI'll keep that in mind the next time I need a job done.\nYour reward is nothing more than status quo-- things could be much worse than they already are.\nGo now, I have no more time for you.")
        RemoveItem(1422) -- Big Tapestry
        AddValue(ReputationInCurrentLocation, 5)
        SetQBit(QBit(702)) -- Finished with Malwick & Assc.
        ClearQBit(QBit(694)) -- Steal the Tapestry from your associate's Castle and return it to Niles Stantley in the Mercenary Guild in Tatalia. - Do the Merc Guild Quest
        evt.SetNPCTopic(438, 0, 0) -- Niles Stantley topic 0 cleared
        evt.SetNPCTopic(438, 1, 0) -- Niles Stantley topic 1 cleared
        evt.SetNPCTopic(438, 2, 0) -- Niles Stantley topic 2 cleared
    else
        evt.SimpleMessage("You don't have the tapestry yet, and the clock is ticking.\nIt would be prudent to keep to the task at hand rather than bothering me with your babble.")
        return
    end
end)

RegisterGlobalEvent(944, "Legacy event 944", function()
    evt.SimpleMessage("A few years back, while mining underneath Stone City, we came upon quite a shock.\nIt seems that the Warlocks from Nighon had burrowed under the sea to make a sneak attack upon the shores of Erathia.\nTheir careless tunneling has sunken the earth around here until now the areas around the old dwarven barrows and, of course, Stone City, rest far above the terrain.\nWe discovered a force of troglodytes in our mining areas, with a tunnel leading back to Nighon.\nIf you could help us by ridding the tunnels of the troglodytes, we could get back to mining.\nCan you help us?")
    SetQBit(QBit(698)) -- Kill all the Troglodytes underneath Stone City and return to Spark Burnkindle in Stone City.
    evt.SetNPCTopic(439, 0, 945) -- Spark Burnkindle topic 0: Quest
end)

RegisterGlobalEvent(945, "Legacy event 945", function()
    if not evt.CheckMonstersKilled(ActorKillCheck.MonsterId, 411, 0, false) then -- monster 411 "Troglodyte Drone"; all matching actors defeated
        evt.SimpleMessage("There are still troglodytes roaming the lower mine levels.")
        return
    end
    if not evt.CheckMonstersKilled(ActorKillCheck.MonsterId, 412, 0, false) then -- monster 412 "Troglodyte Soldier"; all matching actors defeated
        evt.SimpleMessage("There are still troglodytes roaming the lower mine levels.")
        return
    end
    if not evt.CheckMonstersKilled(ActorKillCheck.MonsterId, 413, 0, false) then -- monster 413 "Troglodyte Queen"; all matching actors defeated
        evt.SimpleMessage("There are still troglodytes roaming the lower mine levels.")
        return
    end
    evt.SimpleMessage("They're gone?")
    AddValue(Gold, 2500)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 5000)
    ClearQBit(QBit(698)) -- Kill all the Troglodytes underneath Stone City and return to Spark Burnkindle in Stone City.
    SetAward(Award(40)) -- Troglodyte Slayer
    evt.SetNPCTopic(439, 0, 0) -- Spark Burnkindle topic 0 cleared
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.SetNPCGreeting(439, 279) -- Spark Burnkindle greeting: Thank you for helping us by getting rid of those nasty Troglodytes!
end)

RegisterGlobalEvent(946, "Legacy event 946", function()
    evt.SimpleMessage("I have recently gained information that the forces of Queen Catherine, in Erathia, have begun to build a force to attack Deyja.\nBecause of the difficult terrain, they have begun to breed and train griffins to assist in their attack.\nThese griffins are being raised in both Erathia and the Bracada Desert.\nI need you to kill off all the griffins in those two areas so that the Erathians will be forced to drastically delay their plans of attack.")
    SetQBit(QBit(699)) -- Kill all the Griffins in Erathia and the Bracada Desert and return to Seth Drakkson in the Deyja Moors.
    evt.SetNPCTopic(623, 0, 947) -- Seth Drakkson topic 0: Quest
end)
