            evt.SimpleMessage("You've killed the griffins near Steadwick, but you haven't dealt with the griffins in the Bracada Desert yet.\nFinish them both off and return to me.")
            return
        end
        evt.SimpleMessage("Excellent!\nYou've done a splendid job.\nHere, take this as your reward and know you've earned the respect of Deyja for your bold success.")
        ClearQBit(QBit(699)) -- Kill all the Griffins in Erathia and the Bracada Desert and return to Seth Drakkson in the Deyja Moors.
        AddValue(Gold, 5000)
        evt.ForPlayer(Players.All)
        AddValue(Experience, 10000)
        SubtractValue(ReputationInCurrentLocation, 10)
        SetAward(Award(51)) -- Griffin Slayer
        evt.SetNPCTopic(623, 0, 0) -- Seth Drakkson topic 0 cleared
        evt.SetNPCGreeting(623, 281) -- Seth Drakkson greeting: Good work on those griffins, my lords. It is always a pleasure to see you.
    elseif IsQBitSet(QBit(701)) then -- Killed all Bracada Desert Griffins
        if not IsQBitSet(QBit(700)) then -- Killed all Erathian Griffins
            evt.SimpleMessage("You've killed the griffins near Spyre Town, but you haven't dealt with the griffins in Erathia yet.\nFinish them both off and return to me.")
            return
        end
        evt.SimpleMessage("Excellent!\nYou've done a splendid job.\nHere, take this as your reward and know you've earned the respect of Deyja for your bold success.")
        ClearQBit(QBit(699)) -- Kill all the Griffins in Erathia and the Bracada Desert and return to Seth Drakkson in the Deyja Moors.
        AddValue(Gold, 5000)
        evt.ForPlayer(Players.All)
        AddValue(Experience, 10000)
        SubtractValue(ReputationInCurrentLocation, 10)
        SetAward(Award(51)) -- Griffin Slayer
        evt.SetNPCTopic(623, 0, 0) -- Seth Drakkson topic 0 cleared
