RegisterGlobalEvent(948, "Legacy event 948", function()
    evt.SimpleMessage("My brother, Elron, was an avid Arcomage player.\nHave you played Arcomage yet?\nHorribly addicting game, if I do say so.\nIn any rate, you can only play if you have a deck, and decks are hard to come by… so I guess you probably haven't.\nIn any case, Elron wanted to go over some strategies to help him win more games.\nUnfortunately, he didn't want to be in town because he didn't want anyone else to spy on him learn his tricks so he went to the White Cliff Caves southeast a bit from town.Elron hasn't been back in almost a week.\nI'm certain something horrible has happened to him, but if he's alive I'd like to know that too.\nWould you do me the service of locating him?\nI don't have a lot of money to pay you back with, but I'd be greatly in your debt.")
    SetQBit(QBit(706)) -- Find the fate of Darron's brother in the White Cliff Caves, then return to Darron Temper in Harmondale.
    evt.SetNPCTopic(624, 0, 949) -- Darron Temper topic 0: Quest
end)

RegisterGlobalEvent(949, "Legacy event 949", function()
    evt.ForPlayer(Players.All)
    if not HasItem(1453) then -- Arcomage Deck
        evt.SimpleMessage("Still no sign of him?\nI understand.\nIf you do happen to find out what happened to him, please let me know.")
        return
    end
    evt.SimpleMessage("Dead?\nOh dear!\nThose are certainly his cards, though.\nI don't want the cards; you can have them-- that game has cost me enough now.\nOh, poor Elron!\nI have a little money you can keep for your help, and thank you for finding out what happened to Elron.")
    AddValue(Experience, 2000)
    evt.ForPlayer(Players.Current)
    ClearQBit(QBit(706)) -- Find the fate of Darron's brother in the White Cliff Caves, then return to Darron Temper in Harmondale.
    AddValue(Gold, 750)
    evt.SetNPCTopic(624, 0, 0) -- Darron Temper topic 0 cleared
    SubtractValue(ReputationInCurrentLocation, 5)
end)

