    AddValue(InventoryItem(1432), 1432) -- Red Apple
    evt.ChangeEvent(0)
end)

RegisterGlobalEvent(1165, "Legacy event 1165", function()
    evt.StatusText("Empty Cask")
end)

RegisterGlobalEvent(1166, "Legacy event 1166", function()
    local randomStep = PickRandomOption(1166, 1, {1, 1, 1, 8, 8, 8})
    if randomStep == 1 then
        local randomStep = PickRandomOption(1166, 2, {2, 2, 2, 5, 5, 5})
        if randomStep == 2 then
            SetValue(PoisonedYellow, 0)
            evt.StatusText("Poisoned!")
        elseif randomStep == 5 then
            SetValue(PoisonedGreen, 0)
            evt.StatusText("Drunk!")
        end
    elseif randomStep == 8 then
        local randomStep = PickRandomOption(1166, 9, {9, 9, 11, 11, 13, 15})
        if randomStep == 9 then
            AddValue(InventoryItem(1004), 1004) -- Vial of Troll Blood
        elseif randomStep == 11 then
            AddValue(InventoryItem(1019), 1019) -- Vial of Ooze Endoplasm
        elseif randomStep == 13 then
            AddValue(InventoryItem(1020), 1020) -- Mercury
        elseif randomStep == 15 then
            AddValue(InventoryItem(1016), 1016) -- Vial of Devil Ichor
        end
    end
    evt.ChangeEvent(1165)
end)

RegisterGlobalEvent(1167, "Legacy event 1167", function()
    AddValue(InventoryItem(1017), 1017) -- Mushroom
    evt.ChangeEvent(0)
end)

RegisterGlobalEvent(1168, "Legacy event 1168", function()
    evt.SimpleMessage("So YOU'RE the ones that won Lord Markham's contest!\nHow do you like your winnings so far?\nHad enough winning?\nIf I were you, I'd give him a piece of my mind!\nHis mansion is in Tatalia, near the wharf.")
end)

RegisterGlobalEvent(1169, "Legacy event 1169", function()
    evt.SimpleMessage("Watch your wallet while you're here, my friends--Steadwick abounds in thieves.\nAs a matter of fact, we are the world capital of thieves!\nIt's common knowledge that Bill Lasker, the Master Thief, lives in the sewers beneath Steadwick.")
end)

RegisterGlobalEvent(1170, "Legacy event 1170", function()
    if not IsQBitSet(QBit(708)) then -- Find second entrance to Watchtower6
        evt.SimpleMessage("Back when I was in the army, I was assigned to scout out the watchtowers in Deyja.\n<chuckling> It's no good trying to go through the front door, so I usually looked around for another way in.\nThose Necromancers are so cowardly, they always have an escape route.\nAnd a way out is also a way in...")
        return
    end
    evt.SimpleMessage("Glad you found the way in the back door.")
end)
RegisterCanShowTopic(1170, function()
    evt._BeginCanShowTopic(1170)
    local visible = true
    if IsQBitSet(QBit(708)) then -- Find second entrance to Watchtower6
        visible = true
        return visible
    else
        if IsQBitSet(QBit(531)) then -- Go to Watchtower 6 in the Deyja Moors, and move the weight from the top of the tower to the bottom of the tower. Then return to William Lasker in the Erathian Sewers.
            visible = true
            return visible
        else
            visible = false
            return visible
        end
    end
end)

RegisterGlobalEvent(1171, "Legacy event 1171", function()
    evt.SimpleMessage("Bill Lasker may be a criminal, but he has worked for the Crown from time to time.\nSpecial missions, official denials of involvement, spying…that sort of stuff.\nQuite a few unusual events can be tied to Bill, but none to the Crown.\nSeriously, don't you think the Queen's men could find and arrest one man, even if he was hiding in the sewer?")
end)

RegisterGlobalEvent(1172, "Legacy event 1172", function()
    if HasItem(1342) then -- Lady Carmine's Dagger
        evt.SimpleMessage("So…what goes around comes around, eh?\nGood job with that Carmine traitor!")
    elseif IsQBitSet(QBit(1564)) then -- Promoted to Assassin
        evt.SimpleMessage("So…what goes around comes around, eh?\nGood job with that Carmine traitor!")
    elseif IsQBitSet(QBit(1565)) then -- Promoted to Honorary Assassin
        evt.SimpleMessage("So…what goes around comes around, eh?\nGood job with that Carmine traitor!")
    else
        evt.SimpleMessage("You want to know about that traitor, Carmine?\nWell, she used to work for the diplomatic corps, until she went soft and signed up with the goody two-shoes wizards.\nNow she walks the streets of Celeste freely, without a care in the world for the people she left behind.\nSomething bad will happen to her soon, mark my words!")
        return
    end
end)
RegisterCanShowTopic(1172, function()
    evt._BeginCanShowTopic(1172)
    local visible = true
    if IsQBitSet(QBit(1564)) then -- Promoted to Assassin
        visible = true
        return visible
    else
        if IsQBitSet(QBit(1565)) then -- Promoted to Honorary Assassin
            visible = true
            return visible
        else
            if IsQBitSet(QBit(533)) then -- Go to the Celestial Court in Celeste and kill Lady Eleanor Carmine. Return with proof to Seknit Undershadow in the Deyja Moors.
                visible = true
                return visible
            else
                visible = false
                return visible
            end
        end
    end
end)

RegisterGlobalEvent(1173, "Legacy event 1173", function()
    evt.SimpleMessage("Looking for \"work\"?\nYou can find the Master Assassin somewhere in the Pit.\nHe'll have something for you.\nThere's always someone or something that needs killing, that's for certain.")
end)

RegisterGlobalEvent(1174, "Legacy event 1174", function()
    if IsQBitSet(QBit(1564)) then -- Promoted to Assassin
        evt.SimpleMessage("The dragon is fallen--and at your hands!")
    elseif IsQBitSet(QBit(1565)) then -- Promoted to Honorary Assassin
        evt.SimpleMessage("The dragon is fallen--and at your hands!")
    else
        evt.SimpleMessage("Until recently, our local dragon Wromthrax the Heartless has confined his depredations to the hills in the south--eating goats, farm animals, and stray dogs.\nBut he has developed a taste for elvish blood, and now hunts us as well.\nIf you should care to confront him, his cave is in the north, west of the Mercenary Guild in the mountains.\nHe isn't always there.\nBe careful--he is mighty.")
        return
    end
end)
RegisterCanShowTopic(1174, function()
    evt._BeginCanShowTopic(1174)
    local visible = true
    if IsQBitSet(QBit(1590)) then -- Promoted to Crusader
        visible = true
        return visible
    else
        if IsQBitSet(QBit(1591)) then -- Promoted to Honorary Crusader
            visible = true
            return visible
        else
            if IsQBitSet(QBit(534)) then -- Kill Wromthrax the Heartless in his cave in Tatalia, then talk to Sir Charles Quixote.
                visible = true
                return visible
            else
                visible = false
                return visible
            end
        end
    end
end)

RegisterGlobalEvent(1175, "Legacy event 1175", function()
    evt.SimpleMessage("What, you wanna be a crusader too?\nThis town is filling up with them, I swear!\nWell, there's a crazy man living in the back of a building near the center of town.\nPeople keep trying to sign up with him, and he keeps rejecting them.\nGood luck.")
end)

RegisterGlobalEvent(1176, "Legacy event 1176", function()
    evt.SimpleMessage("Just a minute, let me check.\nMirror, mirror, on the wall… <the witch peers into her mirror for a few minutes, then sighs> It's still Alice Hargreaves.\nShe lives in Castle Gryphonheart.\nShe's quite a noble beauty, that girl is!\nTakes me back to my youth, this one does.")
end)

RegisterGlobalEvent(1177, "Legacy event 1177", function()
    evt.SimpleMessage("One of our finest, most upstanding citizens is William Setag, considered by some to be the most black hearted villain alive.\nAs a matter of fact, he's one of our best agents.\nWizards and their ilk complain because they've been on the receiving end of his schemes too many times-- but he's about the best there is in his profession.\nIf you're looking for employment, go see him.\nHis tower is on the north shore of Deyja at a rather inaccessible point.\nHe doesn't like visitors, but he should be glad to see more students turn up at his door.")
end)

RegisterGlobalEvent(1178, "Legacy event 1178", function()
    evt.SimpleMessage("If you're looking for a teacher to begin serious monk training, speak with Bartholomew Hume--you can find him in the village south of the town of Harmondale.")
end)

RegisterGlobalEvent(1179, "Legacy event 1179", function()
    evt.SimpleMessage("There is a breed of Medusa infesting the Red Dwarf Mines that is immune to magic.\nThese monsters are a real terror!\nI can only thank the Gods that these creatures haven't escaped the mine.\nWhat would we do then, beat them to death with our staves?")
end)

RegisterGlobalEvent(1180, "Legacy event 1180", function()
    if HasItem(1332) then -- Cloak of the Sheep
        evt.SimpleMessage("The Baa cult is gone?\nWell that IS good news!\nEveryone is in your debt, whether they know it or not.\n")
    elseif IsQBitSet(QBit(1574)) then -- Promoted to Master
        evt.SimpleMessage("The Baa cult is gone?\nWell that IS good news!\nEveryone is in your debt, whether they know it or not.\n")
    elseif IsQBitSet(QBit(1575)) then -- Promoted to Honorary Master
        evt.SimpleMessage("The Baa cult is gone?\nWell that IS good news!\nEveryone is in your debt, whether they know it or not.\n")
    else
        evt.SimpleMessage("A few years back, a weird cult called the Temple of Baa moved into the area.\nAt first they seemed popular, what with their free offers of healing, but it soon became clear they were devoted to darkness.\nNo one goes up there very much, now, and it seems that whatever evil gods were backing them have withdrawn their support.\nBut they're up there still, lurking in the shadows.\nCreepy.")
        return
    end
end)
RegisterCanShowTopic(1180, function()
    evt._BeginCanShowTopic(1180)
    local visible = true
