            visible = true
            return visible
        else
            if IsQBitSet(QBit(540)) then -- Go to the Temple of Baa in Avlee and kill the High Priest of Baa, then return to Bartholomew Hume in Harmondale.
                visible = true
                return visible
            else
                visible = false
                return visible
            end
        end
    end
end)

