RegisterGlobalEvent(1182, "Legacy event 1182", function()
    evt.SimpleMessage("Ssspies abound in places like this, my friendsss.\nIf you wish your letters and communiqués to remain sssecret, you should use a cipher when you write.\nThere is a book in the Castle library that will explain everything, my friendsss.")
end)

RegisterGlobalEvent(1183, "Legacy event 1183", function()
    evt.SimpleMessage("Eight years ago, we sent a team of scholars to what is now the Red Dwarf Mine to study the strange creatures that would occasionally show up there.\nThe first thing we noticed was that Ooze ectoplasm makes an excellent potion catalyst.\nThe second was that ooze just can't be physically damaged--they split apart or squish, then run back together. If you want to kill one, you'll have to do it with magic.")
end)

RegisterGlobalEvent(1184, "Legacy event 1184", function()
    evt.SimpleMessage("There is a breed of Medusa infesting the Red Dwarf Mines that is immune to magic.\nThese monsters are a real terror!\nI can only thank the Gods that these creatures haven't escaped the mine.\nWhat would we do then, beat them to death with our staves?")
end)

RegisterGlobalEvent(1185, "Legacy event 1185", function()
    evt.SimpleMessage("If you head south past the Wyvern Plains, don't go knocking at the door of that huge fortress you'll see standing in the middle of the water.\nIt's the Titan's Stronghold, and they don't much like visitors.")
end)

RegisterGlobalEvent(1186, "Legacy event 1186", function()
    evt.SimpleMessage("Arena fighting is available to anyone who wants to practice against any kind of opponent.")
end)

RegisterGlobalEvent(1187, "Legacy event 1187", function()
    evt.SimpleMessage("Arena Champships are held on each Sunday.\nThey are open to all--but be careful!\nYour opponents are chosen by the Arena management, not you!")
end)

RegisterGlobalEvent(1188, "Legacy event 1188", function()
    evt.SimpleMessage("Every graveyard or ancestral burial place seems to have a haunted house nearby--and ours is no exception.")
end)

RegisterGlobalEvent(1189, "Legacy event 1189", function()
    evt.SimpleMessage("Fear the touch of the Ghost as you fear the loss of your life.")
end)

RegisterGlobalEvent(1190, "Legacy event 1190", function()
    evt.SimpleMessage("A few wars ago, my great grandfather worked on an escape tunnel from the Elvish castle to the Tularean Caves.\nI don't think it's ever been used--no attack on the castle has ever brought it down--but it sure is an interesting piece of history, don't you think?")
end)

RegisterGlobalEvent(1191, "Legacy event 1191", function()
    if not IsQBitSet(QBit(709)) then -- Entered Faerie Mound
        evt.SimpleMessage("They say that elves are faeries, but in truth we are only distantly related.\nThe true faeries don't live in civilization, and they're just like the stories say--playful, cruel, magical, and dangerous.\nBut if you really want to meet them, you could visit them in their Hall under the Hill, as they call it.\nIt is just outside of the village, to the North and West.\nIt will be challenging to get to the front door... ")
        return
    end
    evt.SimpleMessage("I'm impressed--very few actually make it inside the fairy mound, or get very far.")
end)

RegisterGlobalEvent(1192, "Legacy event 1192", function()
    if HasItem(1402) then -- Heart of the Wood
        evt.SimpleMessage("The forest is much safer now, thanks you to!\nThe oldest tree is very happy with you, and has included you in its history recitals.")
    elseif IsQBitSet(QBit(1580)) then -- Promoted to Ranger Lord
        evt.SimpleMessage("The forest is much safer now, thanks you to!\nThe oldest tree is very happy with you, and has included you in its history recitals.")
    elseif IsQBitSet(QBit(1581)) then -- Promoted to Honorary Ranger Lord
        evt.SimpleMessage("The forest is much safer now, thanks you to!\nThe oldest tree is very happy with you, and has included you in its history recitals.")
    elseif HasAward(Award(23)) then -- Retrieved the Heart of the Wood
        evt.SimpleMessage("The forest is much safer now, thanks you to!\nThe oldest tree is very happy with you, and has included you in its history recitals.")
    else
        evt.SimpleMessage("A while ago, I saw some men come to the Tularean Forest at night with axes and torches, following some sort of map.\nWhen they left, they were laughing and happy.\nIt looked like they were carrying a big green rock.\nMy brother says they were a band of mercenaries from Tatalia.\nAnyway, the next day was when the forest went mad.\nIt's too dangerous to go there now.")
        return
    end
end)

RegisterGlobalEvent(1193, "Legacy event 1193", function()
    evt.SimpleMessage("The Tularean Forest is so old that it has developed a mind…sort of.\nThe forest is vaguely aware of who walks through it, but only one part of the forest can communicate with people.\nThat's the oldest tree.\nIf you want to have a very long and slow conversation, it will be happy to oblige.\nLook for it on an island to the south east of the forest.\nIt's larger than the rest of the trees.\nYou can't miss it.")
end)

RegisterGlobalEvent(1194, "Legacy event 1194", function()
    evt.SimpleMessage("Anyone needing to earn some spare cash can visit a town hall in any major city to pick up a bounty hunting assignment.\nCity councils are always fearful of the latest man eating monster or bandit or mad wizard, and set bounties on the creature that is bothering them most this month.\nThere's no rhyme or reason to their choices, so don't try to figure it out.\nThey often pay quite well.")
end)

RegisterGlobalEvent(1195, "Legacy event 1195", function()
    evt.SimpleMessage("If you ever get tired of amateur bounty hunts, and want to advance your career, speak with Ebednezer Sower in Avlee.\nHe only teaches followers of the shadow path, though.")
end)

RegisterGlobalEvent(1196, "Legacy event 1196", function()
    evt.SimpleMessage("Pirates been operating out of the tidewater caverns for twenty years.\nThey're not Regnans, and they aren't part of Bill Lasker's men, but they're still pretty mean.\nYou want to get in there, just get yourself out to the islands to the west.")
end)

RegisterGlobalEvent(1197, "Legacy event 1197", function()
    if HasItem(1485) then -- Map to Evenmorn Island
        evt.SimpleMessage("Oh, so the map is found?\nWhat will you do with your newfound treasure?\nShare it, I hope!")
    elseif IsQBitSet(QBit(1607)) then -- Promoted to Priest
        evt.SimpleMessage("Oh, so the map is found?\nWhat will you do with your newfound treasure?\nShare it, I hope!")
    elseif IsQBitSet(QBit(1608)) then -- Promoted to Honorary Priest
        evt.SimpleMessage("Oh, so the map is found?\nWhat will you do with your newfound treasure?\nShare it, I hope!")
    else
        evt.SimpleMessage("Evenmorn Island isn't lost, so much as hard to get to.\nIt is surrounded by treacherous reefs, sandbars, whirlpools, and sharks.\nIf it's dangerous, the Island is surrounded by it.\nThere are only one or two safe ways in, and the map for those ways was stolen by pirates during the chaos of the recent wars.\nThey probably still have the map in their caves.\n")
        return
    end
end)

RegisterGlobalEvent(1198, "Legacy event 1198", function()
    if HasItem(1485) then -- Map to Evenmorn Island
        evt.SimpleMessage("Now that you have the map, I guess you'll be going there soon.\nBe careful--they say the island is cursed!")
    elseif IsQBitSet(QBit(1607)) then -- Promoted to Priest
        evt.SimpleMessage("Now that you have the map, I guess you'll be going there soon.\nBe careful--they say the island is cursed!")
    elseif IsQBitSet(QBit(1608)) then -- Promoted to Honorary Priest
        evt.SimpleMessage("Now that you have the map, I guess you'll be going there soon.\nBe careful--they say the island is cursed!")
    else
        evt.SimpleMessage("The boat captains would be happy to take any paying fare to Evenmorn island, but they don't have proper maps.\nThere's no way anyone is going to risk their ship in the reefs around the Island unless they have the map!")
        return
    end
end)

RegisterGlobalEvent(1199, "Legacy event 1199", function()
    evt.SimpleMessage("If you don't mind the swamp and fog, Evenmorn Island is a great place to live.\nOf course, the Curse doesn't help--ghosts and skeletons roam the island freely--but other than that, the neighbors keep to themselves.\nThe Churches of the Sun and the Moon don't even fight each other very much anymore.\n<Heh!> probably means they're running out of adherents...")
end)

RegisterGlobalEvent(1200, "Legacy event 1200", function()
    evt.SimpleMessage("Well, I don't have any golem parts--I never took that class--but there are students all over Bracada who have spare golem parts lying around.\nThey aren't worth anything unless you have them all, so they'll probably just give them to you for free.")
end)

RegisterGlobalEvent(1201, "Legacy event 1201", function()
    evt.SimpleMessage("You see all those golems walking around Bracada?\nEvery single one of them was made by the School.\nNot bad for students, eh?\nThey don't have much to say, but they're tough guardians and can tell when a follower of Darkness is near.\nYou should see them go into action when one of those Necromancers or Warlocks wanders into our lands.\nZowwwwwieeee!")
end)

RegisterGlobalEvent(1202, "Legacy event 1202", function()
    if HasItem(1289) then -- Divine Intervention
        evt.SimpleMessage("Divine intervention has been found and copied?")
    elseif IsQBitSet(QBit(1621)) then -- Promoted to Archmage
        evt.SimpleMessage("Divine intervention has been found and copied?")
    elseif IsQBitSet(QBit(1622)) then -- Promoted to Honorary Archmage
        evt.SimpleMessage("Divine intervention has been found and copied?")
    else
        evt.SimpleMessage("Our astrologers have determined that the missing Divine Intervention text lies somewhere deep under the ground.\nUnder Deyja, to be precise.\nThey fear that the current incarnation of the text has fallen into the Breeding Pit--the Necromancer's version of our Proving Grounds.\nOh, what must we have done to offend the Gods so?\nWe will never retrieve the text from that forsaken place!")
        return
    end
end)

RegisterGlobalEvent(1203, "Legacy event 1203", function()
    if HasItem(1289) then -- Divine Intervention
        evt.SimpleMessage("All the grandmasters are very pleased with you.")
    elseif IsQBitSet(QBit(1621)) then -- Promoted to Archmage
        evt.SimpleMessage("All the grandmasters are very pleased with you.")
    elseif IsQBitSet(QBit(1622)) then -- Promoted to Honorary Archmage
        evt.SimpleMessage("All the grandmasters are very pleased with you.")
    else
        evt.SimpleMessage("The spell of Divine Intervention, the highest of the school of Light magic, has been missing for centuries.\nIt is a curse, we believe, for our lack of devotion and faith to the Light.\nWe struggle, and some go forth to find the spell, from time to time, but none have been successful.\nEach time they find it, fate cruelly snatches it from our hands.\nOur Grandmasters have been bereft of this final, great spell for as long as anyone alive can remember.")
        return
    end
end)

RegisterGlobalEvent(1204, "Legacy event 1204", function()
    evt.SimpleMessage("The only people in the world who make soul jars are the Warlocks of Nighon.\nIt is a secret of their profession--which is strange, since they have absolutely no use for them.\nStill, we are forced to bargain for the jars in order to advance our craft.\nOf course, we have wrested the jars from them, from time to time...but then they raise their prices in revenge.\nIt must be our fate to suffer so.")
end)

RegisterGlobalEvent(1205, "Legacy event 1205", function()
    evt.SimpleMessage("Every Necromancer aspires to be a Lich one day.\nAll you need is a Soul Jar, knowledge of the Ritual, and the magical skill to survive the journey to the Land of the Dead and return.\nThe body withers while the soul lives on in a glorious state free from hunger, disease, and injury.\nOnly shallow and superficial people would mind what the Ritual does to one's appearance.\nTrue practitioners hardly notice.")
end)

RegisterGlobalEvent(1206, "Legacy event 1206", function()
    if IsQBitSet(QBit(1613)) then -- Promoted to Great Druid
        evt.SimpleMessage("Since you've discovered the circles on your own they have worked their magic on you.\nI hope you will refrain from telling others of their whereabouts, as I have done for you.")
    elseif IsQBitSet(QBit(1614)) then -- Promoted to Honorary Great Druid
        evt.SimpleMessage("Since you've discovered the circles on your own they have worked their magic on you.\nI hope you will refrain from telling others of their whereabouts, as I have done for you.")
    else
        evt.SimpleMessage("Three circles of stones were built by the Druids long ago.\nSince hearing of their locations ruins ascension attempts for would be Great Druids, I can only give you a general clue--All are in the open, unhidden and bare, and all are distant from settlements.\nTo tell you more would spoil your Ascension.")
        return
    end
end)

RegisterGlobalEvent(1207, "Legacy event 1207", function()
    evt.SimpleMessage("Originally, there were four Circles of Stone, one for each Cardinal direction and season, but the Eastern Circle was destroyed somewhere in Nighon during the wars between the Churches of the Sun and the Moon.")
end)

RegisterGlobalEvent(1208, "Legacy event 1208", function()
    evt.SimpleMessage("The graveyard does indeed hold the bones of the ancient King, but the hallowed land will curse any who disturb it.\nI don't envy you this task.\nEach grave you open will unleash its curse, and possibly some other trap.\nBest be sure you're opening the correct grave when you begin to dig.")
end)

RegisterGlobalEvent(1209, "Legacy event 1209", function()
    evt.SimpleMessage("Though the barrows were built to deter thieves, a way was needed to navigate them during burials and ceremonies.\nNear each of the gates you'll find a plaque.\nThese plaques are cryptic, but they will keep you from losing your way, as long as you use them.\nNo thief yet has realized their significance, so once they enter the barrows, they never leave.")
end)

RegisterGlobalEvent(1210, "Legacy event 1210", function()
    evt.SimpleMessage("We built a tunnel leading from our Thunderfist Mountain to the Land of the Giants during the War.\nIt was there we discovered the Kreegan, and more titans and dragons then you can imagine.\nI suppose one who's familiar is to be a dragon could find eggs in one of the dragon caves of that terrible land.\n'Ware the mother...")
end)

RegisterGlobalEvent(1211, "Legacy event 1211", function()
    evt.SimpleMessage("I've heard legends that there is a dragon in the Land of the Titans greater than any that have come before.\nLesser dragons and titans do battle on the slopes of the mountain in which its cave resides.\nThis dragon is so huge, and so mighty that the other dragons feed it for fear it will one day leave its cave and devour them all in its fury.\nThe dragons believe it is a god.\nIf that is so, imagine its treasure...")
end)

RegisterGlobalEvent(1212, "Legacy event 1212", function()
    evt.SimpleMessage("During the wars between the Temples of the Sun and Moon, three statuettes were stolen from the shrines in the Bracada Desert, Tatalia, and Avlee.\nI represent a group of Druids that want these shrines back to their original form-- it is critical for their worship.\nTo this end, I am offering a substantial reward for anyone that will find the statuettes and place them on the shrines.")
    SetQBit(QBit(712)) -- Retrieve the three statuettes and place them on the shrines in the Bracada Desert, Tatalia, and Avlee, then return to Thom Lumbra in the Tularean Forest.
    evt.SetNPCTopic(627, 0, 1213) -- Thom Lumbra topic 0: Quest
end)

RegisterGlobalEvent(1213, "Legacy event 1213", function()
    if IsQBitSet(QBit(713)) then -- Placed item 617 in out14(statue)
        if IsQBitSet(QBit(714)) then -- Place item 618 in out13(statue)
            if not IsQBitSet(QBit(715)) then -- Place item 619 in out06(statue)
                evt.SimpleMessage("All three statuettes are not placed.")
                return
            end
            evt.SimpleMessage("Great work!\nThe Druids are so pleased, they threw in a little extra for your fine performance.\nTake this… you most certainly deserve it.")
            AddValue(Gold, 50000)
            SubtractValue(ReputationInCurrentLocation, 10)
            evt.ForPlayer(Players.All)
            ClearQBit(QBit(712)) -- Retrieve the three statuettes and place them on the shrines in the Bracada Desert, Tatalia, and Avlee, then return to Thom Lumbra in the Tularean Forest.
            AddValue(Experience, 50000)
            SetAward(Award(53)) -- Found and placed all the statuettes
            evt.SetNPCGreeting(627, 289) -- Thom Lumbra greeting: Excellent work; my associates are quite pleased.
            evt.SetNPCTopic(627, 0, 0) -- Thom Lumbra topic 0 cleared
        end
    end
    evt.SimpleMessage("All three statuettes are not placed.")
end)

RegisterGlobalEvent(1214, "Legacy event 1214", function()
    evt.SimpleMessage("As you may have already guessed, I'm a collector of fine art.\nCurrently, I am looking for a set of paintings, one of King Roland, one of his brother Archibald, and one of the angel statue in the courtyard of Castle Ironfist.\nThis set is of great value, and, as a collector, I'm willing to pay quite handsomely for it.\nIf you should gather the entire set of paintings bring them back to me and I'll be sure to compensate you well for your effort.")
    SetQBit(QBit(716)) -- Retrieve the three paintings and return them to Ferdinand Visconti in Tatalia.
    evt.SetNPCTopic(628, 0, 1215) -- Ferdinand Visconti topic 0: Quest
end)

RegisterGlobalEvent(1215, "Legacy event 1215", function()
    evt.ForPlayer(Players.All)
    if HasItem(1423) then -- Angel Statue Painting
        if HasItem(1424) then -- Archibald Ironfist Painting
            if not HasItem(1425) then -- Roland Ironfist Painting
                evt.SimpleMessage("Remember, I need the complete set of paintings-- they aren't worth much by themselves.\nWhen you have the rest, bring them all to me.")
                return
            end
            evt.SimpleMessage("Wonderful!\nThis set has eluded me for years!\nYou more than deserve the reward I promised; here, hopefully this will be sufficient.")
            RemoveItem(1423) -- Angel Statue Painting
            RemoveItem(1424) -- Archibald Ironfist Painting
            RemoveItem(1425) -- Roland Ironfist Painting
            evt.ForPlayer(Players.Current)
            AddValue(Gold, 50000)
            SubtractValue(ReputationInCurrentLocation, 10)
            evt.ForPlayer(Players.All)
            ClearQBit(QBit(716)) -- Retrieve the three paintings and return them to Ferdinand Visconti in Tatalia.
            AddValue(Experience, 50000)
            SetAward(Award(55)) -- Retrieved the complete set of paintings
            evt.SetNPCGreeting(628, 291) -- Ferdinand Visconti greeting 291
            evt.SetNPCTopic(628, 0, 0) -- Ferdinand Visconti topic 0 cleared
        end
    end
    evt.SimpleMessage("Remember, I need the complete set of paintings-- they aren't worth much by themselves.\nWhen you have the rest, bring them all to me.")
end)

RegisterGlobalEvent(1216, "Legacy event 1216", function()
    evt.SimpleMessage("To be declared ArcoMage Champion, you must win a game of ArcoMage in every tavern on, in, and under the continent of Erathia.\nThere are 13 such taverns sponsoring ArcoMage events.\nWhen you have accomplished this, return to me to claim the prize.")
    SetQBit(QBit(717)) -- Win a game of Arcomage in all thirteen taverns, then return to Gina Barnes in Erathia.
    evt.SetNPCTopic(629, 0, 1217) -- Gina Barnes topic 0: Quest
end)

RegisterGlobalEvent(1217, "Legacy event 1217", function()
    if not IsQBitSet(QBit(750)) then -- Won all Arcomage games
        evt.SimpleMessage("You must claim a victory at ALL 13 taverns.\nUntil you do, you cannot be declared ArcoMage Champion.")
        return
    end
    evt.SimpleMessage("Congratulations!")
    ClearQBit(QBit(717)) -- Win a game of Arcomage in all thirteen taverns, then return to Gina Barnes in Erathia.
    AddValue(Gold, 100000)
    SubtractValue(ReputationInCurrentLocation, 10)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 50000)
    SetQBit(QBit(756)) -- Finished ArcoMage Quest - Get the treasure
    SetAward(Award(1632))
    evt.SetNPCGreeting(629, 293) -- Gina Barnes greeting: Welcome ArcoMage Champions!
    evt.SetNPCTopic(629, 0, 0) -- Gina Barnes topic 0 cleared
end)

RegisterGlobalEvent(1218, "Legacy event 1218", function()
    evt.SimpleMessage("People say the Dwarves live in the barren lands south of Harmondale, but that's not exactly true--They live UNDER them.\nLook for their front gate in the center of the Barrow Downs where three bridges meet.")
end)

RegisterGlobalEvent(1219, "Legacy event 1219", function()
    evt.SimpleMessage("Ever since the Warlocks of Nighon tunneled through Stone City from their island, travelers have been asking to pass through the city to get to Nighon.\nThe Dwarf King hates this, and would like to charge a hefty fee for people seeking to enter Stone City.\nHe has not started charging however, fearing political and possible violent repercussions with the Warlocks of Nighon.")
end)

RegisterGlobalEvent(1220, "Legacy event 1220", function()
    evt.SimpleMessage("The Warlocks of Nighon live in Thunderfist Mountain--an extinct volcano on a large island a few miles from the mainland.\nDuring the recent wars, the Warlocks tunneled through Stone City to transport their forces across the channel.\nThose tunnels are still open and can be traversed.")
end)

RegisterGlobalEvent(1221, "Legacy event 1221", function()
    evt.SimpleMessage("During the War, the Warlocks tunneled from Nighon through Stone City to get to the mainland and seize territory.\nEven though they were pushed back to their island by Erathia, the tunnels remain.")
end)

RegisterGlobalEvent(1222, "Legacy event 1222", function()
    evt.SimpleMessage("Dwarves live under the ground of the Barrow Downs--a barren collection of ancient gravesites built by their race centuries ago to honor fallen kings and heroes.")
end)

RegisterGlobalEvent(1223, "Legacy event 1223", function()
    if not IsQBitSet(QBit(610)) then -- Built Castle to Level 2 (rescued dwarf guy)
        evt.SimpleMessage("We were making a fortune in the Red Dwarf Mines until the Medusas came!\nWe had to run before they turned everyone to stone.\nWithout our mining, we have almost no way to make a living.\nNot the way for a proper Dwarf to live, I say!")
        return
    end
    evt.SimpleMessage("The Lords of Harmondale!\nHeroes, I say!\nMy cousin was one of the ones you rescued!\nWe are in your debt!")
end)

RegisterGlobalEvent(1224, "Legacy event 1224", function()
    if not IsQBitSet(QBit(610)) then -- Built Castle to Level 2 (rescued dwarf guy)
        evt.SimpleMessage("Bracada leased the land where we started the Red Dwarf Mine to us a few years ago.")
        return
    end
    evt.SimpleMessage("Thank you for delivering our people from the medusas!")
end)

RegisterGlobalEvent(1225, "Legacy event 1225", function()
    if not IsQBitSet(QBit(610)) then -- Built Castle to Level 2 (rescued dwarf guy)
        evt.SimpleMessage("When the Medusas took the Red Dwarf Mines from us, not everyone escaped.\nThere are still several statues in the mines.\nThey can be rescued if their statues haven't been broken yet, but you would have to fight through the Medusas to do it.")
        return
    end
    evt.SimpleMessage("We owe you much for your daring rescue of our people.")
end)

RegisterGlobalEvent(1226, "Legacy event 1226", function()
    evt.SimpleMessage("Do you like our city?\nIt's not just a hole in the ground--it's a home in the ground!\nDwarves have been working this mountain for centuries!\nThere isn't much mining left here, though, and what there is happens to be in unstable and unsafe tunnels.\nBe careful if you go to the lower levels.")
end)

RegisterGlobalEvent(1227, "Legacy event 1227", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("Good day, my lords.\nI must say the people are changing their minds about your chances of survival.\nEveryone is saying how wonderful it is to have stable rulers in the Castle!")
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("Good day, my lords.\nI must say the people are changing their minds about your chances of survival.\nEveryone is saying how wonderful it is to have stable rulers in the Castle!")
    else
        evt.SimpleMessage("Respectfully, my lords, I must say that no one expects you to last long because no other lords of Harmondale have lasted long.\nThe fighting and politics between Erathia and Avlee will claim you sooner or later.\nProbably sooner.")
        return
    end
end)

RegisterGlobalEvent(1228, "Legacy event 1228", function()
    evt.SimpleMessage("Rebellions here in Harmondale are rare, but we've had a couple of big ones!\nMost of the time lords here don't last long enough to rebel against, but there've been some wicked ones!\nNot that I think you're wicked, my lords.")
end)

RegisterGlobalEvent(1229, "Legacy event 1229", function()
    if not IsQBitSet(QBit(610)) then -- Built Castle to Level 2 (rescued dwarf guy)
        evt.SimpleMessage("It's good to see someone in Harmondale again, my lords.\nThe castle's been standing empty since the War, except for the goblins.\nBut they don't count, I suppose.")
        return
    end
    evt.SimpleMessage("It's good to see the Castle rebuilt and those loathsome goblin bandits evicted.")
end)

RegisterGlobalEvent(1230, "Legacy event 1230", function()
    evt.SimpleMessage("What with all the wars that Avlee gets itself into all the time, and all the high taxes, I've moved to Harmondale to stay.\nHarmondale sees a lot of violence, but at least they don't conscript.\nYou know, there's been so many wars in Avlee that one of the kings had a tunnel dug from his castle to the caves in the North just in case the castle was taken AGAIN.")
end)

RegisterGlobalEvent(1231, "Legacy event 1231", function()
    evt.SimpleMessage("A ways outside of Harmondale there's a cave system that's always been the home of bandits, monsters, and other ne'er-do-wells.\nThey're called the White Cliff Caves.\nIf you're ever robbed, or are looking for some evil doers to punish, all you got to do is go up there.\nYou'll find a fight for sure!")
end)

RegisterGlobalEvent(1232, "Legacy event 1232", function()
    if not IsQBitSet(QBit(595)) then -- Gave false Loren to Catherine (betray)
        evt.SimpleMessage("Did you notice that covered bridge on the way from Harmondale to Steadwick?\nIt's called Fort Riverstride, and it protects us from surprise Elvish attacks coming through Harmondale.\nThere's so many traps and tricks inside there, they say it will never fall without the help of treachery.\n")
        return
    end
    evt.SimpleMessage("I've heard Fort Riverstride was taken with the aid of treachery!")
end)

RegisterGlobalEvent(1233, "Legacy event 1233", function()
    if IsQBitSet(QBit(596)) then -- Gave artifact to humans
        evt.SimpleMessage("Looks like the trophy fell into the hands of Erathia.")
        return
    elseif IsQBitSet(QBit(597)) then -- Gave artifact to elves
        evt.SimpleMessage("Looks like the trophy fell into the hands of Avlee.")
        return
    elseif IsQBitSet(QBit(659)) then -- Gave artifact to arbiter
        evt.SimpleMessage("Looks like the trophy fell into the hands of the Arbiter.")
    else
        evt.SimpleMessage("There's an artifact that Avlee and Erathia have been fighting over for decades.\nBoth claim it was made by their people, and have lost the thing to raids against one another many times.\nIt isn't even magical--just a trophy.\nFifteen years ago, the trophy was lost during a raid, and no one knows where it went.\nRecently, rumors have been flying, and the hunt's been on to figure out where it went.\nIf they find it--watch out!\nBlood will be spilt. ")
        return
    end
end)
