    if IsQBitSet(QBit(610)) then -- Built Castle to Level 2 (rescued dwarf guy)
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(1234, "Legacy event 1234", function()
    if not IsQBitSet(QBit(646)) then -- Arbiter Messenger only happens once
        evt.SimpleMessage("Because of all the tension in the air, Erathia and Avlee hired an arbiter to help them work out their differences.\nHe's staying in the \"House of Stars\" on the eastern edge of Harmondale territory.\nMaybe he has some advice for you.")
        return
    end
    evt.SimpleMessage("The death of Judge Grey was a blow to all of us.")
end)
RegisterCanShowTopic(1234, function()
    evt._BeginCanShowTopic(1234)
    local visible = true
    if IsQBitSet(QBit(610)) then -- Built Castle to Level 2 (rescued dwarf guy)
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(1235, "Legacy event 1235", function()
    evt.SimpleMessage("If you ever feel like you need advice on what next to do, or you've lost something important, go visit the Arbiter in the House of Stars near the Eastern edge of Harmondale territory.\nHe often knows where lost items went, or has advice on what you need to do.\nI'm sure you'll find him helpful.")
end)

RegisterGlobalEvent(1236, "Legacy event 1236", function()
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        evt.SimpleMessage("It looks like the consequences of your choice are just beginning, my lords.\nI hope you chose wisely.")
    elseif IsQBitSet(QBit(612)) then -- Chose the path of Dark
        evt.SimpleMessage("It looks like the consequences of your choice are just beginning, my lords.\nI hope you chose wisely.")
    else
        evt.SimpleMessage("The death of Judge Grey, Arbiter of Harmondale, has put the War on hold.\nIt's like the whole world is holding its breath, waiting for you to make a choice.\nBetter be careful who you choose--this sounds like a big one, my Lords.")
        return
    end
end)
RegisterCanShowTopic(1236, function()
    evt._BeginCanShowTopic(1236)
    local visible = true
    if IsQBitSet(QBit(646)) then -- Arbiter Messenger only happens once
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(1237, "Legacy event 1237", function()
    evt.SimpleMessage("The proving grounds, called the Walls of Mist,\nis the place where all the wizards in Celeste have to go before they learn the High Art.\nI hear it is much more of a moral test than a physical one.\nYou aren't allowed to kill any of the monsters in the maze.")
end)

RegisterGlobalEvent(1238, "Legacy event 1238", function()
    evt.SimpleMessage("The city of Celeste has been home to the Light for centuries.\nIt was established by King Magnus II\nin 499 as the centerpiece to the Kingdom of Bracada, and as a beacon of hope to the rest of the world.\n")
end)

RegisterGlobalEvent(1239, "Legacy event 1239", function()
    evt.SimpleMessage("What you see on the surface in Deyja is only a small part of the true Kingdom of Death.")
end)

RegisterGlobalEvent(1240, "Legacy event 1240", function()
    evt.SimpleMessage("Celeste is the magical city built by the Wizards of Bracada centuries ago, and anchored half in the mountains, and half in mist high above Bracada.\nYou must use one of their teleporters to get there--you can find it near the center of Bracada.")
end)

RegisterGlobalEvent(1241, "Legacy event 1241", function()
    if not IsQBitSet(QBit(619)) then -- Slayed the vampire
        evt.SimpleMessage("There was another murder, recently, that's been all the talk around town.\nAnother body--young woman, so I hear--was found near the sewers.\nDrained of blood, for the love of Light!\nIt's those thieves living' in the sewers I tell you!\nRats, they are.\nSomeone should go down there and put them out of business!")
        return
    end
    evt.SimpleMessage("So it was a vampire that was killing all those people!\nI hear you're the ones to get rid of it, too!\nThanks!\nEveryone feels much safer now.")
end)
RegisterCanShowTopic(1241, function()
