        return visible
    end
end)

RegisterGlobalEvent(1242, "Legacy event 1242", function()
    evt.SimpleMessage("During the War, the Warlocks had dealings with some strange creatures called the \"Kreegan\" in the mountains south of Avlee.\nIt's impossible to get there from the mainland, but the Warlocks dug a tunnel under the sea from their island that leads to the Kreegan's home.")
end)

RegisterGlobalEvent(1243, "Legacy event 1243", function()
    evt.SimpleMessage("We…overplayed our hand during the War, and failed to win any territory on the mainland.\nOur \"allies\", the Kreegan, turned out to be very untrustworthy.\nPeople from Enroth call them devils--now we know why.\nAt just the moment when we needed them most, they turned and ran, leaving us to face the wrath of the armies of Erathia and Avlee.\nNext time, we won't be so trusting.")
end)

RegisterGlobalEvent(1244, "Legacy event 1244", function()
    evt.SimpleMessage("There's been quite a bit of activity in Deyja, people are saying.\nIt seems that Archibald Ironfist, the leader of Deyja (and former King of Enroth) has left the Pit for an island off the Eastern shore of Avlee.\nA lot of Necromancers followed him there--seems there's some sort of split going on.")
end)
RegisterCanShowTopic(1244, function()
    evt._BeginCanShowTopic(1244)
    local visible = true
    if IsQBitSet(QBit(710)) then -- Archibald in Clankers Lab now
        visible = true
        return visible
    else
        visible = false
        return visible
    end
end)

RegisterGlobalEvent(1245, "Legacy event 1245", function()
    if not IsQBitSet(QBit(752)) then -- Talked to Roland
        evt.SimpleMessage("Rumors have been trickling out of Nighon that King Roland of Enroth may still be alive.")
        return
    end
    evt.SimpleMessage("They say you are being credited with rescuing King Roland!\nThat's quite a feather in your cap, my lords!\nQUITE a feather!")
end)
RegisterCanShowTopic(1245, function()
    evt._BeginCanShowTopic(1245)
    local visible = true
    if IsQBitSet(QBit(611)) then -- Chose the path of Light
        return visible
    else
        if IsQBitSet(QBit(612)) then -- Chose the path of Dark
            return visible
        else
            visible = false
            return visible
        end
    end
end)

RegisterGlobalEvent(1246, "Legacy event 1246", function()
    evt.SimpleMessage("A Soul Jar is what a Necromancer needs to complete the Ritual and become a Lich--an immortal undead monster that retains its mind and memories from life.\nIt's pretty obvious that this is not a desirable condition for most people, which is why the market for these artifacts isn't very good.\nNonetheless, Necromancers will do almost anything to get more--their profession's very existence depends on them.")
end)

RegisterGlobalEvent(1247, "Legacy event 1247", function()
    evt.SimpleMessage("Although the Warlocks are technically servants of the Dark, they usually aren't violent.\nThey will defend themselves if attacked, of course, but they won't start a fight unless you start it first.\nThey're quite reasonable, as a matter of fact, and they take their business seriously.\nI've found dealing with them to be quite pleasant.")
end)

RegisterGlobalEvent(1248, "Legacy event 1248", function()
    if not IsQBitSet(QBit(637)) then -- Destroy the magical defenses inside Clanker's Laboratory and return to Dark Shade in the Pit.
        evt.SimpleMessage("The underground complex Clanker has created is surprisingly well defended.\nThe front door will keep out all magical attacks, and the island makes it difficult for any sort of large force to land on the island.\nSo far, Clanker has kept to himself, and no one has seriously tried his defenses, but his best protection comes from a series of teleport blockers inside the complex.\nNo magical invasion force can teleport past the front door until those blockers are brought down first.")
        return
    end
    evt.SimpleMessage("So much for the mighty defenses.\nWord is the Necromancers, led by Archibald Ironfist, teleported straight into Clanker's Laboratory and took over.\nI'm told that treachery from within had something to do with it, though.")
end)
