RegisterGlobalEvent(1249, "Legacy event 1249", function()
    evt.SimpleMessage("Looking for Expert instruction in one of your Skills?\nExpert teachers for most Skills can be found in Harmondale, Erathia and the Tularean Forest. ")
end)

RegisterGlobalEvent(1250, "Legacy event 1250", function()
    evt.SimpleMessage("People have been disappearing recently.\nNot just one or two, but several every day!\nThey go to bed at night, and the next day they aren't seen and their houses are empty!\nI certainly wish someone would find out what it happening!")
end)

RegisterGlobalEvent(1251, "Legacy event 1251", function()
    evt.SimpleMessage("The teleporters of central Bracada can get you to numerous locations in the desert.\nJust check the pillar in front of the teleporter for the location it will take you to.\nBe careful however, some of the teleporters haven't been working correctly and will not show the destination!")
end)

RegisterGlobalEvent(1252, "Legacy event 1252", function()
    if HasAward(Award(28)) then -- Completed Necromancer Breeding Pit
        evt.SimpleMessage("My Lords!\nLord Archibald sent engineers and artisans to upgrade Castle Harmondale!\nNow we have an upstairs and downstairs!\nLord Archibald also left gifts in chests in these new areas.\nThe artisans are setting up shop in the entry hall and will have many wonderful items for sale!\nOh, yes, the workers discovered an older area to the castle--a torture chamber and dungeon!\nWe are very lucky!\nI never thought Harmondale could afford such luxuries, my lords!")
        return
    elseif HasAward(Award(6)) then -- Completed Wizard Proving Grounds
        evt.SimpleMessage("My Lords!\nGavin Magnus sent engineers and artisans to upgrade Castle Harmondale!\nNow we have an upstairs and downstairs!\nGavin Magnus also left gifts in chests in these new areas.\nThe artisans are setting up shop in the entry hall and will have many wonderful items for sale!\nThe workers, however, discovered an older area to the castle--a torture chamber and dungeon.\nIt isn't a pretty sight, I'm afraid.")
    else
        evt.SimpleMessage("My Lords. Castle Harmondale stands ready.")
        return
    end
end)
