RegisterGlobalEvent(1253, "Legacy event 1253", function()
    evt.SimpleMessage("Pedestals can be found through out the land that can lend you temporary protection from certain types of magic. ")
end)

RegisterGlobalEvent(1254, "Legacy event 1254", function()
    evt.SimpleMessage("My Lords ::bows:: Now that you have cleared Castle Harmondale of the goblins and vermin, you should concentrate on removing the goblins from the area surrounding Harmondale.\nTo the east of here is the center of the disputed region.\nMany great battles have been waged there between the forces of King Eldrich of the Elves and Queen Catherine of Erathia.\nThe goblins have taken the ruined fort in this area an use it to attack any travelers attempting to reach Harmondale!")
