RegisterGlobalEvent(1312, "Legacy event 1312", function()
    evt.SimpleMessage("I have heard rumors that the shrine to the southeast of here can send you to the Land of the Giants.\nI have been to the shrine many times and it has never done anything special for me.\nOr is that you can get here, FROM the Land of the Giants? I wonder...")
