RegisterGlobalEvent(1314, "Legacy event 1314", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2125) then -- The Letter
        evt.SimpleMessage("My instructions are quite clear.\nI am to pay the person carrying the letter that bears the Seal.\nSince you don't have a letter with a Seal, you get no money!")
        return
    end
    evt.SimpleMessage("Oh!\nThe Seal.\nHere, I'm supposed to give you this money.\nNow, go away before we're seen together!\nSomeone will get suspicious.")
    evt.ForPlayer(Players.Current)
