RegisterGlobalEvent(1316, "Legacy event 1316", function()
    evt.SimpleMessage("Just south of town is an old keep called Goblinwatch.\nIt was originally built to help keep the town safe from goblin raids, but times have been so peaceful recently that we haven't been taking care of it.\nYou can imagine our embarrassment when we realized that the very monsters we were guarding against have moved into the keep!\nThey also changed the lock on a very important door leading to the caves below the dungeon level.\nWe have a standing reward of 2000 gold pieces to the ones who can figure out the combination and tell us what it is.")
    evt.SetNPCTopic(1076, 0, 1317) -- Janice topic 0: Goblinwatch
    SetQBit(QBit(1107)) -- Find the Combination to the vault door in Goblinwatch and return to the Town Hall in New Sorpigal. - Set by Town Hall
    AddValue(InventoryItem(2109), 2109) -- Key to Goblinwatch
end)

RegisterGlobalEvent(1317, "Legacy event 1317", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2163) then -- Goblinwatch Code
        evt.SimpleMessage("How can you find the combination to that lock by standing around here?")
        return
    end
    evt.SimpleMessage("Ah, thank you for taking care of that little detail for us.\nHere's your gold!\nFeel free to return to Goblinwatch any time to finish clearing out the rest of the monsters.\nWe can't pay you, but you can have anything you find there.\n")
    SetAward(Award(95)) -- Solved the Goblinwatch Combination
    AddValue(Experience, 2000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 2000)
    AddValue(131307, 2)
    ClearQBit(QBit(1107)) -- Find the Combination to the vault door in Goblinwatch and return to the Town Hall in New Sorpigal. - Set by Town Hall
    evt.SetNPCTopic(1076, 0, 1318) -- Janice topic 0: Evil Cults
    evt.MoveNPC(1081, 0) -- Urok -> removed
    evt.MoveNPC(828, 1463) -- Samson Tess -> House
end)

RegisterGlobalEvent(1318, "Legacy event 1318", function()
    evt.SimpleMessage("You did such a fine job with the Goblinwatch assignment that we would like to employ you again.\nA cult has moved into an old abandoned temple a few day's journey west of here.\nTo pay for their blasphemous activities, they've been robbing travelers using the road that leads to Castle Ironfist.\nWe've appealed to the regent to do something about these horrible cultists, but he says all his forces are occupied in the west, or some such nonsense.\nWe want it gone now, so we're willing to pay you 5000 gold pieces to get rid of them and bring us back the Chime of Harmony as proof you've done the deed.")
    evt.SetNPCTopic(1076, 0, 1319) -- Janice topic 0: Evil Cults
    SetQBit(QBit(1108)) -- Get the Chime of Harmony from the Temple of Baa and return to the New Sorpigal Town Hall. - Paul
end)

RegisterGlobalEvent(1319, "Legacy event 1319", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2095) then -- Chime of Harmony
        evt.SimpleMessage("Without the Chime of Harmony, I'm not authorized to pay the reward money.\n")
        return
    end
    evt.SimpleMessage("Good work!")
    RemoveItem(2095) -- Chime of Harmony
    AddValue(Experience, 10000)
    SetAward(Award(96)) -- Returned with the Chime of Harmony
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 5000)
    AddValue(131307, 2)
    ClearQBit(QBit(1108)) -- Get the Chime of Harmony from the Temple of Baa and return to the New Sorpigal Town Hall. - Paul
    evt.SetNPCTopic(1076, 0, 1320) -- Janice topic 0: Evil Cults
end)

RegisterGlobalEvent(1320, "Legacy event 1320", function()
    evt.SimpleMessage("The road to Ironfist is much safer thanks to you.")
