RegisterGlobalEvent(1322, "Legacy event 1322", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2125) then -- The Letter
        evt.SimpleMessage("Welcome, adventurers!\nDid you have something for me?\nI'm a very busy man, you know.\n")
        return
    end
    evt.SimpleMessage("Thank you so much for bringing me these letters! <Wilbur begins reading the letters> I’ve been so worried…I see… This is not good news…Oh, no.\nTraitors!\nTraitors and conspirators everywhere!\nI must organize an expedition at once! <Wilbur lowers his voice> I trust you will not speak to the prince about these letters– he is already too depressed and unhappy to hear more bad news.\nAnd now I must see to the organization of the expedition.\nHere is a bag of gold as a reward– you’ve earned it and my gratitude.\nNow, if only I could find someone to finish looking for Lord Kilburn…")
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 5000)
    evt.ForPlayer(Players.All)
    SetAward(Award(100)) -- Delivered 6th Letter to Wilbur Humphry
    RemoveItem(2125) -- The Letter
    ClearQBit(QBit(1205)) -- Quest item bits for seer
    ClearQBit(QBit(1106)) -- Bring Sulman's letter to Regent Wilbur Humphrey at Castle Ironfist. - Set by Andover after you show him the letter
    ClearQBit(QBit(1105)) -- Show Sulman's letter to Andover Potbello in New Sorpigal. - Set when the party starts
    AddValue(Experience, 3000)
    evt.SetNPCTopic(789, 0, 1323) -- Wilbur Humphrey topic 0: Lord Kilburn
end)

RegisterGlobalEvent(1323, "Legacy event 1323", function()
    evt.SimpleMessage("<Wilbur snaps his fingers> Say, you wouldn’t happen to be interested in taking care of a little detail for me, would you?\nLord Kilburn disappeared near Blackshire.\nFind out what you can and return to me with the information.\nIf it is true that he has been slain by devils, return his shield to me if at all possible.\nI will grant you my favor with the High Council, should you require it, and you can rest assured your compensation will be generous.")
    SetQBit(QBit(1110)) -- Find Lord Kilburn's Shield and return to Wilbur Humphrey in Castle Ironfist to report. - Paul
    evt.SetNPCTopic(789, 0, 1324) -- Wilbur Humphrey topic 0: Lord Kilburn
end)

RegisterGlobalEvent(1324, "Legacy event 1324", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2119) then -- Lord Kilburn's Shield
        evt.SimpleMessage("Hmm.\nNo luck finding the shield yet, eh?\nWell, do keep looking, will you?\nIt really is important that someone accounts for his whereabouts.")
        return
    end
    evt.SimpleMessage("Ah.\n‘Tis a sad day when so noble a Knight should fall to such foul monsters!\nYou have done a good thing, bringing his shield to me.\nI shall ensure that he and his men receive all the honors due them.\nI am in your debt, and you have my favor with the council.\nHere is your reward.")
    RemoveItem(2119) -- Lord Kilburn's Shield
    ClearQBit(QBit(1206)) -- Quest item bits for seer
    AddValue(Experience, 40000)
    SetAward(Award(57)) -- Retrieved Lord Kilburn's Shield
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 5000)
    AddValue(655595, 10)
    evt.SetNPCTopic(789, 0, 1325) -- Wilbur Humphrey topic 0: The High Council
    ClearQBit(QBit(1110)) -- Find Lord Kilburn's Shield and return to Wilbur Humphrey in Castle Ironfist to report. - Paul
    evt.ForPlayer(Players.All)
    if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
    if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
    if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
    if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
    if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
    if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
    if HasAward(Award(62)) then -- Ended Winter
        SetQBit(QBit(1191)) -- NPC
    end
end)

RegisterGlobalEvent(1325, "Legacy event 1325", function()
    if not HasAward(Award(63)) then -- Exposed the Traitor on the High Council
        evt.SimpleMessage("Well, you have my vote on the High Council.\nI trust you implicitly.\nI've sent a messenger instructing Slicker Silvertongue to vote for you on my behalf.\nNow I'm quite busy, and must attend to other duties.\nI'm sure you can take care of any problems and miscommunications that may arise in this matter.\nYes.\nQuite right.")
        return
    end
    evt.SimpleMessage("I cannot thank you enough for uncovering that horrible traitor and his crimes against the throne.\nI understand you are on a mission of some importance, so for Services Rendered to the Crown, it behooves me to offer you free use of the royal yacht for your travels.\nIt will take you as far as Hermit's Isle, if you need it to.\nOnce again, thank you!")
    evt.ForPlayer(Players.All)
    SetAward(Award(101)) -- Allowed to use the Royal Yacht
end)

RegisterGlobalEvent(1326, "Legacy event 1326", function()
    evt.SimpleMessage("I am the Foremost Paladin, and as such, I am the one charged with the promotion and keeping of the titles and responsibilities of paladinhood.\nThose paladins who wish to perform a quest for the official promotion to crusader must rescue a damsel in distress.\nThose of you who are not paladins will be awarded the title of honorary crusader, and all will be given a sizeable gold reward.\nReturn to me with said damsel and I will promote any paladins aiding in her rescue to the status of crusader.")
    SetQBit(QBit(1112)) -- Rescue a Damsel in Distress and return with her to Wilbur Humphrey in Castle Ironfist. - Paul
    evt.SetNPCTopic(789, 1, 1327) -- Wilbur Humphrey topic 1: Crusaders
end)

RegisterGlobalEvent(1327, "Legacy event 1327", function()
    if not IsQBitSet(QBit(1699)) then -- Replacement for NPCs ą11 ver. 6
        evt.SimpleMessage("I know there is a shortage of damsels in distress, but this quest is the traditional test.\nI really can’t bend the rules here.\nKeep looking– I’m sure you’ll find someone.\nIf it helps, I hear Melody Silver, daughter of the noble John Silver, is being held captive by ruffians on the Island of Mist.")
        return
    end
    evt.SimpleMessage("I have heard stories of the daring rescue, and I am delighted that you have returned with Miss Silver.\nI shall arrange to have her returned to her family at once.\nExemplary work!\nI hereby officially promote all paladins to the status of crusader, and all non-paladins to honorary crusaders!")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 26) then
            SetValue(ClassId, 27)
            SetQBit(QBit(1635)) -- Received Promotion to Crusader
        else
            SetQBit(QBit(1636)) -- Received Promotion to Honorary Crusader
        end
    end
    AddValue(Gold, 5000)
    ClearQBit(QBit(1699)) -- Replacement for NPCs ą11 ver. 6
    ClearQBit(QBit(1112)) -- Rescue a Damsel in Distress and return with her to Wilbur Humphrey in Castle Ironfist. - Paul
    AddValue(131307, 2)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 15000)
    evt.SetNPCTopic(789, 1, 1328) -- Wilbur Humphrey topic 1: Heroes
end)

RegisterGlobalEvent(1328, "Legacy event 1328", function()
    evt.SimpleMessage("Well, then!\nIt is a fine thing to be promoted to crusader, but even finer a thing to be promoted to hero.\nAs you may have guessed by now, the condition for hero status is to slay a dragon.\nI know this seems difficult, but tradition has its demands.\nWhat’s worse, you can’t slay just any dragon, but must slay a named dragon.\nYour task is to slay Longfang Witherhide and return with a claw or tooth as proof.\nFortunately, we know that Longfang lives in a cave in the mountains behind Castle Darkmoor.\nHe has slain at least twelve would-be heroes, so be careful!")
    SetQBit(QBit(1113)) -- Slay Longfang Witherhide in his cave near Castle Darkmoor and return to Wilbur Humphrey in Castle Ironfist. - Paul
    evt.SetNPCTopic(789, 1, 1329) -- Wilbur Humphrey topic 1: Heroes
end)

RegisterGlobalEvent(1329, "Legacy event 1329", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2075) then -- Dragon Claw
        evt.SimpleMessage("There is no use returning to me to talk about your quest.")
        return
    end
    evt.SimpleMessage("Well done!\nOne less horrible monster in the world is a good thing.\nI hereby officially promote all crusaders to heroes, and all honorary crusaders to the status of honorary hero! May you long continue to live up to the title!")
    AddValue(Experience, 30000)
    RemoveItem(2075) -- Dragon Claw
    ClearQBit(QBit(1209)) -- Quest item bits for seer
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 27) then
            SetValue(ClassId, 28)
            SetQBit(QBit(1637)) -- Received Promotion to Hero
        else
            SetQBit(QBit(1638)) -- Received Promotion to Honorary Hero
        end
    end
    AddValue(327915, 5)
    ClearQBit(QBit(1113)) -- Slay Longfang Witherhide in his cave near Castle Darkmoor and return to Wilbur Humphrey in Castle Ironfist. - Paul
    evt.SetNPCTopic(789, 1, 1330) -- Wilbur Humphrey topic 1: Heroes
end)

RegisterGlobalEvent(1330, "Legacy event 1330", function()
    evt.SimpleMessage("It is always good to speak with heroes of the realm!")
end)

RegisterGlobalEvent(1331, "Legacy event 1331", function()
    evt.SimpleMessage("The palace is deadly dull, and everyone tells me what to do.\nBeing royalty isn’t really worth much and no one will let me go outside the walls while my father is gone.\nI haven’t left the castle for months!\nAnyway, you people look pretty important.\nWhat if you helped me sneak out and stay with you for a couple of days?\nI can’t give you much in return yet, but I’ll owe you a favor.\nSomeday I’ll be able to repay you.\nI am the prince, after all!\nI’ll go out the secret door and meet you outside.")
    SetQBit(QBit(1114)) -- Entertain Nicolai. - Paul
    SetQBit(QBit(1700)) -- Replacement for NPCs ą13 ver. 6
    evt.SetNPCTopic(798, 0, 1332) -- Nicolai Ironfist topic 0: The Circus
end)

