    evt.SimpleMessage("We should go back to Castle Ironfist.")
end)

RegisterGlobalEvent(1337, "Legacy event 1337", function()
    evt.SimpleMessage("Thanks for bringing me home.")
end)

RegisterGlobalEvent(1338, "Legacy event 1338", function()
    evt.SimpleMessage("Everyone says that my Uncle Archibald wasn’t a very nice person, and that he almost usurped the throne from my father, but we defeated him.\nFather had Tanir turn him to stone and then locked him in the library.\nNobody’s been in there for years. ")
end)

RegisterGlobalEvent(1339, "Legacy event 1339", function()
    evt.SimpleMessage("You want to free Archibald?!\nIf the Oracle told you to do it, I guess we should, but he’ll be trouble once he’s loose, that’s for sure.\nI know where the bell is that turned him to stone, but I can’t open the family vault that it’s in without the Third Eye.\nIt’s one of three gems you need to put into the door of the vault in order to open it.\nI’ve got two of them– one in my father’s crown and one in his scepter, but my father hid the third one, and he didn’t tell me where it is.\nIf you could find it, I could open the vault and get the bell.")
    SetQBit(QBit(1120)) -- Find the Third Eye and bring it to Prince Nicolai in Castle Ironfist. - Walt
    evt.SetNPCTopic(798, 1, 1340) -- Nicolai Ironfist topic 1: Uncle Archibald
    evt.SetNPCTopic(793, 1, 0) -- Oracle topic 1 cleared
end)

RegisterGlobalEvent(1340, "Legacy event 1340", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2066) then -- The Third Eye
        evt.SimpleMessage("Without the Third Eye, I can’t get into the vault to get you the bell that will release Archibald.\nHe must have hidden it near the castle, because he used to just go right outside and fetch it whenever he needed to open the vault.")
        return
    end
    evt.SimpleMessage("You found the Third Eye!\nAll right, wait here– the bell should be in the vault.\n<Nicolai runs out of the throne room, returning a short while later> Ok, here it is! ")
    RemoveItem(2066) -- The Third Eye
    ClearQBit(QBit(1220)) -- Quest item bits for seer
    ClearQBit(QBit(1120)) -- Find the Third Eye and bring it to Prince Nicolai in Castle Ironfist. - Walt
    evt.ForPlayer(Players.Current)
    AddValue(InventoryItem(2081), 2081) -- Tanir's Bell
    SetQBit(QBit(1221)) -- Quest item bits for seer
    evt.SetNPCTopic(798, 1, 1341) -- Nicolai Ironfist topic 1: Uncle Archibald
end)

RegisterGlobalEvent(1341, "Legacy event 1341", function()
    evt.SimpleMessage("I hope you know what you're doing.")
end)

RegisterGlobalEvent(1343, "Legacy event 1343", function()
    if IsQBitSet(QBit(1201)) then return end -- NPC
    evt.SimpleMessage("Now wait just a minute Tanir, and I’ll make it worth your while to let me…Oh. <Archibald is silent for a long while> I guess I have you people to thank for releasing me from my prison of stone.\nThank you!\nYou say you need a spell that I've created?\n<reaching to the shelves and removing a library scroll> Well, as a reward, I’ll give you the Ritual of the Void.\nUse it in good health.\nNow, I’m sure you’re very busy, as am I…<Archibald waves his arms and fades away>")
    AddValue(InventoryItem(2164), 2164) -- Ritual of the Void
    ClearQBit(QBit(1221)) -- Quest item bits for seer
    SetQBit(QBit(1201)) -- NPC
    ClearQBit(QBit(1121)) -- Walt
    ClearQBit(QBit(1259)) -- Obtain Arcane Magic from Archibald in the Royal Library in Castle Ironfist - NPC
    SetQBit(QBit(1222)) -- Quest item bits for seer
    evt.ForPlayer(Players.All)
    SubtractValue(3277035, 50)
    AddValue(Experience, 50000)
    evt.MoveNPC(797, 0) -- Archibald Ironfist -> removed
end)

RegisterGlobalEvent(1344, "Legacy event 1344", function()
    evt.SimpleMessage("Thank you for rescuing me from the clutches of those ruffians!\nOh, I wish there was some way for me to reward you!")
    SetQBit(QBit(1699)) -- Replacement for NPCs ą11 ver. 6
    SetQBit(QBit(1151)) -- NPC
end)

RegisterGlobalEvent(1345, "Legacy event 1345", function()
    evt.SimpleMessage("Mine is the traditional duty to oversee the, um, less than upright business in the Kingdom.\nMy House has done this for centuries under the philosophy that such business will always exist and is better watched and regulated than not.\nRecently, a man styling himself the 'Prince of Thieves' has begun to usurp my authority in Free Haven.\nNot only does he challenge my authority, he cooperates with that loathsome new cult that’s sprung up recently…what’s it called?\nMoo, or Yak, or Bark…no…whatever.\nSome sort of animal sound.\nAnyway, my sources tell me that this cult plots to overthrow the King and assume power in Enroth.\nThis is a bad business, and needs to be stopped.\nYou can start by arresting the Prince of Thieves and returning him to me in chains.\nI will, of course, reward you richly.\n")
    SetQBit(QBit(1122)) -- Capture the Prince of Thieves and bring him to Lord Anthony Stone at Castle Stone. - NPC
    evt.SetNPCTopic(801, 0, 1346) -- Anthony Stone topic 0: The Prince of Thieves
end)

RegisterGlobalEvent(1346, "Legacy event 1346", function()
    if not IsQBitSet(QBit(1701)) then -- Replacement for NPCs ą17 ver. 6
        evt.SimpleMessage("I have no information on his whereabouts, so it will do you no good to talk to me about it.\nTry going to Free Haven and asking around.\nHe must have a hideout somewhere in or near that town.\n<Smiling> if you find where he’s living, be sure to check under the bed and in the closet– you’ll probably find him hiding under a pile of clothes.")
        return
    end
    ClearQBit(QBit(1122)) -- Capture the Prince of Thieves and bring him to Lord Anthony Stone at Castle Stone. - NPC
    evt.SimpleMessage("Ah!\nMy friends, you have returned with the package!\nWell done!\nHere is your reward money.\nYou have my full support at the council. <looking at the Prince> Welcome to my humble home, mighty Prince.\nI have a room prepared just for you.\nGuards!\nTake him away.")
    evt.SetNPCTopic(801, 0, 1347) -- Anthony Stone topic 0: The High Council
    AddValue(Gold, 10000)
    AddValue(655595, 10)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 30000)
    SetAward(Award(60)) -- Captured the Prince of Thieves
    ClearQBit(QBit(1701)) -- Replacement for NPCs ą17 ver. 6
    evt.SetNPCTopic(802, 0, 1347) -- The Prince of Thieves topic 0: The High Council
    evt.ForPlayer(Players.All)
    if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
    if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
    if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
    if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
    if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
    if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
    if HasAward(Award(62)) then -- Ended Winter
        SetQBit(QBit(1191)) -- NPC
    end
end)

RegisterGlobalEvent(1347, "Legacy event 1347", function()
    evt.SimpleMessage("Your work in capturing the Prince of Thieves has been quite beneficial to me.")
end)

RegisterGlobalEvent(1348, "Legacy event 1348", function()
    evt.SimpleMessage("In addition to my duties as overseer of unlicensed business, I am the High Priest of Enroth.\nIt is my job to promote clerics to priests, and if warranted, priests to priests of light.\nRight now, the rolls are full of priests, and I am unable to promote new ones without creating new positions.\nTo do so would be highly irregular, but if someone were to perform an extraordinary service for the kingdom, the promotion would be acceptable.\n<Rubbing his temples> Come to think of it, there is a service I need.\nA temple in Free Haven was destroyed by fire a few months ago.\nIf you could get it rebuilt, I would have a reason to promote any clerics among you to priest status.\nSince I really want this job done, I am even willing to promote non-priests to an honorary priest status, and I will pay you well for your service.\nYou’ll need to hire a stonecutter and a carpenter and show them the temple you want them to work on.")
    SetQBit(QBit(1129)) -- Hire a Stonecutter and a Carpenter, bring them to Temple Stone in Free Haven to repair the Temple, and then return to Lord Anthony Stone at Castle Stone. - NPC
    evt.SetNPCTopic(801, 1, 1349) -- Anthony Stone topic 1: Priests
end)

RegisterGlobalEvent(1349, "Legacy event 1349", function()
    if not IsQBitSet(QBit(1130)) then -- NPC
        evt.SimpleMessage("The temple I asked you to rebuild still stands in ruins.\nThe people are deprived of their rightful religious solace, and you return to me empty-handed.\nLeave here and complete your mission!\n")
        return
    end
    evt.SimpleMessage("Excellent work!\nThe temple has been rebuilt and the affront to the gods eased.\nFor this service, I am happy to promote all clerics to priests, and I grant honorary priest status to all non-clerics.\nCongratulations! ")
    ClearQBit(QBit(1129)) -- Hire a Stonecutter and a Carpenter, bring them to Temple Stone in Free Haven to repair the Temple, and then return to Lord Anthony Stone at Castle Stone. - NPC
    evt.SetNPCTopic(801, 1, 1350) -- Anthony Stone topic 1: High Priests
    AddValue(131307, 2)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 15000)
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 4) then
            SetValue(ClassId, 5)
            SetQBit(QBit(1647)) -- Received Promotion to Priest
        else
            SetQBit(QBit(1648)) -- Received Promotion to Honorary Priest
        end
    end
end)

RegisterGlobalEvent(1350, "Legacy event 1350", function()
    evt.SimpleMessage("It seems a bit quick to promote anyone to high priests, given that the promotion to priest has been so recent.\nWhy, many wait their entire lives to receive such a promotion, only to be granted it posthumously.\nHowever, an extraordinary service could possibly accelerate that promotion to, well, right now for instance… and I do have such a service in mind.\nThe heretical monks that live on the islands east of Free Haven have stolen our sacred chalice.\nRetrieve it from the monks and put it in the temple you rebuilt.\nThen return to me.")
    SetQBit(QBit(1131)) -- Take the Sacred Chalice from the monks in their island temple east of Free Haven, return it to Temple Stone in Free Haven, and then return to Lord Stone at Castle Stone. - NPC
    evt.SetNPCTopic(801, 1, 1351) -- Anthony Stone topic 1: High Priests
end)

RegisterGlobalEvent(1351, "Legacy event 1351", function()
    evt.ForPlayer(Players.All)
    if IsQBitSet(QBit(1132)) then -- NPC
        evt.SimpleMessage("You are successful!\nIt looks like I will have to keep my promise and make more irregular, early promotions.\nI do so with pleasure.\nI hereby promote all priests to high priests, and all honorary priests to honorary high priests.")
        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
            evt.ForPlayer(player)
            if IsAtLeast(ClassId, 5) then
                SetValue(ClassId, 6)
                SetQBit(QBit(1649)) -- Received Promotion to High Priest
            else
                SetQBit(QBit(1650)) -- Received Promotion to Honorary High Priest
            end
        end
        AddValue(327915, 5)
        ClearQBit(QBit(1131)) -- Take the Sacred Chalice from the monks in their island temple east of Free Haven, return it to Temple Stone in Free Haven, and then return to Lord Stone at Castle Stone. - NPC
        evt.ForPlayer(Players.All)
        AddValue(Experience, 30000)
        evt.SetNPCTopic(801, 1, 1352) -- Anthony Stone topic 1: High Priests
    elseif HasItem(2054) then -- Sacred Chalice
        evt.SimpleMessage("I see that you have recovered the chalice!\nGood work, but you still need to ensconce it in the temple.\nTake it there at once and return to me for your promotion!")
    else
        evt.SimpleMessage("The monks still have the chalice, and our temple is still without it.\nWhy do you delay?")
    end
end)

