RegisterGlobalEvent(1364, "Legacy event 1364", function()
    evt.SimpleMessage("I sometimes have the worst trouble trying to remember things I’ve learned.\nI’m not sure why this is, but I’ve discovered a way around the problem.\nI am going to create a mirror that will allow me to look back in time, so that I can remember what it is I’ve forgotten.\nTo do this, I need the Hourglass of Time, but my duties and research prevent me from searching for the hourglass on my own.\nThe hourglass is said to be in a dark cavern up near area… <pauses a moment>\nNo, that was the Spear of Darkness…\nwhere is the hourglass?\n<pauses again>\nI should be able to remember this.\n<snaps his fingers>\nOf course!\nIt’s buried in an old fort to the south of here.\nI can offer you my support in the council if you will help me in creating my mirror.")
    evt.SetNPCTopic(790, 0, 1365) -- Albert Newton topic 0: Council Quest
    SetQBit(QBit(1134)) -- Find and return the Hourglass of Time to Lord Albert Newton in Mist. - NPC
end)

RegisterGlobalEvent(1365, "Legacy event 1365", function()
    evt.ForPlayer(Players.All)
    if HasItem(2053) then -- Hourglass of Time
        evt.SimpleMessage("Now all I have to do is remember how to create the mirror.\nI wrote down all the important parts so I wouldn’t forget how to do it.\n<stops> Where did I put those notes?\n<ponders for a minute> I must have left them somewhere obvious, maybe in the laboratory.\nAnyway, your part in this is done, and again I thank you.\nYou will have my complete support in the council for this.\nWhat were your names again? ")
        AddValue(Experience, 50000)
        SetAward(Award(58)) -- Retrieved the Hourglass of Time
        RemoveItem(2053) -- Hourglass of Time
        ClearQBit(QBit(1207)) -- Quest item bits for seer
        evt.ForPlayer(Players.Current)
        AddValue(655595, 10)
        ClearQBit(QBit(1134)) -- Find and return the Hourglass of Time to Lord Albert Newton in Mist. - NPC
        evt.SetNPCTopic(790, 0, 1367) -- Albert Newton topic 0: Council Quest
        evt.ForPlayer(Players.All)
        if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
        if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
        if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
        if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
        if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
        if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
        if HasAward(Award(62)) then -- Ended Winter
            SetQBit(QBit(1191)) -- NPC
        end
        return
    elseif HasItem(2107) then -- Key to Gharik's Laboratory
        evt.SimpleMessage("The hourglass wasn’t there?\nOh, that’s right!\nI knew I forgot something!\nThe key is in there!\nYou use the key to open the Forge of… <pauses>\nWell, I can’t remember whose forge it is, but that is the resting place of the Hourglass of Time...I think.\nIt can’t hurt to look there, especially now that you’ve found the key.\n<pauses>\nAt least I THINK that’s what the key opens.\nAnyway, that forge or laboratory or whatever it is can be found on the islands north of New Sorpigal.\nGood Luck!")
    else
        evt.SimpleMessage("I’m still looking for the mirror. <pauses> I mean Hourglass… I keep getting those mixed up.\nDid you try the dark cavern– no wait, it was the old fort south of here.\nI always seem to mix those up.")
        return
    end
end)

