RegisterGlobalEvent(1368, "Legacy event 1368", function()
    SetQBit(QBit(1135)) -- Drink from the Fountain of Magic and return to Lord Albert Newton in Mist. - NPC
    evt.SetNPCTopic(790, 1, 1369) -- Albert Newton topic 1: Wizards
    evt.ForPlayer(Players.All)
    if not IsAtLeast(ClassId, 42) then
        evt.SimpleMessage("I am the magus responsible for\nthe promotion of sorcerers.\nThough none of you are sorcerers, I’m a fair man.\nIf you are able to locate the Fountain of Magic, I’ll grant you honorary wizard status.\nYou won’t receive any benefits of the wizards’ training, but you will gain more respect in the eyes of sorcerers and wizards.\n")
        return
    end
    evt.SimpleMessage("I am the magus in charge of training and promoting sorcerers.\nThough powerful, sorcerer is not the pinnacle of the elemental magician.\nWizards take the knowledge and ability of a sorcerer, and hone those abilities to a sharper level.\nThey have greater magical potential than the sorcerer, and demand greater respect.\nThe way to earn this training, however, is not easy.\nFind the Fountain of Magic, drink from its waters, and return here.\nIf you are able to do this, I will train you in the ways of the wizard.")
end)

RegisterGlobalEvent(1369, "Legacy event 1369", function()
    evt.SimpleMessage("Don’t ask me for hints, I’ve already forgotten where the Fountain is.\nI know this isn’t an easy task, but if it were not difficult, every sorcerer would already BE a wizard.")
end)

RegisterGlobalEvent(1371, "Legacy event 1371", function()
    evt.SimpleMessage("You have done well in finding the Fountain.\nIt’s location and powers are a secret, do not spread its location around.\nNow, let me show you the secrets of the wizard.")
    evt.ForPlayer(Players.All)
    AddValue(Experience, 15000)
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 42) then
            SetValue(ClassId, 43)
            SetQBit(QBit(1639)) -- Received Promotion to Wizard
        else
            SetQBit(QBit(1640)) -- Received Promotion to Honorary Wizard
        end
    end
    AddValue(131307, 2)
    ClearQBit(QBit(1135)) -- Drink from the Fountain of Magic and return to Lord Albert Newton in Mist. - NPC
    evt.SetNPCTopic(790, 1, 1372) -- Albert Newton topic 1: Master Wizards
end)

RegisterGlobalEvent(1372, "Legacy event 1372", function()
    evt.SimpleMessage("Your training does not end with what you have learned as a wizard, one final step remains.\nMaster wizard status completes your mastery of elemental magic.\nBuilding on your wizard training, master wizards have vast magical ability– the most efficient and skilled use of magic anywhere.\nEarning this training requires a powerful artifact, owned by the powerful Arch Mage Drael-.. no, it was Frundir-… no, that’s not right either.\nActually, I can’t seem to remember what the artifact was or who owned it.\nI'd remember it if I saw it, though.\nI know it can be found in Corlagon’s Estate near the Mire of the Damned.\nSearch for it there and return it; I must have it to train you to become a master wizard.")
    SetQBit(QBit(1136)) -- Retrieve the Crystal of Terrax and return to Lord Albert Newton in Mist. - NPC
    evt.SetNPCTopic(790, 1, 1373) -- Albert Newton topic 1: Master Wizards
end)

RegisterGlobalEvent(1373, "Legacy event 1373", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2077) then -- Crystal of Terrax
        evt.SimpleMessage("I’m sorry, but I still haven’t remembered exactly what it is you need.\nI know you need to search Corlagon’s Estate.\n ")
        return
    end
    evt.SimpleMessage("Great news!\nI remember what you need to find!\nThe Crystal of Terrax!\nOh, you seem to have found it already.\nWell, perfect!\nI can train you to master wizards, then.\nThe first arch mage, Terrax, used this Crystal to master the elements.\nFire, earth, water, and air all formed together to make it, and from analyzing it he learned a great deal about elemental magic.\nIn addition, its effect on light led him to his discoveries of light and dark magic.\nSince that time, the study of this crystal has guided every new master wizard.\nLet me show you the secrets of the crystal. ")
    AddValue(Experience, 30000)
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 43) then
            SetValue(ClassId, 46)
            SetQBit(QBit(1641)) -- Received Promotion to Archmage
        else
            SetQBit(QBit(1642)) -- Received Promotion to Honorary Archmage
        end
    end
    AddValue(327915, 5)
    ClearQBit(QBit(1136)) -- Retrieve the Crystal of Terrax and return to Lord Albert Newton in Mist. - NPC
    evt.ForPlayer(Players.All)
    RemoveItem(2077) -- Crystal of Terrax
    ClearQBit(QBit(1210)) -- Quest item bits for seer
    evt.SetNPCTopic(790, 1, 1353) -- Albert Newton topic 1: Arch Mages
end)

RegisterGlobalEvent(1374, "Legacy event 1374", function()
    evt.SimpleMessage("I don’t have much time to talk right now– I have a lot to do.\nI’m in the process of organizing a few campaigns to attack the devils along the western coast.\nYou must realize, as I do, that nothing in all of Enroth poses as much of a threat to our safety as they do.\nI only wish the other Lords would assist me by contributing supplies and troops, or just helping in the planning of these attacks.\nThey spend more time bickering amongst themselves over borders and laws and trade than in helping me deal with the REAL threat.\nThe devils have an advance post in Kriegspire near the Sentinels.\nFrom here, they are able to base small raids and gather intelligence on our forces.\nI need you to sneak in and attack it, find what information you can on the location of any devil strongholds and patrol patterns, and destroy the place.\nDo not let any of the devils escape!\nSurprise and secrecy are our greatest weapons.")
    SetQBit(QBit(1137)) -- Destroy the Devil's Outpost and return to Lord Osric Temper at Castle Temper. - NPC
    evt.SetNPCTopic(791, 0, 1375) -- Osric Temper topic 0: Council Quest
end)

RegisterGlobalEvent(1375, "Legacy event 1375", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2126) then -- Devil Plans
        evt.SimpleMessage("Did you fail in your mission?\nYou didn’t allow the demons to escape, did you?\nThat post MUST be destroyed for any large attack against them to be successful.\nAs long as that post exists, your mission still stands. ")
        return
    end
    evt.SimpleMessage("Good job!\nWith the information you’ve brought back, we now have the intelligence we need to stage an attack on the devils, and with that post out of the way, we can hit them when they won’t expect it. I give you my full support in the council– hopefully the council will actually DO something for once.")
    AddValue(Experience, 40000)
    SetAward(Award(59)) -- Destroyed the Devil's Post
    RemoveItem(2126) -- Devil Plans
    ClearQBit(QBit(1208)) -- Quest item bits for seer
    evt.ForPlayer(Players.Current)
    ClearQBit(QBit(1137)) -- Destroy the Devil's Outpost and return to Lord Osric Temper at Castle Temper. - NPC
    AddValue(655595, 10)
    evt.SetNPCTopic(791, 0, 1377) -- Osric Temper topic 0: Council Quest
    evt.ForPlayer(Players.All)
    if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
    if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
    if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
    if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
    if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
    if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
    if HasAward(Award(62)) then -- Ended Winter
        SetQBit(QBit(1191)) -- NPC
    end
end)

RegisterGlobalEvent(1377, "Legacy event 1377", function()
    evt.SimpleMessage("Excellent work in dispatching those devils!\nAgain, you have my thanks.\nMy support in the council is yours, at least until the threat of the devils is past.\nHopefully you can spur the council into action.\nBy the way, the information that you brought back has confirmed our suspicion about the enemy base.\nIt is definitely near the town of Sweet Water in Paradise Valley.")
end)

RegisterGlobalEvent(1378, "Legacy event 1378", function()
    SetQBit(QBit(1138)) -- Get Knight's nomination from Chadwick and return to Lord Osric Temper at Castle Temper. - NPC
    evt.SetNPCTopic(792, 0, 1379) -- Chadwick Blackpoole topic 0: Nomination
    evt.SetNPCTopic(791, 1, 1381) -- Osric Temper topic 1: Cavaliers
    evt.ForPlayer(Players.All)
    if not IsAtLeast(ClassId, 16) then
        evt.SimpleMessage("I am the Armsmaster in charge of the promotion of knights.\nUnfortunately, none of you are knights, and therefore the skills I would teach you would be worthless.\nHowever, if you so desire, you can attempt the task of a would-be cavalier.\nSeek the nomination of a person of authority, a cavalier, for example, and return to me.")
        return
    end
    evt.SimpleMessage("I am the Armsmaster in charge of the promotion of all knights in Enroth.\nWorthy knights can be promoted to cavaliers.\nCavaliers embody the spirit of action and the power of purpose.\nBehind their courageous example, armies charge into battle and enemies flee in terror. However, to become a cavalier, you need to be nominated by a person of authority.\nIf you could get the nomination of a cavalier, that would be good enough for me.\n ")
end)

RegisterGlobalEvent(1379, "Legacy event 1379", function()
    evt.SimpleMessage("Well there, you’re looking for a nomination to become cavaliers?\nI was once a valiant knight in my day.\nI fought with Roland in the Succession wars, though now I’m too old to do much good on the battlefield.\nIt’s good to see Osric keeping the traditions of the knights alive.\nTell him that I proudly nominate you to become cavaliers, and if he gives you any trouble tell him to come see me himself.")
    evt.SetNPCTopic(791, 1, 1382) -- Osric Temper topic 1: Cavaliers
    evt.SetNPCTopic(792, 0, 0) -- Chadwick Blackpoole topic 0 cleared
end)

