end)

RegisterGlobalEvent(1381, "Legacy event 1381", function()
    evt.SimpleMessage("Come now!\nA person of your fame and stature should have no problem being nominated.\nDon’t tell me your fame is contrived– are you sure you deserve to be as famous as you are?\n<laughs>\nI’m jesting, calm down.\nSeriously, I'd suggest looking in Free Haven or the village of Rockham.\nI've heard a few cavaliers frequent the taverns there.")
end)

RegisterGlobalEvent(1382, "Legacy event 1382", function()
    evt.SimpleMessage("Congratulations!\nThe nomination may not seem important, but we have a tradition that must be followed for this promotion.\nAs a cavalier, you need to understand that the traditions and values of the people need to be defended.\nI gladly promote you to the rank of cavalier!")
    ClearQBit(QBit(1138)) -- Get Knight's nomination from Chadwick and return to Lord Osric Temper at Castle Temper. - NPC
    AddValue(131307, 2)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 15000)
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 16) then
            SetValue(ClassId, 17)
            SetQBit(QBit(1643)) -- Received Promotion to Cavalier
        else
            SetQBit(QBit(1644)) -- Received Promotion to Honorary Cavalier
        end
    end
    evt.SetNPCTopic(791, 1, 1383) -- Osric Temper topic 1: Champions
    evt.SetNPCTopic(792, 0, 1380) -- Chadwick Blackpoole topic 0: Cavaliers
end)

RegisterGlobalEvent(1383, "Legacy event 1383", function()
    evt.SimpleMessage("Ah, worthy cavaliers, the final step in your training is to become a champion.\nA cavalier is a brave and noble warrior, but a champion is a power to behold.\nNo force can stand between the champion and victory.\nEntire campaigns are decided on the bravery, decisiveness, and powerful example of the champion.\nThe task to complete this promotion, however, is difficult.\nYou must defeat a powerful enemy to prove your ability and determination.\nThe only enemy worthy of this task is a man known only as the Warlord, a dangerous and powerful warrior.\nHe commands a legion of evil knights, normally based to the northeast of\nIcewind Pass.\nDefeat him, bring back proof of your victory, and your promotion to champion is assured.")
    SetQBit(QBit(1139)) -- Defeat the Warlord and bring proof to Osric Temper - NPC
    evt.SetNPCTopic(791, 1, 1384) -- Osric Temper topic 1: Champions
end)

RegisterGlobalEvent(1384, "Legacy event 1384", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2128) then -- Discharge Papers
        evt.SimpleMessage("You’re not scared of the Warlord, are you?\nHis terror needs to be put to an end.\nYou can’t become champion hiding underneath your bed or standing around looking at the walls– you need to go out and DO it!")
        return
    end
    evt.SimpleMessage("Good job!\nExcellent!\nI wasn’t sure you’d make it back alive.\nKergmond had more potential than I realized, but you’re certainly more than a match for an army of Kergmonds.\nYou’ve proven yourselves worthy of the rank of champion. You must not be afraid to take up arms to defend what is right.\nMay your enemies fear your approach and your allies rally behind your courage. And now, I promote you to the rank of champion! ")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 17) then
            SetValue(ClassId, 19)
            SetQBit(QBit(1645)) -- Received Promotion to Champion
        else
            SetQBit(QBit(1646)) -- Received Promotion to Honorary Champion
        end
    end
    AddValue(327915, 5)
    ClearQBit(QBit(1139)) -- Defeat the Warlord and bring proof to Osric Temper - NPC
    evt.ForPlayer(Players.All)
    AddValue(Experience, 40000)
    RemoveItem(2128) -- Discharge Papers
    ClearQBit(QBit(1211)) -- Quest item bits for seer
    evt.SetNPCTopic(791, 1, 1385) -- Osric Temper topic 1: Champions
end)

RegisterGlobalEvent(1385, "Legacy event 1385", function()
    evt.SimpleMessage("Well met, champions!\nPlease, don’t waste your valuable time or mine in times like this.\nUse your skills for the good of Enroth and leave me to my planning!\nWhen this battle is over, THEN we can share tales of valor and skill.")
end)

RegisterGlobalEvent(1386, "Legacy event 1386", function()
    evt.SimpleMessage("Memory Crystal Alpha – Hermit’s Isle.Memory Crystal Beta – Alamos.Memory Crystal Delta – Darkmoor.Memory Crystal Epsilon – Kriegspire.")
    if IsQBitSet(QBit(1186)) then return end -- Find Memory Crystal Alpha in the Supreme Temple of Baa and restore it to a module altar at the Oracle beneath the High Council.. - NPC
    SetQBit(QBit(1186)) -- Find Memory Crystal Alpha in the Supreme Temple of Baa and restore it to a module altar at the Oracle beneath the High Council.. - NPC
    SetQBit(QBit(1187)) -- Find Memory Crystal Beta in Castle Alamos and restore it to a module altar at the Oracle beneath the High Council. - NPC
    SetQBit(QBit(1188)) -- Find Memory Crystal Delta in Castle Darkmoor and restore it to a module altar at the Oracle beneath the High Council. - NPC
    SetQBit(QBit(1189)) -- Find Memory Crystal Epsilon in Castle Kriegspire and restore it to a module altar at the Oracle beneath the High Council. - NPC
end)

RegisterGlobalEvent(1387, "Legacy event 1387", function()
    evt.SimpleMessage("Place the memory Crystals into the modules above.")
end)

RegisterGlobalEvent(1389, "Legacy event 1389", function()
    evt.ForPlayer(Players.All)
    if IsQBitSet(QBit(1190)) then -- Retrieve the Control Cube from the Tomb of Varn in Dragonsand and return to the Oracle beneath the High Council. - NPC
        if HasItem(2076) then -- Control Cube
            AddValue(Experience, 500000)
            SetAward(Award(76)) -- Gained Access to the Control Center
            ClearQBit(QBit(1190)) -- Retrieve the Control Cube from the Tomb of Varn in Dragonsand and return to the Oracle beneath the High Council. - NPC
            RemoveItem(2076) -- Control Cube
            ClearQBit(QBit(1219)) -- Quest item bits for seer
            evt.SetNPCTopic(793, 0, 1390) -- Oracle topic 0: Kreegan
            evt.SetNPCTopic(793, 1, 1391) -- Oracle topic 1: Ancients
            evt.SimpleMessage("You now have access to the Control Center.\nSimply ask to be transported and I will oblige.\nOne warning however– the guardians of the Control Center are no longer under my control, so please exercise caution while visiting the Center.")
        end
        evt.SimpleMessage("I am Melian, Guardian of Enroth.\nThank you for replacing my memory modules.\nArchibald took them from here when I refused to give him any help in his battle for succession.\nYour timing is impeccable.\nThe Kreegan have invaded our world, and you must try and stop them.\nUnfortunately, Archibald’s attempts at extracting information from me have damaged me enough that I cannot help you directly now.\nInstead, I can only give you advice.While most of the Kreegan can be slain with ordinary weapons and spells, the elite guards and upper echelon breeders have tougher skin and natural defenses that protect them from anything but very powerful weapons.\nIn the planetary control center beneath me are the weapons and armor you will need to survive battle with the enemy.\nMy orders, however, will only permit passage to someone with a Control Cube.\nMy instruments tell me that the only Control Cube left in Enroth can be found somewhere underground in Dragonsand.\n")
        return
    end
    SetAward(Award(75)) -- Awakened the Oracle
    SetQBit(QBit(1190)) -- Retrieve the Control Cube from the Tomb of Varn in Dragonsand and return to the Oracle beneath the High Council. - NPC
    ClearQBit(QBit(1186)) -- Find Memory Crystal Alpha in the Supreme Temple of Baa and restore it to a module altar at the Oracle beneath the High Council.. - NPC
    ClearQBit(QBit(1187)) -- Find Memory Crystal Beta in Castle Alamos and restore it to a module altar at the Oracle beneath the High Council. - NPC
    ClearQBit(QBit(1188)) -- Find Memory Crystal Delta in Castle Darkmoor and restore it to a module altar at the Oracle beneath the High Council. - NPC
    ClearQBit(QBit(1189)) -- Find Memory Crystal Epsilon in Castle Kriegspire and restore it to a module altar at the Oracle beneath the High Council. - NPC
    evt.SimpleMessage("I am Melian, Guardian of Enroth.\nThank you for replacing my memory modules.\nArchibald took them from here when I refused to give him any help in his battle for succession.\nYour timing is impeccable.\nThe Kreegan have invaded our world, and you must try and stop them.\nUnfortunately, Archibald’s attempts at extracting information from me have damaged me enough that I cannot help you directly now.\nInstead, I can only give you advice.While most of the Kreegan can be slain with ordinary weapons and spells, the elite guards and upper echelon breeders have tougher skin and natural defenses that protect them from anything but very powerful weapons.\nIn the planetary control center beneath me are the weapons and armor you will need to survive battle with the enemy.\nMy orders, however, will only permit passage to someone with a Control Cube.\nMy instruments tell me that the only Control Cube left in Enroth can be found somewhere underground in Dragonsand.\n")
end)

RegisterGlobalEvent(1390, "Legacy event 1390", function()
    if IsQBitSet(QBit(1329)) then -- NPC
        evt.SimpleMessage("As I said, the Kreegan are resistant to most of the weapons available in Enroth, but not all.\nTo rid the world of them, you will need to find where their vessel crashed and destroy the main reactor.\nThe only problem is that the resulting explosions from the reactor will destroy this planet.\nYou will need a powerful spell to prevent the explosion from damaging the planet, but no spell like that exists in the world today.\nThe only person I can think of that would know of such a spell is Archibald, but he is in no condition to teach you.\nTo make matters worse, the reactor cannot be harmed by normal weapons or spells– you will need the ancient weapons in the Control Center to destroy the reactor.")
    elseif IsQBitSet(QBit(1120)) then -- Find the Third Eye and bring it to Prince Nicolai in Castle Ironfist. - Walt
        evt.SimpleMessage("As I said, the Kreegan are resistant to most of the weapons available in Enroth, but not all.\nTo rid the world of them, you will need to find where their vessel crashed and destroy the main reactor.\nThe only problem is that the resulting explosions from the reactor will destroy this planet.\nYou will need a powerful spell to prevent the explosion from damaging the planet, but no spell like that exists in the world today.\nThe only person I can think of that would know of such a spell is Archibald, but he is in no condition to teach you.\nTo make matters worse, the reactor cannot be harmed by normal weapons or spells– you will need the ancient weapons in the Control Center to destroy the reactor.")
    else
        SetQBit(QBit(1259)) -- Obtain Arcane Magic from Archibald in the Royal Library in Castle Ironfist - NPC
        evt.SetNPCTopic(798, 1, 1339) -- Nicolai Ironfist topic 1: The Third Eye
        SetQBit(QBit(1193)) -- NPC
        evt.SimpleMessage("As I said, the Kreegan are resistant to most of the weapons available in Enroth, but not all.\nTo rid the world of them, you will need to find where their vessel crashed and destroy the main reactor.\nThe only problem is that the resulting explosions from the reactor will destroy this planet.\nYou will need a powerful spell to prevent the explosion from damaging the planet, but no spell like that exists in the world today.\nThe only person I can think of that would know of such a spell is Archibald, but he is in no condition to teach you.\nTo make matters worse, the reactor cannot be harmed by normal weapons or spells– you will need the ancient weapons in the Control Center to destroy the reactor.")
    end
end)

RegisterGlobalEvent(1391, "Legacy event 1391", function()
    evt.SimpleMessage("Though my memory has been damaged by Archibald, I can still remember the danger that our ancient enemy, the Kreegan, pose to our world.\nThe Kreegan first appeared roughly 1500 years ago, attacking outlying colonies and stealing their resources.\nIt was thought at the time they simply needed certain minerals, and could be reasoned with, but this was not the case.\nTheir life cycle forces them to breed until the world cannot support their numbers, then they send ships off to other worlds to renew the cycle.\nTheir attacks against the empire of the Ancients disrupted the network of shipping and communications that held us all together, causing the Silence that marks the first year of our modern calendar.\nWithout support from the homeworlds, our fledgling technology failed, bringing us to this sorry state.\nI would help rebuild our technology, but I seem to have become a religious figure in the minds of many people, and very few visit me or understand what I have to offer.\nPerhaps this Kreegan crisis we face will bring people to their senses--as long as we survive it.")
end)

RegisterGlobalEvent(1392, "Legacy event 1392", function()
    evt.SimpleMessage("I happen to know that you are amongst a short list of adventurers looking to receive favor from the High Council.\nWhat you want it for I don’t know, nor do I care.\nI’ll be blunt:\nI love money, and I want more.\nMuch more.\nI have a plan to fix the price of shipping in my favor for a time and I need competent agents to carry it out.\nPerform this task well and I will give you my support, not to mention a lot of money.\nHere is the plan:\nEach of the nine shipping companies in the Kingdom must be convinced to charge at least 48 gold per pound per mile of material they transport.\nThey are all in competition and they know it, so none will want to make a move before the others.\nI don’t care how you convince them– just get the job done and report back to me.")
    SetQBit(QBit(1140)) -- Fix the prices of all 9 stables in the Kingdom and return to Lady Fleise in Silver Cove. - NPC
    SetQBit(QBit(1706)) -- Replacement for NeedToTestIt ą0 ver. 6
    evt.SetNPCTopic(799, 0, 1393) -- Loretta Fleise topic 0: Money
end)

RegisterGlobalEvent(1393, "Legacy event 1393", function()
    if not IsQBitSet(QBit(1141)) then -- NPC
        evt.SimpleMessage("Not all of the companies have agreed to raise their prices!\nWhy do you return only to report incompetence?\nThere are large profits I could be reaping if you had done your job and convinced these idiots to raise their prices!\nMUST I DO THIS MYSELF?\nShould I send someone else?\nWhy do I surround myself with MORONS?!\nSo far I have lost a lot of gold because you haven’t finished your job!\nI’ll deduct these losses from your final payment, you can be sure of that!")
        return
    end
    evt.SimpleMessage("At last!\nThought you would never finish.\nMaybe you’re good for something after all.\nYou have won my support in the council, and of course, your payment. ")
    if not IsQBitSet(QBit(1707)) then -- Replacement for NeedToTestIt ą31 ver. 6
        AddValue(Gold, 25000)
        ClearQBit(QBit(1140)) -- Fix the prices of all 9 stables in the Kingdom and return to Lady Fleise in Silver Cove. - NPC
        SubtractValue(655595, 10)
        evt.ForPlayer(Players.All)
        SetAward(Award(61)) -- Fixed the Stable Prices
        AddValue(Experience, 25000)
        evt.SetNPCTopic(799, 0, 1394) -- Loretta Fleise topic 0: Money
        evt.ForPlayer(Players.All)
        if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
        if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
        if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
        if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
        if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
        if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
        if HasAward(Award(62)) then -- Ended Winter
            SetQBit(QBit(1191)) -- NPC
        end
        return
    end
    AddValue(Gold, 5000)
    ClearQBit(QBit(1140)) -- Fix the prices of all 9 stables in the Kingdom and return to Lady Fleise in Silver Cove. - NPC
    SubtractValue(655595, 10)
    evt.ForPlayer(Players.All)
    SetAward(Award(61)) -- Fixed the Stable Prices
    AddValue(Experience, 25000)
    evt.SetNPCTopic(799, 0, 1394) -- Loretta Fleise topic 0: Money
    evt.ForPlayer(Players.All)
    if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
    if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
    if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
    if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
    if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
    if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
    if HasAward(Award(62)) then -- Ended Winter
        SetQBit(QBit(1191)) -- NPC
    end
end)

RegisterGlobalEvent(1394, "Legacy event 1394", function()
    evt.SimpleMessage("If you're concerned about the suffering of the peasants over my price increase, don't be.\nI did it all for a good cause.\nI needed to raise money for granaries to store the excess grain we are harvesting this year.\nThe shipping prices are back down, and the availability of cheap, high quality grain more than makes up for it.\nThere!\nI'm not so horrible, am I?")
end)

RegisterGlobalEvent(1395, "Legacy event 1395", function()
    evt.SimpleMessage("Although it may be hard to believe, I happen to be one of the top druids in the land.\nAs such I am empowered to promote druids to great and arch druid status, provided they prove themselves worthy.\nTo be promoted to great druid status, you must perform the Ceremony of the Sun.\nPray at the center of the Circle of Stone during any equinox or solstice– March 20th, June 21st, September 23rd, or December 21st.\nIf you are there at that time, I will contact you magically and lead you through the Ceremony, thus promoting you to great druid.\nThose among you who are not druids will be granted honorary great druid status, and I am sure the experience will be worthwhile.")
    SetQBit(QBit(1142)) -- Visit the Altar of the Sun in the circle of stones north of Silver Cove on an equinox or solstice (HINT: March 20th is an equinox). - NPC
    evt.SetNPCTopic(799, 1, 1396) -- Loretta Fleise topic 1: Great Druids
end)

RegisterGlobalEvent(1396, "Legacy event 1396", function()
    evt.SimpleMessage("You must pray at the center of the Circle of Stone during an equinox or solstice to complete the Ceremony of the Sun and be promoted to great druid.")
end)

RegisterGlobalEvent(1397, "Legacy event 1397", function()
    evt.SimpleMessage("So, you believe you are deserving of the title of arch druid.\nYou must complete the Ceremony of the Moon to achieve arch druid status.\nThis used to be rather easy before the factional split amongst the last generation of druids, but now you must fight your way to the sacred altar.\nIt is in the Temple of the Moon, currently controlled by the evil heretic Cedric Druthers.\nThere is no way they will just let you complete the ceremony peacefully, so you will probably have to fight your way in.\nLike the Ceremony of the Sun, the Ceremony of the Moon must be performed at a certain place and time.\nPray at the Altar of the Moon in the Temple of the Moon at midnight during any full moon.\nIf you are there at that time, I will contact you magically and lead you through the Ceremony.")
    SetQBit(QBit(1143)) -- Visit the Altar of the Moon in the Temple of the Moon at midnight of a full moon. - NPC
    evt.SetNPCTopic(1090, 1, 1398) -- Loretta Fleise topic 1: Arch Druids
end)

RegisterGlobalEvent(1398, "Legacy event 1398", function()
    evt.SimpleMessage("You must be standing before the altar of the Moon at midnight on any full moon to complete the Ceremony of the Moon and be promoted to arch druid.")
end)

RegisterGlobalEvent(1399, "Legacy event 1399", function()
    evt.SimpleMessage("The earth is wounded in the west.\nI can feel it, my fellow druids, and if you put your hand to the ground and listen with your heart, you'll feel it, too.\nI am bound here with my responsibilities, but I urge you to investigate the source of this pain.\nI am sure the wound and the Night of Shooting Stars are related.\n")
end)

RegisterGlobalEvent(1400, "Legacy event 1400", function()
    evt.SimpleMessage("I grow tired of winter.\nIn my lands, winter seems to last year round.\nAs a matter of fact, for the last few years, summer didn’t arrive at all.\nI have come to believe that something is wrong with the weather, and I want something done about it.\nI know your reputation, and I hear you can do anything.\nI have a deal for you.\nEnd the winter in my land and I will give you my support in the High Council when it comes time for you to ask for it.\nIf it's any help at all, I hear there is hermit on a mountaintop somewhere west of here who has studied the weather in detail.")
    SetQBit(QBit(1144)) -- End winter for Lord Stromgard at Castle Stromgard, and return to him with the good news. - NPC
    evt.SetNPCTopic(800, 0, 1401) -- Erik Von Stromgard topic 0: Winter
    evt.SetNPCTopic(804, 0, 1409) -- The Hermit on the Mountain topic 0: Winter
end)

RegisterGlobalEvent(1401, "Legacy event 1401", function()
    evt.SimpleMessage("Do you think you could hurry this miracle thing along?\nThe snow on the ground is building up, and we are going to have to start putting buildings on stilts!")
end)

RegisterGlobalEvent(1402, "Legacy event 1402", function()
    evt.SimpleMessage("I was looking out my window when the weather broke and the snow vanished!")
    ClearQBit(QBit(1144)) -- End winter for Lord Stromgard at Castle Stromgard, and return to him with the good news. - NPC
    SetQBit(QBit(1199)) -- NPC
    AddValue(655595, 10)
    evt.SetNPCTopic(800, 0, 1403) -- Erik Von Stromgard topic 0: Winter
    evt.ForPlayer(Players.All)
    SetAward(Award(62)) -- Ended Winter
    AddValue(Experience, 50000)
    evt.ForPlayer(Players.All)
    if not HasAward(Award(63)) then return end -- Exposed the Traitor on the High Council
    if not HasAward(Award(57)) then return end -- Retrieved Lord Kilburn's Shield
    if not HasAward(Award(58)) then return end -- Retrieved the Hourglass of Time
    if not HasAward(Award(59)) then return end -- Destroyed the Devil's Post
    if not HasAward(Award(60)) then return end -- Captured the Prince of Thieves
    if not HasAward(Award(61)) then return end -- Fixed the Stable Prices
    if HasAward(Award(62)) then -- Ended Winter
        SetQBit(QBit(1191)) -- NPC
    end
end)

RegisterGlobalEvent(1403, "Legacy event 1403", function()
    evt.SimpleMessage("For your services, I grant you my favor in the High Council!\nLong may you live, O enemies of Winter!")
end)

RegisterGlobalEvent(1404, "Legacy event 1404", function()
    evt.SimpleMessage("20 years ago, I won the annual archery competition held at Castle Ironfist, and I have held the championship ever since.\nThis gives me the right to promote archers to the title of warrior mage and master archer as I see fit.\nI’ll grant the title of warrior mage to all the archers amongst you if you do me a little favor. I need the key to the old Dragon Towers set up near every major settlement in Enroth to shoot down flying creatures.\nI think that they can be set to shoot down only monsters, instead of shooting anything flying through the air. Since this is something of a pet project, I will reward honorary warrior mage status to the rest of you.\nThe key is in my old keep near the southern entrance to my lands.\nI had to leave it there when the ogres and their companions took it from me a few years ago.\nReturn with that key and be rewarded.\nAnd I won’t be crying in my beer if you kill a lot of those monsters while you’re at it.\nThey took my keep!")
    SetQBit(QBit(1145)) -- Retrieve the key to the Dragon Towers from Icewind Keep south of Whitecap, and bring it to Lord Stromgard at Castle Stromgard. - NPC
    evt.SetNPCTopic(800, 1, 1405) -- Erik Von Stromgard topic 1: Warrior Mages
end)

RegisterGlobalEvent(1405, "Legacy event 1405", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2106) then -- Dragon Tower Keys
        evt.SimpleMessage("No key—No reward.")
        return
    end
    evt.SimpleMessage("Very good!\nYou got the key, and hopefully slew a large number of those loathsome beasts.\nI hereby promote all archers to the status of warrior mage, and all non-archers to honorary warrior mage.")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 0) then
            SetValue(ClassId, 1)
            SetQBit(QBit(1655)) -- Received Promotion to Battle Mage
        else
            SetQBit(QBit(1656)) -- Received Promotion to Honorary Battle Mage
        end
    end
    ClearQBit(QBit(1145)) -- Retrieve the key to the Dragon Towers from Icewind Keep south of Whitecap, and bring it to Lord Stromgard at Castle Stromgard. - NPC
    AddValue(131307, 2)
    evt.ForPlayer(Players.All)
    AddValue(Experience, 15000)
    evt.SetNPCTopic(800, 1, 1406) -- Erik Von Stromgard topic 1: Master Archers
end)

RegisterGlobalEvent(1406, "Legacy event 1406", function()
    evt.SimpleMessage("The reason I wanted the key was to open the Dragon Towers and make the adjustments to prevent them from shooting flyers indiscriminately.\nThere is a way to adjust the towers to shoot at only large objects, and I want all of them adjusted for the good of the Kingdom.\nMagic is becoming more common, as are stories of young Sorcerers getting shot from the sky because they didn’t know the function of the towers.\nYou have the key.\nIf you adjust all of the towers to shoot at only large objects, I will promote all warrior mages amongst you to master archers and promote any honorary warrior mages to honorary master archers.")
    SetQBit(QBit(1146)) -- Reset all of the Dragon Towers at each town and return to Lord Stromgard in Castle Stromgard. - NPC
    evt.SetNPCTopic(800, 1, 1413) -- Erik Von Stromgard topic 1: Master Archers
end)

RegisterGlobalEvent(1407, "Legacy event 1407", function()
    evt.SimpleMessage("Welcome, master archers!\nYou may warm yourself by my hearth any time!")
end)

RegisterGlobalEvent(1408, "Legacy event 1408", function()
    evt.SimpleMessage("I like it up here.\nIt’s as though I can watch the world turn from up high and all alone.\nSerene.\nUntouchable.\nAlmost…Prophetic.\nI can see the clouds churn and travel, break apart and mix together.\nI can predict the weather almost perfectly.\n<Smiling> Right now, I predict more snow.")
end)

RegisterGlobalEvent(1409, "Legacy event 1409", function()
    evt.SimpleMessage("So, Stromgard needs a miracle with the weather, eh?\nAll this time I thought he was the one responsible for making it snow continually.\nI can break the enchantment on the weather easily, and if you hurry back to him, I’m sure you can claim responsibility.")
    SetQBit(QBit(1252)) -- NPC
    evt.SetNPCTopic(800, 0, 1402) -- Erik Von Stromgard topic 0: Winter
    evt.SetNPCTopic(804, 0, 1410) -- The Hermit on the Mountain topic 0: Winter
end)

RegisterGlobalEvent(1410, "Legacy event 1410", function()
    evt.SimpleMessage("As grateful as I am for your company, I am, in fact, a hermit.\nI'm sure you have plenty of important things to do and don't need to be cluttering up my house any longer.")
end)

RegisterGlobalEvent(1411, "Legacy event 1411", function()
    evt.SimpleMessage("Curses!")
end)

RegisterGlobalEvent(1413, "Legacy event 1413", function()
    if IsQBitSet(QBit(1180)) then -- NPC
        if IsQBitSet(QBit(1181)) then -- NPC
            if IsQBitSet(QBit(1182)) then -- NPC
                if IsQBitSet(QBit(1183)) then -- NPC
                    if IsQBitSet(QBit(1184)) then -- NPC
                        if not IsQBitSet(QBit(1185)) then -- NPC
                            evt.SimpleMessage("Hmm.\nNot all of the towers have been reset.\nThey are easy to find, if a bit long in getting to.\nThe easiest is in Whitecap to the west of us.")
                            return
                        end
                        evt.SimpleMessage("I knew my faith in you was well placed!\nYou have fixed a major problem in our kingdom, not to mention doing yourself a favor—It’s now safe to fly above towns.\nIt is my pleasure to promote all warrior mages to master archers, and all honorary warrior mages to honorary master archers.\n")
                        AddValue(327915, 5)
                        ClearQBit(QBit(1146)) -- Reset all of the Dragon Towers at each town and return to Lord Stromgard in Castle Stromgard. - NPC
                        evt.ForPlayer(Players.All)
                        AddValue(Experience, 40000)
                        for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
                            evt.ForPlayer(player)
                            if IsAtLeast(ClassId, 1) then
                                SetValue(ClassId, 2)
                                SetQBit(QBit(1657)) -- Received Promotion to Warrior Mage
                            else
                                SetQBit(QBit(1658)) -- Received Promotion to Honorary Warrior Mage
                            end
                        end
                        evt.SetNPCTopic(800, 1, 1407) -- Erik Von Stromgard topic 1: Master Archers
                    end
                end
            end
        end
    end
    evt.SimpleMessage("Hmm.\nNot all of the towers have been reset.\nThey are easy to find, if a bit long in getting to.\nThe easiest is in Whitecap to the west of us.")
end)

RegisterGlobalEvent(1414, "Legacy event 1414", function()
    evt.SimpleMessage("Slicker Silvertongue refused my order?\nThis must be treason!\nStill, I've known him so long, and he's never disobeyed an order before…perhaps he is suffering from delusions.\nYes, that's it.\nHe's been spending so much time investigating that horrible Baa cult that it's affected his mind– I even found one of their cloaks in his room.\nPerhaps you can find a cure for him.\nThey must surely know what they've done to him!\nI would start at their headquarters east of Castle Kriegspire.\nHere, take the cloak– perhaps you can find some use for it.")
    SetQBit(QBit(1224)) -- Find a cure for Slicker Silvertongue in the Superior Temple of Baa east of Castle Kriegspire and return to Wilbur Humphrey with the good news. - Wilbur Humphrey
    AddValue(InventoryItem(2105), 2105) -- Cloak of Baa
    evt.SetNPCTopic(789, 0, 1415) -- Wilbur Humphrey topic 0: Silvertongue's Cure
end)

RegisterGlobalEvent(1415, "Legacy event 1415", function()
    evt.ForPlayer(Players.All)
    if HasItem(2122) then -- Letter from Zenofex
        evt.SimpleMessage("Oh, my!\nIt appears that Slicker Silvertongue really is a traitor!\nWho ever would have guessed it?\nYou've done a good thing, bringing this letter to me.\nTake it to High Council immediately so we can be rid of this wicked traitor for once and for all!")
        ClearQBit(QBit(1224)) -- Find a cure for Slicker Silvertongue in the Superior Temple of Baa east of Castle Kriegspire and return to Wilbur Humphrey with the good news. - Wilbur Humphrey
        SetQBit(QBit(1225)) -- Bring the the letter detailing Silvertongue's treason to the High Council in Free Haven. - NPC
    elseif HasItem(2105) then -- Cloak of Baa
        evt.SimpleMessage("Please hurry in your quest to find Slicker Silvertongue's cure!")
        return
    else
        evt.ForPlayer(Players.Current)
        AddValue(InventoryItem(2105), 2105) -- Cloak of Baa
        evt.SimpleMessage("Please hurry in your quest to find Slicker Silvertongue's cure!")
        return
    end
end)

RegisterGlobalEvent(1416, "Legacy event 1416", function()
    evt.SimpleMessage("I cannot thank you enough for uncovering that horrible traitor and his crimes against the throne.\nI understand you are on a mission of some importance, so for Services Rendered to the Crown, it behooves me to offer you free use of the royal yacht for your travels.\nIt will take you as far as Hermit's Isle, if you need it to.\nOnce again, thank you!")
end)

RegisterGlobalEvent(1417, "Legacy event 1417", function()
    evt.SimpleMessage("Welcome to the Circus of the Sun!\nWe have a variety of games for your amusement.\nYou can take the prizes you win from the various games and trade them in here for either kegs of wine or golden pyramids.\nYou need at least 10 points to get a keg of wine, and 30 or more points will win you a golden pyramid.\nIn case you didn't know, each lodestone is worth 1 point, each harpy feather is worth 3 points, and each four leaf clover is worth 5 points.\n")
end)

