RegisterGlobalEvent(1435, "Legacy event 1435", function()
    evt.SimpleMessage("As you may know, the last members of the Necromancers' Guild in Enroth fled to Castle Darkmoor after their defeat in the Succession War.\nWho knows what foul magics they're concocting while we wait around.\nI'm certain that the book containing the Ritual of Endless Night, known as the Book of Liches, has been moved into that castle.\nIf the book were to be destroyed, it would deal a severe blow to whatever evil plans they have.\nI've tried a few times to get to the book, but the castle is too well defended.\nIf you are able to destroy the book, come back to me and I'll reward you personally.")
    SetQBit(QBit(1228)) -- Find and destroy the Book of Liches in Castle Darkmoor and return to Terry Ros in Darkmoor village. - NPC
    evt.SetNPCTopic(1115, 0, 1436) -- Terry Ros topic 0: Quest
end)

RegisterGlobalEvent(1436, "Legacy event 1436", function()
    evt.ForPlayer(Players.All)
    if not IsQBitSet(QBit(1033)) then -- 9, CD2, given when you destroy Lich book
        evt.SimpleMessage("There's no rush in destroying the book.\nIf you manage it, come back and talk to me.\nI'm not sure it's even possible to get to the book and destroy it– there are far too many evil creatures in that castle.")
        return
    end
    evt.SimpleMessage("Incredible!\nI didn't expect you'd be able to do it.\nNow that the Book of Liches is gone, the Necromancers' Guild here in Enroth will slowly fade away.\nThis is all thanks to you!\nHere, take this as a reward and accept my gratitude as well.")
    SetAward(Award(102)) -- Destroyed the Book of Liches
    AddValue(Experience, 50000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 5000)
    AddValue(327915, 5)
    ClearQBit(QBit(1228)) -- Find and destroy the Book of Liches in Castle Darkmoor and return to Terry Ros in Darkmoor village. - NPC
    evt.SetNPCTopic(1115, 0, 0) -- Terry Ros topic 0 cleared
    evt.MoveNPC(1115, 0) -- Terry Ros -> removed
end)

