RegisterGlobalEvent(1573, "Legacy event 1573", function()
    evt.SimpleMessage("The best staff teacher in the land, Jasper Rice, lives up near Silver Cove.\nYou'll want to talk to him if you wish to continue your training with the staff.")
end)

RegisterGlobalEvent(1574, "Legacy event 1574", function()
    evt.SimpleMessage("Guy Hampton in Blackshire taught me everything I know about the sword.\nIf you're looking to master the blade, he's the one to train under.")
end)

RegisterGlobalEvent(1575, "Legacy event 1575", function()
    evt.SimpleMessage("I'm only a novice when compared to someone like Jules Miles.\nHe lives near Castle Stone, and he can teach anyone how to improve their dagger skills.")
end)

RegisterGlobalEvent(1576, "Legacy event 1576", function()
    evt.SimpleMessage("Avinril Smythers mastered the axe before most of us were even born, but he doesn't train humans.\nI'm sure if you could do something special for him, he might consider teaching a human how to really swing an axe.\nHe spends most of his time in the Haunt in the Mire of the Damned.")
end)

RegisterGlobalEvent(1577, "Legacy event 1577", function()
    evt.SimpleMessage("The best spearman in Enroth, Burton Rutherford, lives in Darkmoor.\nI'm not sure why he picks such a remote place to call his home.\nMaybe he doesn't like being bothered with students?")
end)

RegisterGlobalEvent(1578, "Legacy event 1578", function()
