RegisterGlobalEvent(1596, "Legacy event 1596", function()
    evt.SimpleMessage("If you think I'm good at repairing things, Ryan Treacle is the best around.\nI'm sure he can be convinced to assist you in mastering the skill.\nHe lives up near Castle Stone the last I heard.")
end)

RegisterGlobalEvent(1597, "Legacy event 1597", function()
    evt.SimpleMessage("Jason Traveler will coach you in the finest points of body-building.\nHe works in Free Haven, if you can handle his rigorous training.")
end)

RegisterGlobalEvent(1598, "Legacy event 1598", function()
    evt.SimpleMessage("If mastering meditation is your goal, you'll need to see Norio Ariganaka in Mist.")
end)

RegisterGlobalEvent(1599, "Legacy event 1599", function()
    evt.SimpleMessage("Perception can be mastered with help from Macro Caligula in Darkmoor.")
end)

RegisterGlobalEvent(1600, "Legacy event 1600", function()
    evt.SimpleMessage("Jacques Kohl is working with Lord Stromgard to develop experimental recipes.\nIf he has time, perhaps he can assist you as well in mastering the art of Alchemy.")
end)

RegisterGlobalEvent(1601, "Legacy event 1601", function()
    evt.SimpleMessage("The greatest trap disarmer, Gabe Lester, is currently teaching his craft near Castle Stone.\nHe's the person to talk to if you want to learn all the best tricks.")
end)

RegisterGlobalEvent(1602, "Legacy event 1602", function()
    evt.SimpleMessage("John Tuck can teach you to master the learning skill.")
end)

RegisterGlobalEvent(1603, "Legacy event 1603", function()
    evt.SimpleMessage("The King of the Dwarves, Snergle, usurped Rocklin for leadership of the dwarven clans.\nNow Rocklin is in exile somewhere and Snergle is in charge.\nMost dwarves don’t like Snergle and would like to see Rocklin back in power.\nUnfortunately, Snergle has claimed both Rocklin’s caverns and the largest dwarven Iron Mine.\nSnergle, fearing treachery near home, has removed me, the Dwarven Weaponmaster, from my position.\nWe need someone to get Snergle out of power by any means necessary.\nI’d even consider training you humans how to use an axe like a true dwarf if you’ll help us.")
    SetQBit(QBit(1148)) -- Kill Snergle in Snergle's Caverns and return with his axe to Avinril Smythers at The Haunt tavern in the Mire of the Damned. - NPC
    evt.SetNPCTopic(817, 0, 1604) -- Avinril Smythers  topic 0: Quest
end)

RegisterGlobalEvent(1604, "Legacy event 1604", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2118) then -- Snergle's Axe
        evt.SimpleMessage("I need proof that Snergle has been defeated.\nI’m sorry, but I just can’t take your word for it.\nBring back some personal item of his, like his axe maybe.")
        return
    end
    evt.SimpleMessage("Oh, glorious day!\nWith Snergle’s passing, we can now search for Rocklin to put him back in power.\nEternal thanks to you for this, and dwarves everywhere owe you a debt of gratitude.")
    SetAward(Award(79)) -- Killed Snergle
    AddValue(Experience, 20000)
    evt.ForPlayer(Players.Current)
    SetQBit(QBit(1051)) -- 27 D05, Given when axe is returned (so door can't be opened)
    ClearQBit(QBit(1148)) -- Kill Snergle in Snergle's Caverns and return with his axe to Avinril Smythers at The Haunt tavern in the Mire of the Damned. - NPC
    AddValue(327915, 5)
    evt.SetNPCTopic(817, 0, 1520) -- Avinril Smythers  topic 0: Master Axe Fighting
end)

RegisterGlobalEvent(1605, "Legacy event 1605", function()
    evt.SimpleMessage("The Mayor here in Mist is considering allowing the Fraternal Order of Silver to police the town in their battle against evil.\nI know the Silver Helm Persecution Squads have murdered innocents in their misguided crusade against ‘evil,’ but there are no living witnesses to their atrocities.\nI need you to storm their outpost to the south of here to find proof so that I can convince the mayor to ban them from Mist.")
    SetQBit(QBit(1149)) -- Storm the Silver Helm Outpost near Mist and return with evidence of their corruption to the Constable of Mist. - NPC
    evt.SetNPCTopic(822, 0, 1606) -- Charles D'Sorpigal topic 0: Quest
end)

RegisterGlobalEvent(1606, "Legacy event 1606", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2123) then -- Enemies List
        evt.SimpleMessage("Keep searching– the lives of the mayor and myself could very well be in your hands.")
        return
    end
    evt.SimpleMessage("Just as I suspected!\nI’m surprised the Mayor was number three on their enemies list.\nI suppose he IS a tad incompetent, but he’s not a bad person.\nThanks again, please accept this gold and my gratitude as your reward.")
    RemoveItem(2123) -- Enemies List
    SetAward(Award(80)) -- Saved the Mayor of Mist
    AddValue(Experience, 15000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 3000)
    AddValue(131307, 2)
    ClearQBit(QBit(1149)) -- Storm the Silver Helm Outpost near Mist and return with evidence of their corruption to the Constable of Mist. - NPC
    evt.SetNPCTopic(822, 0, 0) -- Charles D'Sorpigal topic 0 cleared
    evt.SetNPCTopic(831, 0, 1608) -- Bertrand Scrivner topic 0: Silver Helms
end)

RegisterGlobalEvent(1607, "Legacy event 1607", function()
    evt.SimpleMessage("I think I might just allow the Fraternal Order of Silver to police the areas around Mist.")
end)

RegisterGlobalEvent(1608, "Legacy event 1608", function()
    evt.SimpleMessage("I can’t believe those Silver Helms wanted to kill me!\nI’ve never done anything wrong in my life!\nWell, nothing more wrong than any other mayor at least.\nThank you again for stopping them.")
end)

RegisterGlobalEvent(1609, "Legacy event 1609", function()
    evt.SimpleMessage("Could you do the Temple of Baa a favor?\nIt appears that my brethren left the old temple to the northwest of here in a little too much of a hurry, and a candelabra necessary for some of our rituals was left behind.\nNone of the Baa priests want to go back because they’re afraid of whatever curse has been placed on the temple.\nIf you were to bring back the candelabra to me, however, I could reward you in their place.")
    SetQBit(QBit(1150)) -- Retrieve the candelabra from the Abandoned Temple for Andover Potbello in New Sorpigal. - NPC
    evt.SetNPCTopic(786, 1, 1610) -- Andover Potbello topic 1: Quest
end)

RegisterGlobalEvent(1610, "Legacy event 1610", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2069) then -- Candelabra
        evt.SimpleMessage("Did the curse frighten you away as well?\nI can understand.\nBaa is patient, however.\nShould you work up the courage to find the candelabra, I’m still prepared to compensate you for it.")
        return
    end
    evt.SimpleMessage("Excellent!")
    RemoveItem(2069) -- Candelabra
    SetAward(Award(81)) -- Retrieved the Baa Candelabra
    AddValue(Experience, 2000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 1000)
    SubtractValue(655595, 10)
    ClearQBit(QBit(1150)) -- Retrieve the candelabra from the Abandoned Temple for Andover Potbello in New Sorpigal. - NPC
    evt.SetNPCTopic(786, 1, 0) -- Andover Potbello topic 1 cleared
end)

RegisterGlobalEvent(1611, "Legacy event 1611", function()
    evt.SimpleMessage("Who would have thought that the evil I sought to fight all across Enroth would be found so close to my own home?\nGerrard Blackames was once my second in command.\nNot long before he murdered me he began corresponding with the Temple of Baa, and they began to feed him targets for our Order.\nI ended up being one of the targets, and Gerrard took control of the Order.\nNow, the Silver Helms are as evil as the people they hunt.\nI’m certain the Temple of Baa is responsible for the corruption of our Order.\nAt the same time, Gerrard’s brother, Marcus the Sorcerer, has been supplying the Silver Helms with high quality equipment.\nThe last I heard, Marcus was assisting someone in a forge on an island to the southeast.")
end)

RegisterGlobalEvent(1612, "Legacy event 1612", function()
    if not IsQBitSet(QBit(1151)) then -- NPC
        evt.SimpleMessage("My niece, Melody, has been kidnapped from her home in Mist and locked in a Silver Helm outpost near there.\nShe’s one of the few people who know that I’ve been murdered.\nI’m sure Gerrard has her locked up for that reason, but I believe he wants to force her into marriage to eliminate any opposition to his leadership of the Fraternal Order of Silver.")
        return
    end
    evt.SimpleMessage("Thank you for saving my niece.")
end)

RegisterGlobalEvent(1613, "Legacy event 1613", function()
    evt.SimpleMessage("Gerrard has an ankh inscribed with his name given to him by the priests of Baa.\nI’m not sure exactly what the ankh is used for, but he may use it to identify himself as a friend of Baa.")
    evt.SetNPCTopic(799, 2, 1675) -- Loretta Fleise topic 2: Ankh
    evt.SetNPCTopic(801, 2, 1676) -- Anthony Stone topic 2: Ankh
end)

RegisterGlobalEvent(1614, "Legacy event 1614", function()
    evt.SimpleMessage("You want to defeat Snergle, do you?\nWell, he knows how he stands among most dwarves.\nHe’s holed up in Rocklin’s old caverns surrounded by a horde of his loyal dwarves.\nIf anything were to happen in there, he’d just immediately lock himself in his private room and let his followers handle it.\nYou’ll need a key to get into his room; there’s no way you’ll bash down a high quality dwarven door.\nI was a steward for Rocklin– I know that room well and I happen to still have a key to it hidden on me.\nFortunately for you, I’m in this cell because of Snergle, and there’s nothing I’d rather see than his reign put to a quick end.\nHere’s the key– think of it as payment for letting me out of this cell.")
    evt.MoveNPC(851, 0) -- Ghim Hammond -> removed
    if HasItem(2108) then return end -- Key to Snergle's Chambers
    AddValue(InventoryItem(2108), 2108) -- Key to Snergle's Chambers
end)
RegisterCanShowTopic(1614, function()
    evt._BeginCanShowTopic(1614)
    local visible = true
    if HasItem(2108) then -- Key to Snergle's Chambers
        visible = false
        return visible
    else
        visible = true
        return visible
    end
end)

RegisterGlobalEvent(1615, "Legacy event 1615", function()
    evt.SimpleMessage("Thank you for releasing me.\nThe only thing keeping the Silver Helms from killing me was the fact I’m a priest.\nFrankly, I’m surprised they would show me any mercy at all.\nListen, I’ve heard some strange sounds coming from around here… I think there might be a hidden passage near here.\nIn any event, I should probably be leaving now; I don’t want to stay in this cell any longer.")
    evt.MoveNPC(859, 0) -- Oliver Wendell -> removed
end)

RegisterGlobalEvent(1616, "Legacy event 1616", function()
    evt.SimpleMessage("The Dragoons that have been plaguing the roads around here recently stole a harp of mine from one of my caravans.\nI’m not strong enough to get it back from them, but I’m willing to pay someone capable to do it for me.\nFind the harp and return it, and I’ll reward you.")
    SetQBit(QBit(1152)) -- Retrieve the harp from the Dragoon's Caverns south of Castle Ironfist and return it to Andrew Besper in Castle Ironfist. - NPC
    evt.SetNPCTopic(862, 0, 1617) -- Andrew Besper topic 0: Quest
end)

RegisterGlobalEvent(1617, "Legacy event 1617", function()
    evt.ForPlayer(Players.All)
    if HasItem(2099) then -- Harp
        evt.SimpleMessage("My gratitude!\nMy wife loves this harp; I’m so glad you were able to recover it!\nHere, take this as a reward.\nI’ve heard rumors that the Dragoons were working with the Shadow Guild.\nIf that’s the case, I’m sure the Mayor of New Sorpigal would love to see proof of it.\nThank you again for your assistance.")
        RemoveItem(2099) -- Harp
        SetAward(Award(82)) -- Retrieved Andrew's Harp
        AddValue(Experience, 10000)
        evt.ForPlayer(Players.Current)
        AddValue(Gold, 5000)
        AddValue(131307, 2)
        ClearQBit(QBit(1152)) -- Retrieve the harp from the Dragoon's Caverns south of Castle Ironfist and return it to Andrew Besper in Castle Ironfist. - NPC
        evt.SetNPCTopic(862, 0, 0) -- Andrew Besper topic 0 cleared
    elseif HasItem(2098) then -- Flute
        evt.SimpleMessage("Well, this IS a musical instrument, but it’s not a harp.\nLet me explain the difference:\nYou brought back a flute.\nA flute is a pipe with holes in it.\nA harp has strings.\nDoes that help?\nI’m sure they still have the harp and I will reward you well for its return.")
    else
        evt.SimpleMessage("My harp is still lost, so the reward is still available for it.\nI know the Dragoons base their operations to the south of here near the coast.\nPlease bring back my harp.")
    end
end)

RegisterGlobalEvent(1618, "Legacy event 1618", function()
    evt.SimpleMessage("I have a few theories about the undead that I would very much like to prove.\nWhat I really need is the remains of an undead creature, preferably a powerful one.\nActually, what I really need is the remains of the FIRST lich, Ethric the Mad.\nI am a scholar, however, and don’t have the means to gain such a specimen.\nI do have some money saved up, and I’d be willing to pay you well for Ethric’s remains.")
    SetQBit(QBit(1153)) -- Retrieve Ethric's skull from his tomb west of Free Haven for Gabriel Cartman in Free Haven. - NPC
    evt.SetNPCTopic(956, 0, 1619) -- Gabriel Cartman topic 0: Quest
end)

RegisterGlobalEvent(1619, "Legacy event 1619", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2084) then -- Ethric's Skull
        evt.SimpleMessage("I am well aware of the difficulty of the task, believe me.\nTake your time but at the least, do the job properly. ")
        return
    end
    evt.SimpleMessage("Good work! Now I can conclude my research.\nIf I can learn how the Ritual of Endless Night works, perhaps I can find a way to reverse the process.\nHere is the reward I promised you. ")
    RemoveItem(2084) -- Ethric's Skull
    SetAward(Award(83)) -- Retrieved Ethric's Skull
    AddValue(Experience, 15000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 7500)
    ClearQBit(QBit(1153)) -- Retrieve Ethric's skull from his tomb west of Free Haven for Gabriel Cartman in Free Haven. - NPC
    evt.SetNPCTopic(956, 0, 0) -- Gabriel Cartman topic 0 cleared
    evt.MoveNPC(956, 0) -- Gabriel Cartman -> removed
end)

RegisterGlobalEvent(1621, "Legacy event 1621", function()
    evt.SimpleMessage("Our town is periodically plagued by giant spiders.\nI’m pretty sure that if the spider queen were killed, the rest of the spiders would go away.\nCurrently, I’m offering a reward to the person that can kill the spider queen.")
    SetQBit(QBit(1154)) -- Kill the Queen of the Spiders in the Abandoned Temple in New Sorpigal and return with her heart to Buford T. Allman in New Sorpigal. - NPC
    evt.SetNPCTopic(992, 0, 1622) -- Buford T. Allman topic 0: Quest
end)

RegisterGlobalEvent(1622, "Legacy event 1622", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2101) then -- Spider Queen's Heart
        evt.SimpleMessage("No one has returned with proof that they’ve killed the spider queen, so the reward is still available.")
        return
    end
    evt.SimpleMessage("What a gruesome trophy!")
    RemoveItem(2101) -- Spider Queen's Heart
    SetAward(Award(84)) -- Killed the Spider Queen
    AddValue(Experience, 3000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 1000)
