    evt.SetNPCTopic(992, 0, 0) -- Buford T. Allman topic 0 cleared
end)

RegisterGlobalEvent(1623, "Legacy event 1623", function()
    evt.SimpleMessage("Cedric Druthers and his Celestial Order have taken over the Monolith, an ancient place sacred to druids.\nTheir dark rituals are corrupting the Monolith and they need to be stopped– whatever altar they use as the center of their ceremonies needs to be defaced.\nDo this for us and we will compensate you for your time and services.")
    SetQBit(QBit(1155)) -- Deface the altar in the Monolith west of Silver Cove and return to Eleanor Vanderbilt in Silver Cove. - NPC
    evt.SetNPCTopic(1052, 0, 1624) -- Eleanor Vanderbilt topic 0: Quest
end)

RegisterGlobalEvent(1624, "Legacy event 1624", function()
    if not IsQBitSet(QBit(1047)) then -- 23 D13, Given when Altar is desecrated
        evt.SimpleMessage("I’m glad to see you again, but the Celestial Order is still in the Monolith.")
        return
    end
    evt.SimpleMessage("Thank you for your help!")
