RegisterGlobalEvent(1647, "Legacy event 1647", function()
    evt.SimpleMessage("Our town is under a terrible curse, though most people don’t believe it.\nUnder a full moon, we all change into werewolves.\nAlthough none of us are truly evil, we don’t really know what sort of horrible things we do as werewolves.\nWe can’t approach our lord, Acton Spindler about the problem because he doesn’t realize that we are the werewolves.\nPlease find a way to turn us back to normal!")
    SetQBit(QBit(1165)) -- Destroy the Werewolf's altar in the Lair of the Wolf and return to Maria Trepan in Blackshire. - NPC
    evt.SetNPCTopic(997, 0, 1648) -- Maria Trepan topic 0: Quest
end)

