RegisterGlobalEvent(1651, "Legacy event 1651", function()
    evt.SimpleMessage("I was a guest at Lord Spindler's manor when it was attacked by a band of werewolves that had tunneled in from the mountains.\nI fought my way back down the tunnels they had created hoping to escape.\nEventually, they cornered me and I was killed at this very spot. ")
end)

RegisterGlobalEvent(1652, "Legacy event 1652", function()
    evt.SimpleMessage("In my flight, I managed to hide the Pearl of Purity in these caverns.\nThe pearl will both protect you from the curse of the werewolves, and will also destroy the Altar of the Wolf if the pearl touches it.\nThat should free everyone afflicted by the curse these werewolves have caused.\nThe pearl is at the end of the cavern across from this one.\nPlease do me one favor, return the Pearl to Wilbur Humphrey.\nHe is the lord in charge of paladins and the pearl belongs with him.")
    SetQBit(QBit(1166)) -- NPC
    evt.SetNPCTopic(789, 2, 1655) -- Wilbur Humphrey topic 2: Pearl of Purity
end)

RegisterGlobalEvent(1653, "Legacy event 1653", function()
    evt.SimpleMessage("The werewolf leader possesses the Pearl of Putrescence, the opposite of my Pearl of Purity.\nWith this pearl, he has been able to cause the curse.\nI was never able to kill him in my retreat.\nI will be able to rest in peace knowing that he has been defeated.")
    SetQBit(QBit(1167)) -- Find the Pearl of Putrescence in the Lair of the Wolf and bring it to the Ghost of Balthasar, also in the Lair of the Wolf. - NPC
    evt.SetNPCTopic(1080, 2, 1654) -- Ghost of Balthasar topic 2: Quest
end)

