RegisterGlobalEvent(1662, "Legacy event 1662", function()
    evt.SimpleMessage("Hello again, my pupils!\nI'm afraid there is nothing more I can teach you– your experiences must guide you from this point on.\nI know nothing more than you do about the devils that destroyed Sweet Water, but I know who you need to ask.\nThe Oracle in Free Haven will know what to do to rid Enroth of the terrible devils.\nUnfortunately, you will need the approval of the six High Council members, each of which represents one of the lords of Enroth.\nYou must do whatever necessary to speak to the Oracle in Free Haven and rid Enroth of the devils.")
end)

RegisterGlobalEvent(1664, "Legacy event 1664", function()
    evt.SimpleMessage("I’ve discovered a way to reverse the effects of time and make myself young again.\nThis requires a complex magical ritual, which I’ve worked out.\nThe problem is that I need to place magical statuettes on various pedestals. The tiger statuette goes on the pedestal near Sweet Water, the bear statuette in Kriegspire, the eagle statuette in Dragonsand, the wolf statuette in the Mire of the Damned, and the dragon statuette in Bootleg Bay.\nThe distances are too far for me to travel in my old age, and in the meantime I need to prepare the ritual itself.\nThere is no way I can do all of this on my own; I need your help.\nThe statuettes are in the chest outside my house.\nPlace them on the pedestals and return to me.\nEven if the ritual is a failure, I'll pay you for your efforts.")
    SetQBit(QBit(1243)) -- Place the statuettes in Sweet Water, Kriegspire, Dragonsand, Mire of the Damned, and Bootleg Bay and return to Twillen in Blackshire. - NPC
    SetQBit(QBit(1244)) -- NPC
    evt.SetNPCTopic(872, 0, 1665) -- Twillen topic 0: Quest
end)

RegisterGlobalEvent(1665, "Legacy event 1665", function()
    evt.SimpleMessage("I have almost prepared the entire ritual– all that is left is to place the statuettes.")
end)

RegisterGlobalEvent(1666, "Legacy event 1666", function()
    evt.SimpleMessage("I was once the court magician, long ago.\nThat all ended when Archibald… disrupted… things.\nArchibald had acquired some skill as a sorcerer and had knowledge of spells beyond that taught to magicians today, and therefore didn’t require my services.\nSince then, I’ve lived in this little shack, conducted my own research, and have grown old.")
end)

RegisterGlobalEvent(1667, "Legacy event 1667", function()
    evt.SimpleMessage("Good work!\nI have my youth again, thanks to you– have you ever thought about assisting me full-time?\nI could certainly use reliable help.\nI've managed to collect a variety of trinkets over the years, so please help yourself to a few of these in the chest outside as payment for your services.\nI need to clean up a few things here, but I think I'll head back to Castle Ironfist and see if there's an opening for a court magician.")
    ClearQBit(QBit(1243)) -- Place the statuettes in Sweet Water, Kriegspire, Dragonsand, Mire of the Damned, and Bootleg Bay and return to Twillen in Blackshire. - NPC
    SetQBit(QBit(1245)) -- NPC
    evt.ForPlayer(Players.All)
    AddValue(Experience, 75000)
    SetAward(Award(98)) -- Placed Twillen's statuettes
    evt.SetNPCTopic(826, 0, 0) -- Twillen topic 0 cleared
    evt.MoveNPC(826, 0) -- Twillen -> removed
end)

RegisterGlobalEvent(1668, "Legacy event 1668", function()
    evt.SimpleMessage("I was one of the mages studying at Kriegspire when the creatures there went completely out of control.\nIn my escape from the castle, I left a valuable item behind, a jeweled egg.\nThis egg is a family heirloom that goes back in my family as far as the Silence.\nI have tried a few times to get it back, but the creatures there are too powerful for me.\nI’d gladly trade a generous sum of money to get my egg back.")
    SetQBit(QBit(1168)) -- Retrieve the jewelled egg from Castle Kriegspire and return it to Emil Lime in Kriegspire village. - NPC
    evt.SetNPCTopic(986, 0, 1669) -- Emil Lime topic 0: Quest
end)

