RegisterGlobalEvent(1670, "Legacy event 1670", function()
    evt.SimpleMessage("I am the Lord of Fire, an immortal earth spirit.\nMy power is drawn from below the earth.\nThe channels that I use have been blocked by doors warded with powerful magic in the north.\nI need you to unward the doors so that I may awaken again.\nThough the enchantments on them are powerful, amber will break the ward on the doors.")
    SetQBit(QBit(1169)) -- Unward the doors in the Hall of the Fire Lord and return to the Lord of Fire, also in the Hall of the Fire Lord. - NPC
    evt.SetNPCTopic(1083, 0, 1673) -- Lord of Fire topic 0: Quest
end)

RegisterGlobalEvent(1671, "Legacy event 1671", function()
    evt.SimpleMessage("If you get lost in the caverns, you may find assistance from my servants.\nIf you have a piece of amber, they will assume you are under my care and will teleport you back to me if you talk to them.\nIf you do not have any amber, they will drain with some of your life force as payment for teleporting you back up here.\nDon’t worry, they rarely kill anyone.")
end)

RegisterGlobalEvent(1672, "Legacy event 1672", function()
    evt.SimpleMessage("The doors became warded when a strange creature came to reside here.\nI am not familiar with this type of being, and I’ve seen many types in my long time here in Enroth.\nI do not know why it chose this place as its home, or why there is only one, but I would like to see it destroyed for the trouble it has caused me. ")
end)

