    evt.ForPlayer(Players.All)
    if not HasItem(2068) then -- Ankh
        evt.SimpleMessage("Recently, the Fraternal Order of Silver has been disrupting my business and my caravans.\nI'm not sure why Sir John feels it necessary, but I'd like this to stop.\nIf you could convince him to leave me alone, I'm sure I could give you a portion of the money you would be saving me.")
        return
    end
    evt.SimpleMessage("So, Sir John was murdered and the Silver Helms were bought off by the Temple of Baa?\nThat explains a great deal.\nGood work on bringing this to me, but you’ll need to collect your reward from Anthony Stone.")
    RemoveItem(2068) -- Ankh
    AddValue(Experience, 10000)
    evt.ForPlayer(Players.Current)
    evt.SetNPCTopic(801, 2, 1677) -- Anthony Stone topic 2: Ankh
    evt.SetNPCTopic(799, 2, 0) -- Loretta Fleise topic 2 cleared
end)

RegisterGlobalEvent(1676, "Legacy event 1676", function()
    evt.ForPlayer(Players.All)
    if not HasItem(2068) then -- Ankh
        evt.SimpleMessage("The Fraternal Order of Silver has begun more direct attacks on my legitimate, underworld associates.\nI would appreciate it greatly if you could talk to Sir John and learn why he feels these actions are necessary.")
        return
    end
    evt.SimpleMessage("I should have known Baa was behind this, they seem to be behind everything.\nThank you for bringing this to me.\nIt answers the questions I had about the Fraternal Order of Silver.")
    RemoveItem(2068) -- Ankh
    AddValue(Experience, 10000)
    evt.ForPlayer(Players.Current)
    AddValue(Gold, 5000)
    evt.SetNPCTopic(801, 2, 0) -- Anthony Stone topic 2 cleared
    evt.SetNPCTopic(799, 2, 0) -- Loretta Fleise topic 2 cleared
end)

RegisterGlobalEvent(1677, "Legacy event 1677", function()
    evt.SimpleMessage("So Baa was behind the corruption of the Silver Helms and the murder of Sir John Silver?\nWhat a tragedy for Sir John, rest his soul.\n<blink> Loretta told you to collect the reward from me?\nGreedy witch.\nHere, your services should not go unrewarded.")
    AddValue(Gold, 5000)
    evt.SetNPCTopic(801, 2, 0) -- Anthony Stone topic 2 cleared
end)

RegisterGlobalEvent(1678, "Legacy event 1678", function()
    evt.SimpleMessage("<Loretta Fleise contacts you via a telepathy spell> Welcome to the Ceremony of the Sun.\nStand ye in the circle of life and face the north while no shadows stretch before thee.\nMeditate upon this truth:\n“Money is everything.\nI have no truer a friend than money…” <grinning> Just kidding.\nNow, close your eyes, and meditate as you stand at the center of the world and time for just this one, sublime moment… <long, silent pause>\nOpen your eyes.\nI hereby promote all druids to great druids and all non-druids to honorary druids. <Loretta fades away> ")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 12) then
            SetValue(ClassId, 13)
            SetQBit(QBit(1651)) -- Received Promotion to Great Druid
        else
            SetQBit(QBit(1652)) -- Received Promotion to Honorary Great Druid
        end
    end
    AddValue(131307, 2)
    evt.ForPlayer(Players.All)
    ClearQBit(QBit(1142)) -- Visit the Altar of the Sun in the circle of stones north of Silver Cove on an equinox or solstice (HINT: March 20th is an equinox). - NPC
    SetQBit(QBit(1197)) -- NPC
    AddValue(Experience, 15000)
    evt.SetNPCTopic(1090, 0, 0) -- Loretta Fleise topic 0 cleared
    evt.SetNPCTopic(799, 1, 1397) -- Loretta Fleise topic 1: Arch Druids
end)

RegisterGlobalEvent(1679, "Legacy event 1679", function()
    evt.SimpleMessage("<Loretta Fleise contacts you via a telepathy spell> Welcome to the Ceremony of the Moon.\nStand ye before the altar of the Moon facing south.\nClose your eyes and meditate upon the Circle of Seasons and the Wheel of Life.\n<long, silent pause>\nOpen your eyes, my friends.\nI hereby promote all great druids to arch druids, and all honorary great druids to honorary arch druids.\n<Loretta fades away> ")
    for _, player in ipairs({Players.Member0, Players.Member1, Players.Member2, Players.Member3}) do
        evt.ForPlayer(player)
        if IsAtLeast(ClassId, 13) then
            SetValue(ClassId, 15)
            SetQBit(QBit(1653)) -- Received Promotion to Arch Druid
        else
            SetQBit(QBit(1654)) -- Received Promotion to Honorary Arch Druid
        end
    end
    AddValue(327915, 5)
    evt.ForPlayer(Players.All)
    ClearQBit(QBit(1143)) -- Visit the Altar of the Moon in the Temple of the Moon at midnight of a full moon. - NPC
    SetQBit(QBit(1198)) -- NPC
    AddValue(Experience, 40000)
    evt.SetNPCTopic(1091, 0, 0) -- Loretta Fleise topic 0 cleared
    evt.SetNPCTopic(799, 1, 1399) -- Loretta Fleise topic 1: Arch Druids
end)

